use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct GameSessionLog {
    heap: BinaryHeap<Reverse<u32>>,
    capacity: usize,
}

impl GameSessionLog {
    fn new(capacity: usize) -> Self {
        GameSessionLog {
            heap: BinaryHeap::with_capacity(capacity),
            capacity,
        }
    }

    fn push(&mut self, score: u32) {
        if self.heap.len() < self.capacity {
            self.heap.push(Reverse(score));
        } else {
            if let Some(Reverse(min)) = self.heap.peek() {
                if score > *min {
                    self.heap.pop();
                    self.heap.push(Reverse(score));
                }
            }
        }
    }

    fn pop(&mut self) -> Option<u32> {
        self.heap.pop().map(|Reverse(score)| score)
    }

    fn into_sorted_descending(self) -> Vec<u32> {
        let mut scores: Vec<_> = self.heap.into_sorted_vec().into_iter().map(|Reverse(s)| s).collect();
        scores.sort_by(|a, b| b.cmp(a));
        scores
    }
}
