import java.util.PriorityQueue;
import java.util.Comparator;

public class MessageHandler {
    private PriorityQueue<Message> messageQueue;
    private static final int MAX_CAPACITY = 100;

    public MessageHandler() {
        this.messageQueue = new PriorityQueue<>(Comparator.comparingInt(Message::getUrgency).reversed());
    }

    public synchronized boolean offerMessage(Message message) {
        if (messageQueue.size() < MAX_CAPACITY) {
            return messageQueue.offer(message);
        }
        return false;
    }

    public synchronized Message pollMessage() {
        return messageQueue.poll();
    }

    public static class Message {
        private String content;
        private int urgency;

        public Message(String content, int urgency) {
            this.content = content;
            this.urgency = urgency;
        }

        public String getContent() {
            return content;
        }

        public int getUrgency() {
            return urgency;
        }
    }
}
