package main

import (
	"sync"
)

type ClassroomMonitor struct {
	students []string
	mu       sync.Mutex
	maxCap   int
}

func NewClassroomMonitor() *ClassroomMonitor {
	return &ClassroomMonitor{
		students: make([]string, 0, 50),
		maxCap:   50,
	}
}

func (cm *ClassroomMonitor) AddStudent(name string) {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	if len(cm.students) >= cm.maxCap {
		// Remove the oldest student (first element) to make space
		cm.students = cm.students[1:]
	}
	cm.students = append(cm.students, name)
}

func (cm *ClassroomMonitor) GetStudentListCopy() []string {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	studentCopy := make([]string, len(cm.students))
	copy(studentCopy, cm.students)
	return studentCopy
}

func (cm *ClassroomMonitor) GetTotalStudents() int {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	return len(cm.students)
}
