```go
package main

import (
	"sync"
)

type Classroom struct {
	students []string
	mu       sync.Mutex
}

func NewClassroom() *Classroom {
	return &Classroom{
		students: make([]string, 0, 50),
	}
}

func (c *Classroom) AddStudent(name string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	if len(c.students) < 50 {
		c.students = append(c.students, name)
	}
}

func (c *Classroom) RemoveStudent(name string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	for i, student := range c.students {
		if student == name {
			c.students = append(c.students[:i], c.students[i+1:]...)
			break
		}
	}
}

func (c *Classroom) GetStudentsCopy() []string {
	c.mu.Lock()
	defer c.mu.Unlock()
	copySlice := make([]string, len(c.students))
	copy(copySlice, c.students)
	return copySlice
}

func (c *Classroom) GetStudentCount() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return len(c.students)
}
