package main

import (
	"sync"
)

type ClassroomMonitor struct {
	stack      []string
	maxSize    int
	stackMutex sync.Mutex
}

func NewClassroomMonitor() *ClassroomMonitor {
	return &ClassroomMonitor{
		stack:   make([]string, 0),
		maxSize: 50,
	}
}

func (cm *ClassroomMonitor) Push(student string) {
	cm.stackMutex.Lock()
	defer cm.stackMutex.Unlock()

	if len(cm.stack) >= cm.maxSize {
		cm.stack = cm.stack[1:]
	}
	cm.stack = append(cm.stack, student)
}

func (cm *ClassroomMonitor) Pop() string {
	cm.stackMutex.Lock()
	defer cm.stackMutex.Unlock()

	if len(cm.stack) == 0 {
		return ""
	}
	student := cm.stack[len(cm.stack)-1]
	cm.stack = cm.stack[:len(cm.stack)-1]
	return student
}

func (cm *ClassroomMonitor) GetCount() int {
	cm.stackMutex.Lock()
	defer cm.stackMutex.Unlock()
	return len(cm.stack)
}

func (cm *ClassroomMonitor) CopyStack() []string {
	cm.stackMutex.Lock()
	defer cm.stackMutex.Unlock()

	copiedStack := make([]string, len(cm.stack))
	copy(copiedStack, cm.stack)
	return copiedStack
}
