use std::collections::HashSet;
use std::time::SystemTime;

struct DocumentVersion {
    content: String,
    timestamp: SystemTime,
}

struct DocumentTracker {
    versions: Vec<DocumentVersion>,
    timestamps: HashSet<SystemTime>,
    max_versions: usize,
}

impl DocumentTracker {
    fn new() -> Self {
        DocumentTracker {
            versions: Vec::new(),
            timestamps: HashSet::new(),
            max_versions: 100,
        }
    }

    fn add_version(&mut self, content: String, timestamp: SystemTime) -> Result<(), String> {
        if self.timestamps.contains(&timestamp) {
            return Err("Duplicate timestamp".to_string());
        }

        if self.versions.len() >= self.max_versions {
            return Err("Maximum versions reached".to_string());
        }

        self.timestamps.insert(timestamp);
        self.versions.push(DocumentVersion { content, timestamp });
        Ok(())
    }

    fn insert_version(&mut self, index: usize, content: String, timestamp: SystemTime) -> Result<(), String> {
        if self.timestamps.contains(&timestamp) {
            return Err("Duplicate timestamp".to_string());
        }

        if self.versions.len() >= self.max_versions {
            return Err("Maximum versions reached".to_string());
        }

        self.timestamps.insert(timestamp);
        self.versions.insert(index, DocumentVersion { content, timestamp });
        Ok(())
    }
}
