use std::time::SystemTime;

#[derive(Debug)]
enum DocumentError {
    CapacityExceeded,
    DuplicateTimestamp,
}

struct DocumentTracker {
    versions: Vec<SystemTime>,
}

impl DocumentTracker {
    fn new() -> Self {
        DocumentTracker {
            versions: Vec::with_capacity(100),
        }
    }

    fn add_version(&mut self, timestamp: SystemTime) -> Result<(), DocumentError> {
        if self.versions.len() >= 100 {
            return Err(DocumentError::CapacityExceeded);
        }

        if let Err(insert_pos) = self.versions.binary_search(&timestamp) {
            self.versions.insert(insert_pos, timestamp);
            Ok(())
        } else {
            Err(DocumentError::DuplicateTimestamp)
        }
    }
}
