type ReservationDetails struct {
	Date      string
	TableNum  int
}

var reservations = make(map[string][]ReservationDetails)
var reservationCount int

func addReservation(customerName string, date string, tableNum int) error {
	if reservationCount >= 50 {
		return fmt.Errorf("reservation limit of 50 reached")
	}

	for _, details := range reservations[customerName] {
		if details.Date == date && details.TableNum == tableNum {
			return fmt.Errorf("table %d is already booked on %s", tableNum, date)
		}
	}

	for _, resList := range reservations {
		for _, details := range resList {
			if details.Date == date && details.TableNum == tableNum {
				return fmt.Errorf("table %d is already booked on %s", tableNum, date)
			}
		}
	}

	reservations[customerName] = append(reservations[customerName], ReservationDetails{Date: date, TableNum: tableNum})
	reservationCount++
	return nil
}

func cancelReservation(customerName string, date string, tableNum int) error {
	resList, exists := reservations[customerName]
	if !exists {
		return fmt.Errorf("no reservations found for customer %s", customerName)
	}

	found := false
	for i, details := range resList {
		if details.Date == date && details.TableNum == tableNum {
			reservations[customerName] = append(resList[:i], resList[i+1:]...)
			found = true
			reservationCount--
			break
		}
	}

	if !found {
		return fmt.Errorf("no reservation found for table %d on %s", tableNum, date)
	}

	if len(reservations[customerName]) == 0 {
		delete(reservations, customerName)
	}

	return nil
}
