package main

import (
	"fmt"
	"sync"
)

type ReservationDetails struct {
	Date      string
	TableNum  int
}

type ReservationSystem struct {
	mu           sync.Mutex
	reservations map[string][]ReservationDetails
	waitlist     []struct {
		name     string
		details  ReservationDetails
	}
	maxReservations int
}

func NewReservationSystem() *ReservationSystem {
	return &ReservationSystem{
		reservations:    make(map[string][]ReservationDetails),
		maxReservations: 50,
	}
}

func (rs *ReservationSystem) AddReservation(name string, details ReservationDetails) (bool, string) {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	// Check for double booking
	for _, resList := range rs.reservations {
		for _, res := range resList {
			if res.Date == details.Date && res.TableNum == details.TableNum {
				return false, "Table already booked for this date"
			}
		}
	}

	if len(rs.reservations) < rs.maxReservations {
		rs.reservations[name] = append(rs.reservations[name], details)
		return true, "Reservation added successfully"
	}

	// Add to waitlist
	rs.waitlist = append(rs.waitlist, struct {
		name     string
		details  ReservationDetails
	}{name, details})
	return false, "Restaurant at capacity, added to waitlist"
}

func (rs *ReservationSystem) CancelReservation(name string, details ReservationDetails) bool {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	resList, exists := rs.reservations[name]
	if !exists {
		return false
	}

	for i, res := range resList {
		if res.Date == details.Date && res.TableNum == details.TableNum {
			// Remove the reservation
			resList = append(resList[:i], resList[i+1:]...)
			if len(resList) == 0 {
				delete(rs.reservations, name)
			} else {
				rs.reservations[name] = resList
			}

			// Promote from waitlist if available
			if len(rs.waitlist) > 0 {
				waiting := rs.waitlist[0]
				rs.waitlist = rs.waitlist[1:]
				rs.reservations[waiting.name] = append(rs.reservations[waiting.name], waiting.details)
			}
			return true
		}
	}
	return false
}
