    std::set<std::string> tags;
    std::queue<std::string> tagQueue;
    const int MAX_TAGS = 1000;
    const int MAX_QUEUE_SIZE = 500;

public:
    void pushTag(const std::string& tag) {
        if (tags.size() >= MAX_TAGS) {
            // Remove the oldest tag if max tags reached
            std::string oldestTag = tagQueue.front();
            tagQueue.pop();
            tags.erase(oldestTag);
        }
        tags.insert(tag);
        tagQueue.push(tag);

        // Ensure queue does not exceed max size
        if (tagQueue.size() > MAX_QUEUE_SIZE) {
            tagQueue.pop();
        }
    }

    void popTag() {
        if (!tagQueue.empty()) {
            std::string oldestTag = tagQueue.front();
            tagQueue.pop();
            tags.erase(oldestTag);
        }
    }

    bool hasTag(const std::string& tag) const {
        return tags.find(tag) != tags.end();
    }
};
