import (
	"time"
)

var logMap = make(map[time.Time]string)
const maxEntries = 100

func manageLogs(newLog string, timestamp time.Time, olderThan time.Time) {
	// Add new log entry
	logMap[timestamp] = newLog

	// Delete logs older than specified timestamp
	for ts := range logMap {
		if ts.Before(olderThan) {
			delete(logMap, ts)
		}
	}

	// Ensure total entries don't exceed maxEntries
	if len(logMap) > maxEntries {
		// Find oldest timestamp(s) to delete
		var oldest time.Time
		for ts := range logMap {
			if oldest.IsZero() || ts.Before(oldest) {
				oldest = ts
			}
		}
		delete(logMap, oldest)
	}
}
