		// Remove the oldest entry if stack is full
		ls.entries = ls.entries[1:]
	}
	ls.entries = append(ls.entries, LogEntry{Timestamp: timestamp, Message: message})
}

func (ls *LogStack) PopOlderThan(timestamp time.Time) []LogEntry {
	var removed []LogEntry
	i := 0
	for i < len(ls.entries) && ls.entries[i].Timestamp.Before(timestamp) {
		removed = append(removed, ls.entries[i])
		i++
	}
	ls.entries = ls.entries[i:]
	return removed
}
