#include <stack>
#include <string>
#include <stdexcept>
#include <cctype>

int evaluatePostfix(const std::string& expression) {
    std::stack<int> stack;

    for (char c : expression) {
        if (isspace(c)) {
            continue;
        }

        if (isdigit(c)) {
            if (stack.size() >= 10) {
                throw std::overflow_error("Stack overflow: maximum size exceeded");
            }
            stack.push(c - '0');
        } else {
            if (stack.size() < 2) {
                throw std::invalid_argument("Invalid postfix expression");
            }

            int b = stack.top(); stack.pop();
            int a = stack.top(); stack.pop();

            switch (c) {
                case '+':
                    stack.push(a + b);
                    break;
                case '-':
                    stack.push(a - b);
                    break;
                case '*':
                    stack.push(a * b);
                    break;
                case '/':
                    if (b == 0) {
                        throw std::runtime_error("Division by zero");
                    }
                    stack.push(a / b);
                    break;
                default:
                    throw std::invalid_argument("Invalid operator");
            }

            if (stack.size() > 10) {
                throw std::overflow_error("Stack overflow: maximum size exceeded");
            }
        }
    }

    if (stack.size() != 1) {
        throw std::invalid_argument("Invalid postfix expression");
    }

    return stack.top();
}
