```cpp
#include <iostream>
#include <stack>
#include <string>
#include <stdexcept>
#include <sstream>

using namespace std;

int evaluatePostfix(const string& expr) {
    stack<int> st;
    const int MAX_STACK_SIZE = 10;
    istringstream iss(expr);
    string token;

    while (iss >> token) {
        if (st.size() >= MAX_STACK_SIZE) {
            throw runtime_error("Stack size exceeded maximum limit of 10");
        }

        if (token == "+" || token == "-" || token == "*" || token == "/") {
            if (st.size() < 2) {
                throw runtime_error("Invalid postfix expression: insufficient operands");
            }
            int b = st.top(); st.pop();
            int a = st.top(); st.pop();

            if (token == "+") {
                st.push(a + b);
            } else if (token == "-") {
                st.push(a - b);
            } else if (token == "*") {
                st.push(a * b);
            } else if (token == "/") {
                if (b == 0) {
                    throw runtime_error("Division by zero error");
                }
                st.push(a / b);
            }
        } else {
            try {
                int num = stoi(token);
                st.push(num);
            } catch (const invalid_argument&) {
                throw runtime_error("Invalid symbol in expression: " + token);
            }
        }
    }

    if (st.size() != 1) {
        throw runtime_error("Invalid postfix expression: too many operands");
    }

    return st.top();
}
