use std::collections::HashMap;
use std::collections::hash_map::Entry;

struct LRUInventory {
    stock: HashMap<String, (u32, usize)>,
    access_order: Vec<String>,
    capacity: usize,
}

impl LRUInventory {
    fn new(capacity: usize) -> Self {
        LRUInventory {
            stock: HashMap::new(),
            access_order: Vec::with_capacity(capacity),
            capacity,
        }
    }

    fn update_access(&mut self, product_id: &str) {
        if let Some(pos) = self.access_order.iter().position(|id| id == product_id) {
            self.access_order.remove(pos);
        }
        self.access_order.push(product_id.to_string());
    }

    fn evict_lru(&mut self) {
        if let Some(lru_product) = self.access_order.first() {
            self.stock.remove(lru_product);
            self.access_order.remove(0);
        }
    }

    fn manage_stock(&mut self, product_id: String, quantity: u32) {
        if self.stock.len() >= self.capacity && !self.stock.contains_key(&product_id) {
            self.evict_lru();
        }

        match self.stock.entry(product_id.clone()) {
            Entry::Occupied(mut entry) => {
                let (current_quantity, _) = entry.get_mut();
                if quantity == 0 {
                    entry.remove();
                    if let Some(pos) = self.access_order.iter().position(|id| id == &product_id) {
                        self.access_order.remove(pos);
                    }
                } else {
                    *current_quantity = quantity;
                    self.update_access(&product_id);
                }
            }
            Entry::Vacant(entry) => {
                if quantity > 0 {
                    entry.insert((quantity, 0));
                    self.update_access(&product_id);
                }
            }
        }
    }

    fn get_stock(&mut self, product_id: &str) -> Option<u32> {
        if let Some((quantity, _)) = self.stock.get(product_id) {
            self.update_access(product_id);
            Some(*quantity)
        } else {
            None
        }
    }
}
