    private final int maxCapacity = 50;

    public ElectronicStoreInventory() {
        this.inventory = new LinkedHashSet<>();
    }

    public synchronized boolean addProduct(String product) {
        if (inventory.size() >= maxCapacity) {
            String leastRecent = inventory.iterator().next();
            inventory.remove(leastRecent);
        }
        return inventory.add(product);
    }

    public synchronized boolean removeProduct(String product) {
        return inventory.remove(product);
    }

    public synchronized boolean containsProduct(String product) {
        boolean exists = inventory.contains(product);
        if (exists) {
            inventory.remove(product);
            inventory.add(product);
        }
        return exists;
    }

    public synchronized int getInventorySize() {
        return inventory.size();
    }
}
