struct ElevatorRequest {
    floor: i32,
    is_urgent: bool,
}

struct ElevatorScheduler {
    requests: Vec<ElevatorRequest>,
}

impl ElevatorScheduler {
    fn new() -> Self {
        ElevatorScheduler {
            requests: Vec::with_capacity(10),
        }
    }

    fn add_request(&mut self, floor: i32, is_urgent: bool) -> Result<(), &'static str> {
        if self.requests.len() >= 10 {
            return Err("Capacity reached. Cannot add more requests.");
        }
        self.requests.push(ElevatorRequest { floor, is_urgent });
        Ok(())
    }

    fn process_next_request(&mut self) -> Option<i32> {
        // Check for urgent requests first
        if let Some(index) = self.requests.iter().position(|r| r.is_urgent) {
            let urgent_request = self.requests.remove(index);
            return Some(urgent_request.floor);
        }
        // Process normal requests if no urgent ones exist
        if !self.requests.is_empty() {
            let normal_request = self.requests.remove(0);
            return Some(normal_request.floor);
        }
        None
    }
}
