#[derive(Debug, PartialEq)]
enum RequestPriority {
    Normal,
    Urgent,
}

#[derive(Debug)]
struct FloorRequest {
    floor: u32,
    priority: RequestPriority,
}

struct ElevatorQueue {
    normal_requests: Vec<FloorRequest>,
    urgent_requests: Vec<FloorRequest>,
    max_capacity: usize,
}

impl ElevatorQueue {
    fn new() -> Self {
        ElevatorQueue {
            normal_requests: Vec::with_capacity(10),
            urgent_requests: Vec::with_capacity(10),
            max_capacity: 15,
        }
    }

    fn push(&mut self, request: FloorRequest) -> Result<(), &'static str> {
        if self.len() >= self.max_capacity {
            return Err("Queue capacity exceeded");
        }

        match request.priority {
            RequestPriority::Urgent => self.urgent_requests.push(request),
            RequestPriority::Normal => self.normal_requests.push(request),
        }
        Ok(())
    }

    fn pop(&mut self) -> Option<FloorRequest> {
        if !self.urgent_requests.is_empty() {
            Some(self.urgent_requests.remove(0))
        } else if !self.normal_requests.is_empty() {
            Some(self.normal_requests.remove(0))
        } else {
            None
        }
    }

    fn len(&self) -> usize {
        self.normal_requests.len() + self.urgent_requests.len()
    }
}
