```cpp
#include <map>
#include <string>
#include <vector>
#include <stdexcept>

void manageConferenceSchedule(std::map<std::string, std::vector<std::string>>& schedule,
                             const std::string& timeslot,
                             const std::string& eventName,
                             const std::string& operation) {
    if (operation == "insert") {
        if (schedule.size() >= 10) {
            throw std::runtime_error("Schedule cannot have more than 10 events.");
        }
        schedule[timeslot].push_back(eventName);
    } else if (operation == "erase") {
        auto it = schedule.find(timeslot);
        if (it != schedule.end()) {
            schedule.erase(it);
        }
    } else if (operation == "clear") {
        schedule.clear();
    } else {
        throw std::runtime_error("Invalid operation.");
    }
}
