from collections import Counter

class WordFrequencyAnalyzer:
    def __init__(self):
        self.total_counts = Counter()
        self.non_essential_words = []

    def analyze_document(self, document_text, non_essential_words=None):
        if non_essential_words is not None:
            if len(non_essential_words) > 5:
                raise ValueError("Non-essential words list cannot exceed 5 items.")
            self.non_essential_words = non_essential_words.copy()

        words = document_text.split()
        current_counts = Counter(words)
        self.total_counts.update(current_counts)

        for word in self.non_essential_words:
            if word in self.total_counts:
                self.total_counts[word] = 0

        return self.total_counts
