from collections import Counter

class WordFrequencyAnalyzer:
    def __init__(self):
        self.word_counts = Counter()
        self.non_essential_words = [None] * 5  # Fixed size of 5

    def update_non_essential_word(self, index, word):
        if 0 <= index < 5:
            if self.non_essential_words[index] is not None:
                self.word_counts[self.non_essential_words[index]] += 1
            self.non_essential_words[index] = word
            if word in self.word_counts:
                self.word_counts[word] -= 1
                if self.word_counts[word] <= 0:
                    del self.word_counts[word]

    def append_non_essential_word(self, word):
        if None in self.non_essential_words:
            index = self.non_essential_words.index(None)
            self.update_non_essential_word(index, word)

    def remove_non_essential_word(self, word):
        if word in self.non_essential_words:
            index = self.non_essential_words.index(word)
            self.update_non_essential_word(index, None)

    def analyze_document(self, document_text):
        words = document_text.split()
        self.word_counts.update(words)
        for word in self.non_essential_words:
            if word is not None and word in self.word_counts:
                self.word_counts[word] -= 1
                if self.word_counts[word] <= 0:
                    del self.word_counts[word]
