#include <queue>
#include <iostream>

void handleHelpDeskTickets(std::queue<int>& ticketQueue, int action) {
    static int ticketNumber = 1;

    if (action == 1) { // Add ticket
        if (ticketQueue.size() >= 100) {
            std::cout << "Cannot add ticket. Queue is full (100 tickets)." << std::endl;
        } else {
            ticketQueue.emplace(ticketNumber++);
            std::cout << "Added ticket #" << ticketNumber - 1 << std::endl;
        }
    } else if (action == 2) { // Process ticket
        if (ticketQueue.size() <= 10) {
            std::cout << "Cannot process ticket. Minimum 10 tickets must remain." << std::endl;
        } else {
            int processedTicket = ticketQueue.front();
            ticketQueue.pop();
            std::cout << "Processed ticket #" << processedTicket << std::endl;
        }
    }

    std::cout << "Pending tickets: " << ticketQueue.size() << std::endl;
}
