    :param attendees: Dictionary of current attendees and their statuses
    :param name: Name of the attendee
    :param action: 'register', 'check', or 'remove'
    :param status: Registration status (required only for 'register' action)
    :return: Updated attendees dictionary and a log message
    """
    log = ""

    if action == 'register':
        if len(attendees) >= 100:
            log = f"Cannot register {name}. Maximum attendees reached."
        else:
            existing_status = attendees.get(name, None)
            if existing_status is not None:
                log = f"{name} is already registered with status: {existing_status}."
            else:
                attendees[name] = status
                log = f"Registered {name} with status: {status}."

    elif action == 'check':
        status = attendees.get(name, None)
        if status is not None:
            log = f"{name} is registered with status: {status}."
        else:
            log = f"{name} is not registered."

    elif action == 'remove':
        removed_status = attendees.pop(name, None)
        if removed_status is not None:
            log = f"Removed {name} with status: {removed_status}."
        else:
            log = f"{name} is not registered and cannot be removed."

    return attendees, log
