use std::collections::VecDeque;
use std::sync::{Mutex, Arc};

pub struct CustomerSupportQueue {
    queue: Arc<Mutex<VecDeque<String>>>,
    max_capacity: usize,
}

impl CustomerSupportQueue {
    pub fn new(max_capacity: usize) -> Self {
        CustomerSupportQueue {
            queue: Arc::new(Mutex::new(VecDeque::with_capacity(max_capacity))),
            max_capacity,
        }
    }

    pub fn push_back(&self, query: String) {
        let mut queue = self.queue.lock().unwrap();
        if queue.len() >= self.max_capacity {
            queue.pop_front();
        }
        queue.push_back(query);
    }

    pub fn pop_front(&self) -> Option<String> {
        let mut queue = self.queue.lock().unwrap();
        queue.pop_front()
    }

    pub fn front(&self) -> Option<String> {
        let queue = self.queue.lock().unwrap();
        queue.front().cloned()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_queue_operations() {
        let queue = CustomerSupportQueue::new(10);
        queue.push_back("Query 1".to_string());
        queue.push_back("Query 2".to_string());
        assert_eq!(queue.front(), Some("Query 1".to_string()));
        assert_eq!(queue.pop_front(), Some("Query 1".to_string()));
        assert_eq!(queue.front(), Some("Query 2".to_string()));
    }

    #[test]
    fn test_max_capacity() {
        let queue = CustomerSupportQueue::new(2);
        queue.push_back("Query 1".to_string());
        queue.push_back("Query 2".to_string());
        queue.push_back("Query 3".to_string());
        assert_eq!(queue.queue.lock().unwrap().len(), 2);
        assert_eq!(queue.front(), Some("Query 2".to_string()));
    }
}
