class ConferenceManager {
private:
    std::priority_queue<Speaker> speakers;
    const int MAX_SPEAKERS = 20;

public:
    void push(const Speaker& speaker) {
        if (speakers.size() >= MAX_SPEAKERS) {
            throw std::runtime_error("Cannot add more speakers. Queue is full.");
        }
        speakers.push(speaker);
    }

    Speaker pop() {
        if (speakers.empty()) {
            throw std::runtime_error("No speakers available. Queue is empty.");
        }
        Speaker top = speakers.top();
        speakers.pop();
        return top;
    }
};
