#include <queue>
#include <mutex>
#include <stdexcept>
#include <algorithm>

class ConferenceScheduler {
private:
    std::priority_queue<int> speakers;
    std::mutex mtx;
    const int MAX_SPEAKERS = 20;

public:
    void addSpeaker(int rating) {
        std::lock_guard<std::mutex> lock(mtx);
        if (speakers.size() >= MAX_SPEAKERS) {
            // Remove the lowest-rated speaker if queue is full
            std::priority_queue<int> temp;
            while (speakers.size() > 1) {
                temp.push(speakers.top());
                speakers.pop();
            }
            speakers = std::move(temp);
        }
        speakers.push(rating);
    }

    int getNextSpeaker() {
        std::lock_guard<std::mutex> lock(mtx);
        if (speakers.empty()) {
            throw std::runtime_error("No speakers available in the queue.");
        }
        int nextSpeaker = speakers.top();
        speakers.pop();
        return nextSpeaker;
    }

    int viewNextSpeaker() {
        std::lock_guard<std::mutex> lock(mtx);
        if (speakers.empty()) {
            throw std::runtime_error("No speakers available in the queue.");
        }
        return speakers.top();
    }
};
