package main

import (
	"errors"
)

type Queue struct {
	items    []string
	capacity int
}

func NewQueue(capacity int) *Queue {
	return &Queue{
		items:    make([]string, 0),
		capacity: capacity,
	}
}

func (q *Queue) PushBack(userID string) error {
	if len(q.items) >= q.capacity {
		return errors.New("queue is full")
	}
	if float64(len(q.items)) >= 0.7*float64(q.capacity) {
		return errors.New("queue is operating above 70% capacity")
	}
	q.items = append(q.items, userID)
	return nil
}

func (q *Queue) PushFront(userID string) error {
	if len(q.items) >= q.capacity {
		return errors.New("queue is full")
	}
	maxPriority := int(0.2 * float64(len(q.items)))
	if maxPriority < 1 && len(q.items) > 0 {
		maxPriority = 1
	}
	if len(q.items) > 0 && len(q.items[:maxPriority]) >= maxPriority {
		return errors.New("priority requests exceed 20% of current queue size")
	}
	if float64(len(q.items)) >= 0.7*float64(q.capacity) {
		return errors.New("queue is operating above 70% capacity")
	}
	q.items = append([]string{userID}, q.items...)
	return nil
}

func (q *Queue) Pop() (string, error) {
	if len(q.items) == 0 {
		return "", errors.New("queue is empty")
	}
	userID := q.items[0]
	q.items = q.items[1:]
	return userID, nil
}

func (q *Queue) Size() int {
	return len(q.items)
}

// Example usage for ticket booking queue with capacity 10
