    fn add_product(&mut self, id: u32) -> Result<(), InventoryError> {
        if self.products.contains(&id) {
            return Err(InventoryError::DuplicateId);
        }
        if self.products.len() >= self.max_capacity {
            return Err(InventoryError::FullCapacity);
        }
        self.products.insert(id);
        Ok(())
    }

    fn remove_product(&mut self, id: u32) -> Result<(), InventoryError> {
        if !self.products.contains(&id) {
            return Err(InventoryError::ItemNotFound);
        }
        self.products.remove(&id);
        Ok(())
    }
}
