class BrowserTabManager:
    def __init__(self):
        self.tabs = []
        self.max_tabs = 10

    def push(self, tab):
        if len(self.tabs) >= self.max_tabs:
            print(f"Cannot open '{tab}'. Maximum tabs limit ({self.max_tabs}) reached.")
        else:
            self.tabs.append(tab)
            print(f"Opened '{tab}'. Tabs open: {len(self.tabs)}")

    def pop(self):
        if not self.tabs:
            print("No tabs to close.")
        else:
            closed_tab = self.tabs.pop()
            print(f"Closed '{closed_tab}'. Tabs open: {len(self.tabs)}")

    def operate(self, operations):
        for op in operations:
            if op.startswith("OPEN"):
                tab = op.split(" ")[1]
                self.push(tab)
            elif op == "CLOSE":
                self.pop()
