	// Add other task fields as needed
}

type TaskList struct {
	tasks []Task
}

func (tl *TaskList) insertBefore(task Task, position int) bool {
	if len(tl.tasks) >= 10 {
		return false
	}
	if position < 0 || position > len(tl.tasks) {
		return false
	}
	tl.tasks = append(tl.tasks[:position], append([]Task{task}, tl.tasks[position:]...)...)
	return true
}

func (tl *TaskList) remove(index int) bool {
	if index < 0 || index >= len(tl.tasks) {
		return false
	}
	tl.tasks = append(tl.tasks[:index], tl.tasks[index+1:]...)
	return true
}

func main() {
	// Example usage
	tl := TaskList{}
	tl.insertBefore(Task{Name: "Task1"}, 0)
	tl.insertBefore(Task{Name: "Task2"}, 1)
	tl.insertBefore(Task{Name: "HighPriorityTask"}, 0)
	tl.remove(1)
	fmt.Println(tl.tasks)
}
