	return nil
}

func (ts *TaskStack) Pop() (Task, error) {
	if len(ts.tasks) == 0 {
		return Task{}, errors.New("stack is empty")
	}
	task := ts.tasks[len(ts.tasks)-1]
	ts.tasks = ts.tasks[:len(ts.tasks)-1]
	return task, nil
}

