func processScores(scores []int) (highest, lowest int, average float64) {
    if len(scores) == 0 {
        return 0, 0, 0
    }

    highest = scores[0]
    lowest = scores[0]
    sum := 0

    for _, score := range scores {
        if score > highest {
            highest = score
        }
        if score < lowest {
            lowest = score
        }
        sum += score
    }

    average = float64(sum) / float64(len(scores))
    return highest, lowest, average
}

