func NewStudentScores() *StudentScores {
	return &StudentScores{
		scores: make([]int, 10),
	}
}

func (ss *StudentScores) Pop() int {
	if len(ss.scores) == 0 {
		return 0
	}
	popped := ss.scores[len(ss.scores)-1]
	ss.scores = ss.scores[:len(ss.scores)-1]
	return popped
}

func (ss *StudentScores) AddScore(score int) {
	if len(ss.scores) >= 100 {
		ss.Pop()
	}
	ss.scores = append(ss.scores, score)
}

func (ss *StudentScores) CalculateStats() (highest, lowest int, average float64) {
	if len(ss.scores) == 0 {
		return 0, 0, 0
	}

	highest = ss.scores[0]
	lowest = ss.scores[0]
	sum := 0

	for _, score := range ss.scores {
		if score > highest {
			highest = score
		}
		if score < lowest {
			lowest = score
		}
		sum += score
	}

	average = float64(sum) / float64(len(ss.scores))
	return highest, lowest, average
}

func main() {
	scores := NewStudentScores()
	scores.AddScore(85)
	scores.AddScore(90)
	scores.AddScore(78)
	scores.AddScore(92)
	scores.AddScore(88)

	highest, lowest, average := scores.CalculateStats()
	fmt.Printf("Highest: %d, Lowest: %d, Average: %.2f\n", highest, lowest, average)
}
