import java.util.HashMap;

public class MaxNonConsecutiveSum {
    public static int maxSumNonConsecutive(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }
        HashMap<Integer, Integer> cache = new HashMap<>();
        return helper(nums, 0, cache);
    }

    private static int helper(int[] nums, int index, HashMap<Integer, Integer> cache) {
        if (index >= nums.length) {
            return 0;
        }
        if (cache.containsKey(index)) {
            return cache.get(index);
        }
        if (cache.size() >= 10) {
            cache.clear();
        }
        int include = nums[index] + helper(nums, index + 2, cache);
        int exclude = helper(nums, index + 1, cache);
        int maxSum = Math.max(include, exclude);
        cache.put(index, maxSum);
        return maxSum;
    }
}
