import java.util.HashMap;
import java.util.Stack;

public class MaxNonConsecutiveSum {
    public static int maxSumNonConsecutive(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }
        if (nums.length == 1) {
            return nums[0];
        }

        HashMap<Integer, Integer> sumCache = new HashMap<>();
        Stack<Integer> indexStack = new Stack<>();

        sumCache.put(0, nums[0]);
        sumCache.put(1, Math.max(nums[0], nums[1]));
        indexStack.push(0);

        for (int i = 2; i < nums.length; i++) {
            if (sumCache.size() >= 10) {
                sumCache.remove(sumCache.keySet().iterator().next());
            }

            int prevSum = sumCache.get(i - 1);
            int prevPrevSum = sumCache.get(i - 2);
            int currentSum = Math.max(prevSum, prevPrevSum + nums[i]);

            sumCache.put(i, currentSum);
            if (currentSum == prevPrevSum + nums[i]) {
                indexStack.push(i);
            }
        }

        return sumCache.get(nums.length - 1);
    }
}
