import java.util.HashMap;
import java.util.ArrayList;
import java.util.List;

public class SocialNetwork {
    private HashMap<String, List<String>> userFollowers;
    private List<String> followEvents;

    public SocialNetwork() {
        this.userFollowers = new HashMap<>();
        this.followEvents = new ArrayList<>();
    }

    public void follow(String follower, String followee) {
        if (userFollowers.size() >= 50) {
            return; // Skip if HashMap is at capacity
        }
        if (!userFollowers.containsKey(followee)) {
            userFollowers.put(followee, new ArrayList<>());
        }
        userFollowers.get(followee).add(follower);
        followEvents.add(follower + " followed " + followee);
    }

    public String getLatestCommonFollower(String user1, String user2) {
        List<String> followers1 = userFollowers.getOrDefault(user1, new ArrayList<>());
        List<String> followers2 = userFollowers.getOrDefault(user2, new ArrayList<>());
        for (int i = followEvents.size() - 1; i >= 0; i--) {
            String event = followEvents.get(i);
            String[] parts = event.split(" followed ");
            String follower = parts[0];
            String followee = parts[1];
            if (followers1.contains(follower) && followers2.contains(follower)) {
                return follower;
            }
        }
        return null;
    }

    public List<String> suggestFriends(String user) {
        List<String> suggestions = new ArrayList<>();
        List<String> userFollowersList = userFollowers.getOrDefault(user, new ArrayList<>());
        for (String followee : userFollowers.keySet()) {
            if (!followee.equals(user)) {
                List<String> otherFollowers = userFollowers.get(followee);
                for (String follower : otherFollowers) {
                    if (!userFollowersList.contains(follower) && !follower.equals(user) && !suggestions.contains(follower)) {
                        suggestions.add(follower);
                    }
                }
            }
        }
        return suggestions;
    }
}
