import java.util.PriorityQueue;
import java.util.concurrent.locks.ReentrantLock;

public class EventScheduler {
    private final PriorityQueue<Event> eventQueue;
    private final ReentrantLock lock;
    private static final int MAX_SIZE = 10;

    public EventScheduler() {
        this.eventQueue = new PriorityQueue<>((e1, e2) -> Long.compare(e2.getTimestamp(), e1.getTimestamp()));
        this.lock = new ReentrantLock();
    }

    public void addEvent(Event event) {
        lock.lock();
        try {
            if (eventQueue.size() >= MAX_SIZE) {
                eventQueue.poll();
            }
            eventQueue.offer(event);
        } finally {
            lock.unlock();
        }
    }

    public Event getMostRecentEvent() {
        lock.lock();
        try {
            if (eventQueue.isEmpty()) {
                throw new IllegalStateException("No events left in the queue.");
            }
            return eventQueue.peek();
        } finally {
            lock.unlock();
        }
    }

    public Event removeMostRecentEvent() {
        lock.lock();
        try {
            if (eventQueue.isEmpty()) {
                throw new IllegalStateException("No events left in the queue.");
            }
            return eventQueue.poll();
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return eventQueue.size();
        } finally {
            lock.unlock();
        }
    }

    public static class Event {
        private final long timestamp;
        private final String data;

        public Event(long timestamp, String data) {
            this.timestamp = timestamp;
            this.data = data;
        }

        public long getTimestamp() {
            return timestamp;
        }

        public String getData() {
            return data;
        }
    }
}
