fn manage_student_roster(
    roster: &mut BTreeMap<u32, Student>,
    action: Action,
    student_id: u32,
    student_data: Option<Student>,
) -> Result<(), String> {
    match action {
        Action::Add => {
            if roster.len() >= 50 {
                return Err("Roster is full (max 50 entries)".to_string());
            }
            if roster.contains_key(&student_id) {
                return Err("Student ID already exists".to_string());
            }
            if let Some(data) = student_data {
                roster.insert(student_id, data);
            } else {
                return Err("No student data provided for addition".to_string());
            }
        }
        Action::Remove => {
            if roster.remove(&student_id).is_none() {
                return Err("Student ID does not exist".to_string());
            }
        }
    }
    Ok(())
}

enum Action {
    Add,
    Remove,
}
