use std::collections::BTreeMap;

struct StudentRoster {
    students: BTreeMap<u32, String>, // Assuming student data is a String for simplicity
    max_capacity: usize,
}

impl StudentRoster {
    fn new(max_capacity: usize) -> Self {
        StudentRoster {
            students: BTreeMap::new(),
            max_capacity,
        }
    }

    fn add_student(&mut self, id: u32, data: String) {
        if self.students.len() >= self.max_capacity {
            if let Some(oldest_id) = self.students.keys().next().cloned() {
                self.students.remove(&oldest_id);
            }
        }
        self.students.insert(id, data);
    }

    fn remove_student(&mut self, id: u32) -> Result<(), String> {
        if !self.students.contains_key(&id) {
            return Err("Student ID does not exist".to_string());
        }
        self.students.remove(&id);
        Ok(())
    }

    fn contains_student(&self, id: u32) -> bool {
        self.students.contains_key(&id)
    }
}
