use std::collections::HashSet;
use std::time::{SystemTime, UNIX_EPOCH};

struct UserAuthManager {
    authorized_users: HashSet<String>,
    last_login: std::collections::HashMap<String, u64>,
}

impl UserAuthManager {
    fn new() -> Self {
        UserAuthManager {
            authorized_users: HashSet::new(),
            last_login: std::collections::HashMap::new(),
        }
    }

    fn register_user(&mut self, user_id: String) -> bool {
        if self.authorized_users.len() >= 100 {
            return false;
        }
        self.authorized_users.insert(user_id.clone());
        self.last_login.insert(user_id, current_timestamp());
        true
    }

    fn is_authorized(&self, user_id: &str) -> bool {
        self.authorized_users.contains(user_id)
    }

    fn current_capacity(&self) -> usize {
        self.authorized_users.len()
    }

    fn remove_user(&mut self, user_id: &str) -> bool {
        self.authorized_users.remove(user_id);
        self.last_login.remove(user_id).is_some()
    }

    fn clear_inactive_users(&mut self) {
        let current_time = current_timestamp();
        let inactive_users: Vec<String> = self.last_login
            .iter()
            .filter(|(_, &time)| current_time - time > 30 * 24 * 60 * 60)
            .map(|(id, _)| id.clone())
            .collect();

        for user_id in inactive_users {
            self.authorized_users.remove(&user_id);
            self.last_login.remove(&user_id);
        }
    }
}

fn current_timestamp() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs()
}
