#include <stack>

using namespace std;

void manageGuestList() {
    stack<string> guestStack;
    int maxCapacity = 50;
    string command;
    string guestName;

    while (true) {
        cout << "Enter command (push/pop/exit): ";
        cin >> command;

        if (command == "push") {
            if (guestStack.size() >= maxCapacity) {
                cout << "Stack is full. Cannot add more guests." << endl;
                continue;
            }
            cout << "Enter guest name: ";
            cin >> guestName;
            guestStack.push(guestName);
            cout << "Added guest: " << guestName << endl;
        } else if (command == "pop") {
            if (guestStack.empty()) {
                cout << "Error: No guests to remove. Stack is empty." << endl;
                continue;
            }
            string removedGuest = guestStack.top();
            guestStack.pop();
            cout << "Removed guest: " << removedGuest << endl;
        } else if (command == "exit") {
            break;
        } else {
            cout << "Invalid command." << endl;
        }
    }
}
