#include <iostream>
#include <stack>
#include <string>

void manageGuestList() {
    std::stack<std::string> guestStack;
    const int MAX_CAPACITY = 50;
    std::string guest;
    char operation;

    while (true) {
        std::cout << "Enter operation (p for push, o for pop, q to quit): ";
        std::cin >> operation;

        if (operation == 'q') {
            break;
        }

        switch (operation) {
            case 'p':
                if (guestStack.size() >= MAX_CAPACITY) {
                    std::cout << "Stack is full. Cannot add more guests." << std::endl;
                } else {
                    std::cout << "Enter guest name: ";
                    std::cin >> guest;
                    guestStack.push(guest);
                }
                break;
            case 'o':
                if (guestStack.empty()) {
                    std::cout << "No guests to remove. Stack is empty." << std::endl;
                } else {
                    guestStack.pop();
                }
                break;
            default:
                std::cout << "Invalid operation. Use 'p' for push, 'o' for pop, or 'q' to quit." << std::endl;
        }
    }
}
