    def remove_product(self, category, product_name):
        products = self.catalog.get(category, None)
        if products is None:
            return "Category not found"
        try:
            products.remove(product_name)
            return f"Product '{product_name}' removed from category '{category}'"
        except ValueError:
            return "Product not found in category"
