use std::collections::BTreeMap;
use std::sync::Mutex;

pub fn count_colors(colors: Vec<String>) -> Result<BTreeMap<String, usize>, String> {
    if colors.len() > 2500 {
        return Err("Input size exceeds maximum limit of 2500".to_string());
    }

    let map = Mutex::new(BTreeMap::new());

    for color in colors {
        let normalized_color = color.to_lowercase();
        let mut locked_map = map.lock().unwrap();

        if locked_map.len() >= 100 {
            return Err("BTreeMap size exceeds maximum limit of 100".to_string());
        }

        *locked_map.entry(normalized_color).or_insert(0) += 1;
    }

    Ok(map.into_inner().unwrap())
}
