#include <iostream>
#include <stack>
#include <stdexcept>
#include <string>
#include <memory>

// Logger class for logging significant actions
class Logger {
public:
    static void log(const std::string& message) {
        std::cout << "[LOG] " << message << std::endl;
    }
};

// Base Account class
class Account {
protected:
    std::string accountNumber;
    double balance;

public:
    Account(const std::string& accNum, double initialBalance)
        : accountNumber(accNum), balance(initialBalance) {
        Logger::log("Account created: " + accountNumber);
    }

    virtual ~Account() {
        Logger::log("Account destroyed: " + accountNumber);
    }

    virtual double calculateInterest() const = 0;

    void deposit(double amount) {
        if (amount <= 0) {
            throw std::invalid_argument("Deposit amount must be positive");
        }
        balance += amount;
        Logger::log("Deposited " + std::to_string(amount) + " to " + accountNumber);
    }

    virtual void withdraw(double amount) {
        if (amount <= 0) {
            throw std::invalid_argument("Withdrawal amount must be positive");
        }
        if (balance < amount) {
            throw std::runtime_error("Insufficient funds for withdrawal");
        }
        balance -= amount;
        Logger::log("Withdrew " + std::to_string(amount) + " from " + accountNumber);
    }

    double getBalance() const {
        return balance;
    }

    std::string getAccountNumber() const {
        return accountNumber;
    }
};

// Savings Account
class SavingsAccount : public Account {
private:
    double interestRate;

public:
    SavingsAccount(const std::string& accNum, double initialBalance, double rate)
        : Account(accNum, initialBalance), interestRate(rate) {}

    double calculateInterest() const override {
        return balance * interestRate;
    }
};

// Checking Account
class CheckingAccount : public Account {
private:
    double interestRate;
    double overdraftLimit;

public:
    CheckingAccount(const std::string& accNum, double initialBalance, double rate, double limit)
        : Account(accNum, initialBalance), interestRate(rate), overdraftLimit(limit) {}

    double calculateInterest() const override {
        return balance * interestRate;
    }

    void withdraw(double amount) override {
        if (amount <= 0) {
            throw std::invalid_argument("Withdrawal amount must be positive");
        }
        if (balance + overdraftLimit < amount) {
            throw std::runtime_error("Overdraft limit exceeded");
        }
        balance -= amount;
        Logger::log("Withdrew " + std::to_string(amount) + " from " + accountNumber);
    }
};

// Joint Account
class JointAccount : public Account {
private:
    double interestRate;
    std::string jointHolder;

public:
    JointAccount(const std::string& accNum, double initialBalance, double rate, const std::string& holder)
        : Account(accNum, initialBalance), interestRate(rate), jointHolder(holder) {}

    double calculateInterest() const override {
        return balance * interestRate * 1.1; // Joint accounts get 10% more interest
    }

    std::string getJointHolder() const {
        return jointHolder;
    }
};

// AccountManager to handle stack operations
class AccountManager {
private:
    std::stack<std::unique_ptr<Account>> accounts;
    const int MAX_ACCOUNTS = 300;

public:
    void push(std::unique_ptr<Account> account) {
        if (accounts.size() >= MAX_ACCOUNTS) {
            throw std::runtime_error("Account stack is full (max 300 accounts)");
        }
        if (!account) {
            throw std::invalid_argument("Cannot push null account");
        }
        accounts.push(std::move(account));
        Logger::log("Pushed account " + accounts.top()->getAccountNumber() + " to stack");
    }

    std::unique_ptr<Account> pop() {
        if (accounts.empty()) {
            throw std::runtime_error("Account stack is empty");
        }
        auto account = std::move(accounts.top());
        accounts.pop();
        Logger::log("Popped account " + account->getAccountNumber() + " from stack");
        return account;
    }

    bool isEmpty() const {
        return accounts.empty();
    }

    size_t size() const {
        return accounts.size();
    }
};

int main() {
    AccountManager manager;

    try {
        manager.push(std::make_unique<SavingsAccount>("SA001", 1000.0, 0.05));
        manager.push(std::make_unique<CheckingAccount>("CA001", 2000.0, 0.02, 500.0));
        manager.push(std::make_unique<JointAccount>("JA001", 3000.0, 0.03, "John Doe"));

        // Example operations
        auto account1 = manager.pop();
        account1->deposit(500.0);
        std::cout << "Interest for " << account1->getAccountNumber() << ": " 
                  << account1->calculateInterest() << std::endl;

        auto account2 = manager.pop();
        account2->withdraw(100.0);
        std::cout << "Interest for " << account2->getAccountNumber() << ": " 
                  << account2->calculateInterest() << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
