    void withdraw(double amount) {
        std::lock_guard<std::mutex> lock(mtx);
        if (amount <= 0) {
            Logger::log("Withdrawal failed: Invalid amount for account " + accountNumber);
            throw std::invalid_argument("Invalid withdrawal amount");
        }
        if (balance < amount) {
            Logger::log("Withdrawal failed: Insufficient funds in account " + accountNumber);
            throw std::runtime_error("Insufficient funds");
        }
        balance -= amount;
        Logger::log("Withdrew " + std::to_string(amount) + " from account " + accountNumber);
    }

    double getBalance() const {
        std::lock_guard<std::mutex> lock(mtx);
        return balance;
    }

    std::string getAccountNumber() const {
        return accountNumber;
    }

