// Account Stack Manager
class AccountStack {
private:
    std::stack<std::shared_ptr<Account>> accounts;
    mutable std::mutex mtx;
    const size_t MAX_SIZE = 300;

public:
    void push(std::shared_ptr<Account> account) {
        std::lock_guard<std::mutex> lock(mtx);
        if (accounts.size() >= MAX_SIZE) {
            Logger::log("Account stack is full. Cannot push more accounts.");
            throw std::runtime_error("Account stack is full");
        }
        if (!account) {
            Logger::log("Attempted to push a null account to the stack.");
            throw std::invalid_argument("Null account");
        }
        accounts.push(account);
        Logger::log("Pushed account " + account->getAccountNumber() + " to the stack.");
    }

    std::shared_ptr<Account> pop() {
        std::lock_guard<std::mutex> lock(mtx);
        if (accounts.empty()) {
            Logger::log("Account stack is empty. Cannot pop any account.");
            throw std::runtime_error("Account stack is empty");
        }
        auto account = accounts.top();
        accounts.pop();
        Logger::log("Popped account " + account->getAccountNumber() + " from the stack.");
        return account;
    }

    bool isEmpty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return accounts.empty();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mtx);
        return accounts.size();
    }

    void saveToFile(const std::string& filename) {
        std::lock_guard<std::mutex> lock(mtx);
        std::ofstream outFile(filename);
        if (!outFile) {
            Logger::log("Failed to open file for saving account stack.");
            throw std::runtime_error("Failed to open file");
        }

        auto tempStack = accounts;
        while (!tempStack.empty()) {
            auto account = tempStack.top();
            tempStack.pop();
            outFile << account->getType() << ","
                   << account->getAccountNumber() << ","
                   << account->getAccountHolder() << ","
                   << account->getBalance() << "\n";
        }
        Logger::log("Saved account stack to file: " + filename);
    }

    void loadFromFile(const std::string& filename) {
        std::lock_guard<std::mutex> lock(mtx);
        std::ifstream inFile(filename);
        if (!inFile) {
            Logger::log("Failed to open file for loading account stack.");
            throw std::runtime_error("Failed to open file");
        }

        while (!accounts.empty()) {
            accounts.pop();
        }

        std::string line;
        while (std::getline(inFile, line)) {
            std::istringstream iss(line);
            std::string type, number, holder;
            double balance;
            char delimiter;

            if (!(iss >> type >> delimiter >> number >> delimiter >> holder >> delimiter >> balance)) {
                Logger::log("Invalid account data in file.");
                continue;
            }

            std::shared_ptr<Account> account;
            if (type == "Savings") {
                account = std::make_shared<SavingsAccount>(number, holder, balance, 2.5);
            } else if (type == "Checking") {
                account = std::make_shared<CheckingAccount>(number, holder, balance, 500.0);
            } else if (type == "Joint") {
                std::vector<std::string> holders = {holder};
                account = std::make_shared<JointAccount>(number, holders, balance, 1.5);
            }

            if (account) {
                accounts.push(account);
            }
        }
        Logger::log("Loaded account stack from file: " + filename);
    }
};

int main() {
    AccountStack accountStack;

    try {
        // Example usage
        auto savings = std::make_shared<SavingsAccount>("SA001", "Alice", 1000.0, 2.5);
        auto checking = std::make_shared<CheckingAccount>("CA001", "Bob", 2000.0, 500.0);
        std::vector<std::string> holders = {"Charlie", "Dave"};
        auto joint = std::make_shared<JointAccount>("JA001", holders, 3000.0, 1.5);

        accountStack.push(savings);
        accountStack.push(checking);
        accountStack.push(joint);

        // Save to file
        accountStack.saveToFile("accounts.dat");

        // Load from file
        AccountStack newStack;
        newStack.loadFromFile("accounts.dat");

        // Perform operations
        auto acc = newStack.pop();
        acc->deposit(500.0);
        acc->withdraw(200.0);
        std::cout << "Account " << acc->getAccountNumber() << " balance: " << acc->getBalance() << std::endl;

    } catch (const std::exception& e) {
        Logger::log(std::string("Error: ") + e.what());
    }

    return 0;
}
