        Account::log("Added account " + account->getAccountNumber() + " of type " + account->getAccountType());
    }

    void removeAccount() {
        std::lock_guard<std::mutex> lock(accountMutex);
        if (accounts.empty()) {
            Account::log("Failed to remove account: No accounts available");
            throw std::runtime_error("No accounts available");
        }
        auto account = accounts.back();
        accounts.pop_back();
        Account::log("Removed account " + account->getAccountNumber() + " of type " + account->getAccountType());
    }

    void saveAccounts() {
        std::lock_guard<std::mutex> lock(accountMutex);
        std::ofstream outFile("accounts.dat", std::ios::binary);
        if (!outFile) {
            Account::log("Failed to save accounts: Unable to open file");
            throw std::runtime_error("Unable to open file for saving accounts");
        }
        for (const auto& account : accounts) {
            outFile << account->getAccountNumber() << " "
                    << account->getBalance() << " "
                    << account->getAccountType() << "\n";
        }
        Account::log("Saved all accounts to file");
    }

    void loadAccounts() {
        std::lock_guard<std::mutex> lock(accountMutex);
        std::ifstream inFile("accounts.dat", std::ios::binary);
        if (!inFile) {
            Account::log("No previous account data found");
            return;
        }
        accounts.clear();
        std::string accNum, accType;
        double balance;
        while (inFile >> accNum >> balance >> accType) {
            if (accType == "Savings") {
                accounts.push_back(std::make_shared<SavingsAccount>(accNum, balance, 1.5));
            } else if (accType == "Checking") {
                accounts.push_back(std::make_shared<CheckingAccount>(accNum, balance, 0.5));
            } else if (accType == "Joint") {
                accounts.push_back(std::make_shared<JointAccount>(accNum, balance, 1.0, "Secondary Holder"));
            }
        }
        Account::log("Loaded accounts from file");
    }
};

