class RestrictedDict(dict):
    def __delitem__(self, key):
        raise TypeError("Deletion not supported")

    def __setitem__(self, key, value):
        if key in self:
            raise TypeError("Reassignment not supported")
        if len(self) >= 1000:
            raise MemoryError("Memoization dictionary size limit reached")
        super().__setitem__(key, value)

def fibonacci(n, memo=RestrictedDict()):
    if n < 0:
        raise ValueError("Input must be a non-negative integer")
    if n in memo:
        return memo[n]
    if n <= 1:
        memo[n] = n
        return n
    memo[n] = fibonacci(n-1, memo) + fibonacci(n-2, memo)
    return memo[n]

def generate_fibonacci_sequence(length):
    if length > 1000:
        raise ValueError("Sequence length exceeds maximum limit of 1000")
    sequence = []
    for i in range(length):
        sequence.append(fibonacci(i))
    return sequence
