	"sync"
	"time"
)

type Message struct {
	User    string
	Content string
}

type ChatServer struct {
	messageChan chan Message
	wg          sync.WaitGroup
}

func NewChatServer(bufferSize int) *ChatServer {
	return &ChatServer{
		messageChan: make(chan Message, bufferSize),
	}
}

func (cs *ChatServer) SendMessage(user, content string) {
	select {
	case cs.messageChan <- Message{User: user, Content: content}:
		fmt.Printf("Message sent by %s: %s\n", user, content)
	default:
		fmt.Println("Channel is full. Message dropped.")
	}
}

func (cs *ChatServer) ProcessMessages() {
	cs.wg.Add(1)
	go func() {
		defer cs.wg.Done()
		for msg := range cs.messageChan {
			fmt.Printf("Processed message from %s: %s\n", msg.User, msg.Content)
			time.Sleep(100 * time.Millisecond) // Simulate processing time
		}
	}()
}

func (cs *ChatServer) Stop() {
	close(cs.messageChan)
	cs.wg.Wait()
}

func main() {
	chatServer := NewChatServer(200)
	chatServer.ProcessMessages()

	// Simulate multiple users sending messages
	for i := 0; i < 250; i++ {
		user := fmt.Sprintf("User%d", i%10)
		content := fmt.Sprintf("Hello %d", i)
		chatServer.SendMessage(user, content)
	}

	chatServer.Stop()
}
