package main

import (
	"fmt"
	"sync"
)

type Message struct {
	User    string
	Content string
}

type ChatServer struct {
	messages chan Message
	mu       sync.Mutex
}

func NewChatServer() *ChatServer {
	return &ChatServer{
		messages: make(chan Message, 200),
	}
}

func (cs *ChatServer) AddMessage(user, content string) bool {
	cs.mu.Lock()
	defer cs.mu.Unlock()

	if len(cs.messages) == cap(cs.messages) {
		return false
	}

	cs.messages <- Message{User: user, Content: content}
	return true
}

func (cs *ChatServer) Start() {
	for msg := range cs.messages {
		fmt.Printf("[%s]: %s\n", msg.User, msg.Content)
	}
}

func main() {
	server := NewChatServer()
	go server.Start()

	var wg sync.WaitGroup
	wg.Add(1)

	go func() {
		defer wg.Done()
		for i := 0; i < 250; i++ {
			user := fmt.Sprintf("User%d", i%10)
			content := fmt.Sprintf("Message %d", i)
			if !server.AddMessage(user, content) {
				fmt.Println("Channel full. Message discarded.")
			}
		}
		close(server.messages)
	}()

	wg.Wait()
}
