import collections
import operator

def evaluate_expression():
    cache = collections.defaultdict(lambda: None)
    cache_info = {'size': 0, 'max_size': 1000}

    def get(key):
        return cache[key]

    def set(key, value):
        if cache_info['size'] >= cache_info['max_size']:
            cache.pop(next(iter(cache)))
            cache_info['size'] -= 1
        cache[key] = value
        cache_info['size'] += 1

    def evaluate(expr):
        if expr in cache:
            return get(expr)

        # Tokenize the expression
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i] == ' ':
                i += 1
                continue
            if expr[i] in '()+-*/':
                tokens.append(expr[i])
                i += 1
            else:
                j = i
                while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                    j += 1
                tokens.append(expr[i:j])
                i = j

        # Convert infix to postfix notation
        output = []
        ops = []
        precedence = {'+': 1, '-': 1, '*': 2, '/': 2}

        for token in tokens:
            if token.replace('.', '').isdigit():
                output.append(float(token))
            elif token == '(':
                ops.append(token)
            elif token == ')':
                while ops[-1] != '(':
                    output.append(ops.pop())
                ops.pop()
            else:
                while ops and ops[-1] != '(' and precedence[ops[-1]] >= precedence[token]:
                    output.append(ops.pop())
                ops.append(token)

        while ops:
            output.append(ops.pop())

        # Evaluate postfix expression
        stack = []
        for token in output:
            if isinstance(token, float):
                stack.append(token)
            else:
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(a / b)

        result = stack[0]
        set(expr, result)
        return result

    return evaluate

evaluate = evaluate_expression()
