import collections
import operator

def evaluate_expression(expr):
    cache = collections.defaultdict(lambda: None)
    stack = []

    def get_from_cache(key):
        nonlocal stack
        stack.append(('get', key))
        return cache[key]

    def set_to_cache(key, value):
        nonlocal stack
        if len(cache) >= 1000:
            # Simulate stack-based eviction (pop oldest if needed)
            if stack:
                oldest_op, oldest_key = stack.pop(0)
                if oldest_op == 'set':
                    del cache[oldest_key]
        stack.append(('set', key))
        cache[key] = value

    def compute(s):
        if s in cache:
            return get_from_cache(s)

        num = 0
        stack = []
        sign = '+'
        i = 0

        while i < len(s):
            c = s[i]
            if c.isdigit():
                num = num * 10 + int(c)
                i += 1
            elif c == '(':
                cnt = 1
                j = i + 1
                while j < len(s) and cnt > 0:
                    if s[j] == '(':
                        cnt += 1
                    elif s[j] == ')':
                        cnt -= 1
                    j += 1
                num = compute(s[i+1:j-1])
                i = j
            else:
                if sign == '+':
                    stack.append(num)
                elif sign == '-':
                    stack.append(-num)
                elif sign == '*':
                    stack.append(stack.pop() * num)
                elif sign == '/':
                    stack.append(int(stack.pop() / num))
                sign = c
                num = 0
                i += 1

        if sign == '+':
            stack.append(num)
        elif sign == '-':
            stack.append(-num)
        elif sign == '*':
            stack.append(stack.pop() * num)
        elif sign == '/':
            stack.append(int(stack.pop() / num))

        result = sum(stack)
        set_to_cache(s, result)
        return result

    return compute(expr.replace(' ', ''))
