import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.Iterator;
import java.util.Map;
import java.util.concurrent.TimeUnit;

public class SessionManager {
    private static final int MAX_SESSIONS = 500;
    private static final long INACTIVITY_THRESHOLD = TimeUnit.MINUTES.toMillis(30);
    private static final int MAX_OPERATIONS = 10;

    private final ConcurrentHashMap<String, Long> activeSessions = new ConcurrentHashMap<>();
    private final AtomicInteger operationCount = new AtomicInteger(0);

    public boolean addSession(String sessionId) {
        if (activeSessions.size() >= MAX_SESSIONS) {
            return false;
        }
        performOperation(1);
        activeSessions.put(sessionId, System.currentTimeMillis());
        return true;
    }

    public void removeSession(String sessionId) {
        performOperation(2);
        activeSessions.remove(sessionId);
    }

    public boolean isSessionActive(String sessionId) {
        performOperation(3);
        return activeSessions.containsKey(sessionId);
    }

    public void updateSessionTimestamp(String sessionId) {
        performOperation(4);
        activeSessions.computeIfPresent(sessionId, (k, v) -> System.currentTimeMillis());
    }

    public void cleanupInactiveSessions() {
        performOperation(5);
        long currentTime = System.currentTimeMillis();
        Iterator<Map.Entry<String, Long>> iterator = activeSessions.entrySet().iterator();
