    private final ConcurrentHashMap<String, Long> sessionMap;
    private final AtomicInteger operationCount;

    public SessionMonitor() {
        this.sessionMap = new ConcurrentHashMap<>(MAX_CAPACITY);
        this.operationCount = new AtomicInteger(0);
    }

