        if (sessionMap.size() >= MAX_SESSIONS) {
            return false;
        }
        if (sessionMap.size() < MAX_CAPACITY) {
            sessionMap.put(sessionId, System.currentTimeMillis());
            incrementOperationCount();
            return true;
        }
        return false;
    }

    public synchronized void removeInactiveSessions() {
        long currentTime = System.currentTimeMillis();
        sessionMap.entrySet().removeIf(entry -> 
            (currentTime - entry.getValue()) > INACTIVITY_THRESHOLD
        );
        incrementOperationCount();
    }

    public synchronized boolean containsSession(String sessionId) {
        incrementOperationCount();
        return sessionMap.containsKey(sessionId);
    }

    public synchronized void updateSessionTimestamp(String sessionId) {
        if (sessionMap.containsKey(sessionId)) {
            sessionMap.put(sessionId, System.currentTimeMillis());
            incrementOperationCount();
        }
    }

    public synchronized void removeSession(String sessionId) {
        sessionMap.remove(sessionId);
        incrementOperationCount();
    }

    public synchronized int getActiveSessionCount() {
        incrementOperationCount();
        return sessionMap.size();
    }

    public synchronized void clearAllSessions() {
        sessionMap.clear();
        incrementOperationCount();
    }

    public synchronized boolean isSessionActive(String sessionId) {
        incrementOperationCount();
        Long timestamp = sessionMap.get(sessionId);
        if (timestamp == null) {
            return false;
        }
        return (System.currentTimeMillis() - timestamp) <= INACTIVITY_THRESHOLD;
    }

    public synchronized void replaceSession(String oldSessionId, String newSessionId) {
        if (sessionMap.containsKey(oldSessionId)) {
            Long timestamp = sessionMap.remove(oldSessionId);
            sessionMap.put(newSessionId, timestamp);
            incrementOperationCount();
        }
    }

    public synchronized void mergeSessions(String sessionId1, String sessionId2) {
        if (sessionMap.containsKey(sessionId1) && sessionMap.containsKey(sessionId2)) {
            Long timestamp1 = sessionMap.get(sessionId1);
            Long timestamp2 = sessionMap.get(sessionId2);
            sessionMap.put(sessionId1, Math.max(timestamp1, timestamp2));
            sessionMap.remove(sessionId2);
            incrementOperationCount();
        }
    }

    private void incrementOperationCount() {
        if (operationCount.incrementAndGet() > 10) {
            throw new IllegalStateException("Exceeded maximum allowed operations (10)");
        }
    }
