        LinkedList<Integer> mergedList = new LinkedList<>();
        if (lists == null || lists.isEmpty()) {
            return ensureMinimumSize(mergedList);
        }

        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        for (LinkedList<Integer> list : lists) {
            if (list != null) {
                for (Integer num : list) {
                    if (num != null) {
                        minHeap.add(num); // or minHeap.offer(num);
                    }
                }
            }
        }

        while (!minHeap.isEmpty()) {
            mergedList.add(minHeap.poll());
        }

        return ensureMinimumSize(mergedList);
    }

    private static LinkedList<Integer> ensureMinimumSize(LinkedList<Integer> list) {
        while (list.size() < 10) {
            list.add(0); // or list.offer(0);
        }
        return list;
    }
}
