package main

import (
	"errors"
	"fmt"
)

type StudentRecord struct {
	Name  string
	Grade int
}

type Stack struct {
	records []StudentRecord
	maxSize int
}

func NewStack(maxSize int) *Stack {
	return &Stack{
		records: make([]StudentRecord, 0),
		maxSize: maxSize,
	}
}

func (s *Stack) Push(record StudentRecord) error {
	if len(s.records) >= s.maxSize {
		return errors.New("stack is full")
	}
	if record.Name == "" {
		return errors.New("student name cannot be empty")
	}
	if record.Grade < 0 || record.Grade > 100 {
		return errors.New("grade must be between 0 and 100")
	}
	if len(s.records) > 0 && s.records[len(s.records)-1].Name == record.Name {
		return errors.New("student name already exists at the top of the stack")
	}
	s.records = append(s.records, record)
	return nil
}

func (s *Stack) UpdateTopGrade(name string, newGrade int) error {
	if len(s.records) == 0 {
		return errors.New("stack is empty")
	}
	top := &s.records[len(s.records)-1]
	if top.Name != name {
		return errors.New("student name does not match the top record")
	}
	if newGrade < 0 || newGrade > 100 {
		return errors.New("grade must be between 0 and 100")
	}
	top.Grade = newGrade
	return nil
}

func (s *Stack) Pop() (StudentRecord, error) {
	if len(s.records) == 0 {
		return StudentRecord{}, errors.New("stack is empty")
	}
	record := s.records[len(s.records)-1]
	s.records = s.records[:len(s.records)-1]
	return record, nil
}

func (s *Stack) Iterate() []StudentRecord {
	records := make([]StudentRecord, len(s.records))
	copy(records, s.records)
	return records
}

func main() {
	stack := NewStack(2000)

	// Example usage
	err := stack.Push(StudentRecord{Name: "Alice", Grade: 85})
	if err != nil {
		fmt.Println("Error:", err)
	}

	err = stack.UpdateTopGrade("Alice", 90)
	if err != nil {
		fmt.Println("Error:", err)
	}

	records := stack.Iterate()
	for _, record := range records {
		fmt.Printf("Name: %s, Grade: %d\n", record.Name, record.Grade)
	}

	popped, err := stack.Pop()
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("Popped: Name: %s, Grade: %d\n", popped.Name, popped.Grade)
	}
}
