use std::collections::HashSet;

fn max_non_adjacent_sum(arr: &[u32]) -> u32 {
    let n = arr.len();
    if n == 0 {
        return 0;
    }
    if n == 1 {
        return arr[0];
    }

    let mut dp = vec![0; n];
    let mut sum_set = HashSet::with_capacity(1500.min(n * 2));

    dp[0] = arr[0];
    sum_set.insert(dp[0]);

    dp[1] = arr[1].max(dp[0]);
    sum_set.insert(dp[1]);

    for i in 2..n {
        let prev_max = if let Some(&max) = sum_set.get(&dp[i - 2]) {
            max
        } else {
            0
        };
        dp[i] = (arr[i] + prev_max).max(dp[i - 1]);
        sum_set.insert(dp[i]);

        if sum_set.len() > 1500 {
            sum_set.clear();
            sum_set.insert(dp[i - 1]);
            sum_set.insert(dp[i]);
        }
    }

    dp[n - 1]
}

fn main() {
    let arr = [1, 2, 3, 1, 4, 5, 2];
    println!("Maximum sum of non-adjacent elements: {}", max_non_adjacent_sum(&arr));
}
