    let n = nums.len();
    if n == 0 {
        return 0;
    }
    if n == 1 {
        return nums[0];
    }

    let mut dp = vec![0; n];
    let mut sum_set = HashSet::with_capacity(750);

    dp[0] = nums[0];
    dp[1] = std::cmp::max(nums[0], nums[1]);
    sum_set.insert(dp[0]);
    sum_set.insert(dp[1]);

    for i in 2..n {
        let prev_max = if let Some(&max) = sum_set.get(&dp[i - 1]) {
            max
        } else {
            dp[i - 1]
        };
        let prev_prev_max = if let Some(&max) = sum_set.get(&dp[i - 2]) {
            max
        } else {
            dp[i - 2]
        };
        dp[i] = std::cmp::max(prev_max, prev_prev_max + nums[i]);
        sum_set.insert(dp[i]);

        if sum_set.len() > 1500 {
            sum_set.clear();
            for &num in &dp {
                sum_set.insert(num);
            }
        }
    }

    dp[n - 1]
}

fn main() {
