public class WordFrequencyCounter {
    public static Map<String, Integer> countWordFrequency(String input) {
        if (input == null || input.isEmpty()) {
            return new HashMap<>();
        }

        Map<String, Integer> wordFrequency = new HashMap<>();
        String[] words = input.toLowerCase().split("\\s+");

        for (String word : words) {
            String cleanedWord = word.replaceAll("[^a-zA-Z]", "");
            if (cleanedWord.isEmpty()) {
                continue;
            }

            if (wordFrequency.size() >= 100) {
                break;
            }

            if (wordFrequency.containsKey(cleanedWord)) {
                wordFrequency.put(cleanedWord, wordFrequency.get(cleanedWord) + 1);
            } else {
                wordFrequency.put(cleanedWord, 1);
            }
        }

        if (wordFrequency.size() > 20) {
            System.err.println("Error: More than 20 unique words detected.");
            return null;
        }

        if (wordFrequency.size() > 10000) {
            return null;
        }

        return wordFrequency;
    }
}
