class Flight {
public:
    std::string flightNumber;
    int totalSeats;
    int bookedSeats;

    Flight(const std::string& num, int seats) : flightNumber(num), totalSeats(seats), bookedSeats(0) {}

    bool reserveSeats(int seats) {
        if (bookedSeats + seats > totalSeats) {
            throw std::runtime_error("Overbooking not allowed.");
        }
        bookedSeats += seats;
        return true;
    }

    bool cancelSeats(int seats) {
        if (bookedSeats - seats < 0) {
            throw std::runtime_error("Invalid cancellation. Not enough booked seats.");
        }
        bookedSeats -= seats;
        return true;
    }

    int availableSeats() const {
        return totalSeats - bookedSeats;
    }
};

class Airline {
private:
    std::vector<Flight> flights;
    const int MAX_FLIGHTS = 300;

public:
    bool addFlight(const std::string& flightNumber, int totalSeats) {
        if (flights.size() >= MAX_FLIGHTS) {
            throw std::runtime_error("Maximum flights limit reached for this airline.");
        }
        flights.emplace_back(flightNumber, totalSeats);
        return true;
    }

    Flight* getFlight(const std::string& flightNumber) {
        for (auto& flight : flights) {
            if (flight.flightNumber == flightNumber) {
                return &flight;
            }
        }
        return nullptr;
    }

    bool removeFlight(const std::string& flightNumber) {
        for (auto it = flights.begin(); it != flights.end(); ++it) {
            if (it->flightNumber == flightNumber) {
                flights.erase(it);
                return true;
            }
        }
        return false;
    }
};

class FlightReservationSystem {
private:
    std::unordered_map<std::string, Airline> airlines;

public:
    bool addAirline(const std::string& airlineName) {
        if (airlines.find(airlineName) != airlines.end()) {
            throw std::runtime_error("Airline already exists.");
        }
        airlines[airlineName] = Airline();
        return true;
    }

    bool addFlight(const std::string& airlineName, const std::string& flightNumber, int totalSeats) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found.");
        }
        return it->second.addFlight(flightNumber, totalSeats);
    }

    bool reserveSeats(const std::string& airlineName, const std::string& flightNumber, int seats) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found.");
        }
        Flight* flight = it->second.getFlight(flightNumber);
        if (!flight) {
            throw std::runtime_error("Flight not found.");
        }
        return flight->reserveSeats(seats);
    }

    bool cancelSeats(const std::string& airlineName, const std::string& flightNumber, int seats) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found.");
        }
        Flight* flight = it->second.getFlight(flightNumber);
        if (!flight) {
            throw std::runtime_error("Flight not found.");
        }
        return flight->cancelSeats(seats);
    }

