use std::collections::VecDeque;
use std::fs::File;
use std::io::{self, Read, Write};
use std::path::Path;
use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Debug)]
struct Task {
    description: String,
    completed: bool,
}

const MAX_TASKS: usize = 30;

fn save_tasks(tasks: &VecDeque<Task>, path: &str) -> io::Result<()> {
    let serialized = serde_json::to_string(tasks)?;
    let mut file = File::create(path)?;
    file.write_all(serialized.as_bytes())?;
    Ok(())
}

fn load_tasks(path: &str) -> io::Result<VecDeque<Task>> {
    if !Path::new(path).exists() {
        return Ok(VecDeque::new());
    }
    let mut file = File::open(path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;
    let tasks: VecDeque<Task> = serde_json::from_str(&contents)?;
    Ok(tasks)
}

fn add_task(tasks: &mut VecDeque<Task>, description: String, high_priority: bool) {
    if tasks.len() >= MAX_TASKS {
        tasks.pop_back();
    }
    let task = Task {
        description,
        completed: false,
    };
    if high_priority {
        tasks.push_front(task);
    } else {
        tasks.push_back(task);
    }
}

fn remove_task(tasks: &mut VecDeque<Task>) -> Option<Task> {
    tasks.pop_back()
}

fn view_tasks(tasks: &VecDeque<Task>) {
    for (i, task) in tasks.iter().enumerate() {
        println!("{}: [{}] {}", i + 1, if task.completed { "X" } else { " " }, task.description);
    }
}

fn mark_completed(tasks: &mut VecDeque<Task>, index: usize) -> bool {
    if let Some(task) = tasks.get_mut(index) {
        task.completed = true;
        true
    } else {
        false
    }
}

fn prioritize_task(tasks: &mut VecDeque<Task>, index: usize) -> bool {
    if index < tasks.len() {
        let task = tasks.remove(index).unwrap();
        tasks.push_front(task);
        true
    } else {
        false
    }
}

fn main() -> io::Result<()> {
    let mut tasks = load_tasks("tasks.json")?;
    let mut input = String::new();

    loop {
        println!("Commands: add [high], remove, view, complete <index>, prioritize <index>, exit");
        input.clear();
        io::stdin().read_line(&mut input)?;
        let parts: Vec<&str> = input.trim().split_whitespace().collect();

        match parts.as_slice() {
            ["add", "high", desc @ ..] => {
                let description = desc.join(" ");
                add_task(&mut tasks, description, true);
            },
            ["add", desc @ ..] => {
                let description = desc.join(" ");
                add_task(&mut tasks, description, false);
            },
            ["remove"] => {
                if let Some(task) = remove_task(&mut tasks) {
                    println!("Removed: {}", task.description);
                } else {
                    println!("No tasks to remove");
                }
            },
            ["view"] => {
                view_tasks(&tasks);
            },
            ["complete", index] => {
                if let Ok(i) = index.parse::<usize>() {
                    if mark_completed(&mut tasks, i - 1) {
                        println!("Task marked as completed");
                    } else {
                        println!("Invalid task index");
                    }
                } else {
                    println!("Invalid index");
                }
            },
            ["prioritize", index] => {
                if let Ok(i) = index.parse::<usize>() {
                    if prioritize_task(&mut tasks, i - 1) {
                        println!("Task prioritized");
                    } else {
                        println!("Invalid task index");
                    }
                } else {
                    println!("Invalid index");
                }
            },
            ["exit"] => break,
            _ => println!("Unknown command"),
        }
    }

    save_tasks(&tasks, "tasks.json")?;
    Ok(())
}
