#include <iostream>
#include <vector>
#include <queue>
#include <unordered_set>
#include <climits>

using namespace std;

struct Intersection {
    int x, y;
    int dist;
};

struct CompareDist {
    bool operator()(const Intersection& a, const Intersection& b) {
        return a.dist > b.dist;
    }
};

int shortestPath(vector<vector<int>>& grid, int startX, int startY, int endX, int endY) {
    int rows = grid.size();
    if (rows == 0) return -1;
    int cols = grid[0].size();

    vector<vector<int>> dist(rows, vector<int>(cols, INT_MAX));
    dist[startX][startY] = 0;

    priority_queue<Intersection, vector<Intersection>, CompareDist> pq;
    pq.push({startX, startY, 0});

    unordered_set<int> visited;
    auto hash = [cols](int x, int y) { return x * cols + y; };

    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};

    while (!pq.empty()) {
        Intersection current = pq.top();
        pq.pop();

        if (current.x == endX && current.y == endY) {
            return current.dist;
        }

        int key = hash(current.x, current.y);
        if (visited.find(key) != visited.end()) continue;

        visited.insert(key);
        if (visited.size() > 500) {
            visited.clear();
        }

        for (int i = 0; i < 4; ++i) {
            int nx = current.x + dx[i];
            int ny = current.y + dy[i];

            if (nx >= 0 && nx < rows && ny >= 0 && ny < cols && grid[nx][ny] != -1) {
                int newDist = current.dist + grid[nx][ny];
                if (newDist < dist[nx][ny]) {
                    dist[nx][ny] = newDist;
                    pq.push({nx, ny, newDist});
                }
            }
        }
    }

    return -1;
}

int main() {
    vector<vector<int>> grid = {
        {1, 3, 1},
        {1, -1, 1},
        {1, 1, 1}
    };

    int startX = 0, startY = 0;
    int endX = 2, endY = 2;

    cout << "Shortest path distance: " << shortestPath(grid, startX, startY, endX, endY) << endl;
    return 0;
}
