#include <iostream>
#include <vector>
#include <queue>
#include <unordered_set>
#include <climits>

using namespace std;

struct Point {
    int x, y;
    Point(int x, int y) : x(x), y(y) {}
    bool operator==(const Point &other) const {
        return x == other.x && y == other.y;
    }
};

namespace std {
    template<>
    struct hash<Point> {
        size_t operator()(const Point &p) const {
            return hash<int>()(p.x) ^ hash<int>()(p.y);
        }
    };
}

vector<vector<int>> grid;
vector<vector<int>> dist;
unordered_set<Point> visited;

int dx[] = {-1, 1, 0, 0};
int dy[] = {0, 0, -1, 1};

void shortestPath(int startX, int startY, int endX, int endY, int n, int m) {
    dist.assign(n, vector<int>(m, INT_MAX));
    dist[startX][startY] = 0;
    queue<Point> q;
    q.push(Point(startX, startY));
    visited.insert(Point(startX, startY));

    while (!q.empty()) {
        Point current = q.front();
        q.pop();
        visited.erase(current);

        for (int i = 0; i < 4; ++i) {
            int nx = current.x + dx[i];
            int ny = current.y + dy[i];

            if (nx >= 0 && nx < n && ny >= 0 && ny < m && grid[nx][ny] != -1) {
                if (dist[nx][ny] > dist[current.x][current.y] + 1) {
                    dist[nx][ny] = dist[current.x][current.y] + 1;
                    if (visited.find(Point(nx, ny)) == visited.end()) {
                        if (visited.size() < 500) {
                            visited.insert(Point(nx, ny));
                            q.push(Point(nx, ny));
                        } else {
                            visited.clear();
                            visited.insert(Point(nx, ny));
                            q.push(Point(nx, ny));
                        }
                    }
                }
            }
        }
    }
}

int main() {
    int n, m;
    cin >> n >> m;
    grid.assign(n, vector<int>(m));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            cin >> grid[i][j];
        }
    }

    int startX, startY, endX, endY;
    cin >> startX >> startY >> endX >> endY;

    shortestPath(startX, startY, endX, endY, n, m);

    if (dist[endX][endY] == INT_MAX) {
        cout << "No path found" << endl;
    } else {
        cout << "Shortest path length: " << dist[endX][endY] << endl;
    }

    return 0;
}
