import java.util.ArrayList;
import java.util.Iterator;

public class FileMetadataCache {
    private final ArrayList<FileObject> cache;
    private static final int MAX_CAPACITY = 1000;

    public FileMetadataCache() {
        this.cache = new ArrayList<>(MAX_CAPACITY);
    }

    public static class FileObject {
        private final String filename;
        private final long lastModified;
        private final long fileSize;

        public FileObject(String filename, long lastModified, long fileSize) {
            this.filename = filename;
            this.lastModified = lastModified;
            this.fileSize = fileSize;
        }

        public String getFilename() {
            return filename;
        }

        public long getLastModified() {
            return lastModified;
        }

        public long getFileSize() {
            return fileSize;
        }
    }

    public boolean addFile(String filename, long lastModified, long fileSize) {
        if (cache.size() >= MAX_CAPACITY) {
            return false;
        }
        cache.add(new FileObject(filename, lastModified, fileSize));
        return true;
    }

    public FileObject getFileMetadata(String filename) {
        for (FileObject file : cache) {
            if (file.getFilename().equals(filename)) {
                return file;
            }
        }
        return null;
    }

    public boolean removeFile(FileObject file) {
        Iterator<FileObject> iterator = cache.iterator();
        while (iterator.hasNext()) {
            FileObject current = iterator.next();
            if (current.getFilename().equals(file.getFilename()) &&
                current.getLastModified() == file.getLastModified() &&
                current.getFileSize() == file.getFileSize()) {
                iterator.remove();
                return true;
            }
        }
        return false;
    }
}
