package main

import (
	"errors"
	"log"
	"os"
	"sync"

	"github.com/gammazero/deque"
)

const (
	maxBufferSize = 1000
)

type Buffer struct {
	data  deque.Deque[float64]
	mutex sync.Mutex
	size  int
}

func NewBuffer(size int) *Buffer {
	if size > maxBufferSize {
		size = maxBufferSize
	}
	return &Buffer{
		size: size,
	}
}

func (b *Buffer) Add(temp float64) error {
	b.mutex.Lock()
	defer b.mutex.Unlock()

	if b.data.Len() >= b.size {
		return errors.New("buffer overflow")
	}
	b.data.PushBack(temp)
	return nil
}

func (b *Buffer) MovingAverage(window int) (float64, error) {
	b.mutex.Lock()
	defer b.mutex.Unlock()

	if b.data.Len() == 0 {
		return 0, errors.New("empty buffer")
	}
	if window > b.data.Len() {
		window = b.data.Len()
	}

	sum := 0.0
	for i := 0; i < window; i++ {
		sum += b.data.At(i)
	}
	return sum / float64(window), nil
}

func main() {
	logger := log.New(os.Stdout, "TEMPERATURE_PROCESSOR: ", log.Ldate|log.Ltime|log.Lshortfile)
	logger.SetOutput(os.Stdout)

	buffer := NewBuffer(maxBufferSize)

	// Example: Simulate adding temperature data
	temps := []float64{20.5, 21.0, 22.3, 23.7, 24.1}
	for _, temp := range temps {
		if err := buffer.Add(temp); err != nil {
			logger.Printf("ERROR: %v\n", err)
		} else {
			logger.Printf("INFO: Added temperature %.2f\n", temp)
		}
	}

	avg, err := buffer.MovingAverage(3)
	if err != nil {
		logger.Printf("ERROR: %v\n", err)
	} else {
		logger.Printf("INFO: Moving average %.2f\n", avg)
	}
}
