	b.mutex.Lock()
	defer b.mutex.Unlock()

	if b.data.Len() == 0 {
		return 0, errors.New("buffer empty")
	}
	return b.data.PopFront(), nil
}

func (b *Buffer) Len() int {
	b.mutex.Lock()
	defer b.mutex.Unlock()
	return b.data.Len()
}

func main() {
	const bufferSize = 1000
	buffer := NewBuffer(bufferSize)
	logger := log.Default()

	// Example: Process a stream of temperature data
	temperatures := []float64{20.5, 21.0, 22.3, 23.7, 24.1}

	for _, temp := range temperatures {
		if err := buffer.Push(temp); err != nil {
			logger.Printf("Error pushing temperature: %v", err)
			continue
		}
		logger.Printf("Pushed temperature: %.2f", temp)
	}

	var sum float64
	count := buffer.Len()
	if count == 0 {
		logger.Println("No data to compute moving average")
		return
	}

	for i := 0; i < count; i++ {
