package main

import (
	"errors"
	"log"
	"os"
)

type Buffer struct {
	data  []float64
	size  int
	max   int
	count int
}

func NewBuffer(max int) *Buffer {
	return &Buffer{
		data: make([]float64, 0, max),
		max:  max,
	}
}

func (b *Buffer) Push(value float64) error {
	if b.count >= b.max {
		b.Pop()
	}
	b.data = append(b.data, value)
	b.count++
	b.size = len(b.data)
	return nil
}

func (b *Buffer) Pop() (float64, error) {
	if b.size == 0 {
		return 0, errors.New("buffer is empty")
	}
	value := b.data[0]
	b.data = b.data[1:]
	b.count--
	b.size = len(b.data)
	return value, nil
}

func (b *Buffer) MovingAverage(window int) (float64, error) {
	if b.size < window || window <= 0 {
		return 0, errors.New("invalid window size or insufficient data")
	}

	sum := 0.0
	for i := 0; i < window; i++ {
		sum += b.data[i]
	}
	return sum / float64(window), nil
}

func main() {
	logger := log.New(os.Stdout, "TEMPERATURE_PROCESSOR: ", log.LstdFlags|log.Lshortfile)
	buffer := NewBuffer(20)

	for i := 0; i < 1000; i++ {
		temp := float64(i) // Simulate temperature data
		err := buffer.Push(temp)
		if err != nil {
			logger.Printf("ERROR: %v", err)
			continue
		}

		if buffer.size >= 18 {
			logger.Printf("WARNING: Buffer approaching capacity (%d/20)", buffer.size)
		}

		if buffer.size >= 5 { // Example: Compute moving average over last 5 entries
			avg, err := buffer.MovingAverage(5)
			if err != nil {
