var cache sync.Map

func fibonacci(n int) int {
	if n <= 1 {
		return n
	}

	if val, ok := cache.Load(n); ok {
		return val.(int)
	}

	val := fibonacci(n-1) + fibonacci(n-2)
	cache.Store(n, val)
	return val
}

func main() {
	for i := 0; i <= 1000; i++ {
		fmt.Printf("Fibonacci(%d) = %d\n", i, fibonacci(i))
