package main

import (
	"sync"
)

var (
	cache sync.Map
	size  int
	mu    sync.Mutex
)

func fibonacci(n int) int {
	if n <= 1 {
		return n
	}

	key := n
	if val, ok := cache.Load(key); ok {
		return val.(int)
	}

	mu.Lock()
	defer mu.Unlock()

	if size >= 500 {
		var oldestKey interface{}
		cache.Range(func(key, _ interface{}) bool {
			oldestKey = key
			return false
		})
		cache.Delete(oldestKey)
		size--
	}

	val := fibonacci(n-1) + fibonacci(n-2)
	cache.Store(key, val)
	size++

	return val
}

func main() {
	for i := 0; i <= 1000; i++ {
		fibonacci(i)
	}
}
