	memoSize int
	sizeLock sync.Mutex
)

func fibonacci(n int) int {
	if n <= 1 {
		return n
	}

	// Check if value is already memoized
	if val, ok := memo.Load(n); ok {
		return val.(int)
	}

	// Calculate Fibonacci number recursively
	result := fibonacci(n-1) + fibonacci(n-2)

	// Store the result if within the 500-entry limit
	sizeLock.Lock()
	if memoSize < 500 {
		memo.LoadOrStore(n, result)
		memoSize++
	}
	sizeLock.Unlock()

	return result
}

func main() {
	// Pre-populate base cases
	memo.Store(0, 0)
	memo.Store(1, 1)
	memoSize = 2

	// Example usage: calculate Fibonacci numbers up to 1000
