#include <vector>
#include <queue>
using namespace std;

struct Element {
    int value;
    int arrayIndex;
    int elementIndex;

    Element(int val, int arrIdx, int elemIdx) : value(val), arrayIndex(arrIdx), elementIndex(elemIdx) {}
};

struct Compare {
    bool operator()(const Element& a, const Element& b) {
        return a.value > b.value;
    }
};

vector<int> mergeSortedArrays(const vector<vector<int>>& arrays) {
    priority_queue<Element, vector<Element>, Compare> minHeap;
    vector<int> result;

    // Push the first element of each array into the min heap
    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.push(Element(arrays[i][0], i, 0));
        }
    }

    while (!minHeap.empty()) {
        Element current = minHeap.top();
        minHeap.pop();
        result.push_back(current.value);

        int nextElementIndex = current.elementIndex + 1;
        if (nextElementIndex < arrays[current.arrayIndex].size()) {
            minHeap.push(Element(arrays[current.arrayIndex][nextElementIndex], current.arrayIndex, nextElementIndex));
        }
    }

    return result;
}
