import java.util.PriorityQueue;
import java.util.Comparator;

public class TaskProcessor {
    private PriorityQueue<Task> taskQueue;
    private int maxTasks = 100;

    public TaskProcessor() {
        taskQueue = new PriorityQueue<>(new Comparator<Task>() {
            @Override
            public int compare(Task t1, Task t2) {
                return Integer.compare(t2.getPriority(), t1.getPriority());
            }
        });
    }

    public void add(Task task) throws IllegalStateException {
        if (taskQueue.size() >= maxTasks) {
            throw new IllegalStateException("Queue is full. Maximum capacity is " + maxTasks);
        }
        taskQueue.add(task);
    }

    public Task poll() throws IllegalStateException {
        if (taskQueue.isEmpty()) {
            throw new IllegalStateException("Queue is empty.");
        }
        return taskQueue.poll();
    }

    public Task peek() throws IllegalStateException {
        if (taskQueue.isEmpty()) {
            throw new IllegalStateException("Queue is empty.");
        }
        return taskQueue.peek();
    }

    public void clear() {
        taskQueue.clear();
    }

    public long executeAllTasks() throws IllegalStateException {
        if (taskQueue.isEmpty()) {
            throw new IllegalStateException("Queue is empty.");
        }
        long totalTime = 0;
        while (!taskQueue.isEmpty()) {
            Task task = taskQueue.poll();
            try {
                Thread.sleep(task.getDuration());
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                throw new IllegalStateException("Task execution interrupted.");
            }
            totalTime += task.getDuration();
        }
        return totalTime;
    }

    public static class Task {
        private int priority;
        private long duration;

        public Task(int priority, long duration) {
            this.priority = priority;
            this.duration = duration;
        }

        public int getPriority() {
            return priority;
        }

        public long getDuration() {
            return duration;
        }
    }
}
