func maxSubArraySum(nums [100]int, size int) int {
	maxSoFar := math.MinInt32
	maxEndingHere := 0

	for i := 0; i < size; i++ {
		maxEndingHere += nums[i]
		if maxSoFar < maxEndingHere {
			maxSoFar = maxEndingHere
		}
		if maxEndingHere < 0 {
			maxEndingHere = 0
		}
	}
	return maxSoFar
}

func main() {
	var nums [100]int
	nums = [100]int{-2, -3, 4, -1, -2, 1, 5, -3}
	size := 8

	result := maxSubArraySum(nums, size)
	fmt.Println("Maximum contiguous sum is", result)
