#include <stack>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

struct Product {
    string name;
    string genre;
    double price;
    int quantity;
};

class BookstoreCheckout {
private:
    map<string, Product> productCatalog;
    stack<string> productStack;
    const int MAX_STACK_SIZE = 150;
    const int MAX_MAP_SIZE = 500;

    void ensureStackLimit() {
        if (productStack.size() >= MAX_STACK_SIZE) {
            productStack.pop();
        }
    }

    void ensureMapLimit() {
        if (productCatalog.size() >= MAX_MAP_SIZE) {
            string oldestProduct = productStack.top();
            productCatalog.erase(oldestProduct);
            productStack.pop();
        }
    }

public:
    void addProduct(const string& id, const Product& product) {
        ensureMapLimit();
        productCatalog[id] = product;
        ensureStackLimit();
        productStack.push(id);
    }

    void removeProduct(const string& id) {
        if (productCatalog.find(id) != productCatalog.end()) {
            productCatalog.erase(id);
            stack<string> tempStack;
            while (!productStack.empty()) {
                string current = productStack.top();
                productStack.pop();
                if (current != id) {
                    tempStack.push(current);
                }
            }
            while (!tempStack.empty()) {
                productStack.push(tempStack.top());
                tempStack.pop();
            }
        }
    }

    double calculateTotal(const map<string, int>& cart, double itemDiscount = 0.0, double totalDiscount = 0.0) {
        double subtotal = 0.0;
        for (const auto& item : cart) {
            if (productCatalog.find(item.first) != productCatalog.end()) {
                double price = productCatalog[item.first].price * (1.0 - itemDiscount);
                subtotal += price * item.second;
            }
        }
        return subtotal * (1.0 - totalDiscount);
    }

    void sortCatalogByPrice() {
        vector<pair<string, Product>> sortedProducts(productCatalog.begin(), productCatalog.end());
        sort(sortedProducts.begin(), sortedProducts.end(),
            [](const pair<string, Product>& a, const pair<string, Product>& b) {
                return a.second.price < b.second.price;
            });
        productCatalog.clear();
        for (const auto& product : sortedProducts) {
            productCatalog[product.first] = product.second;
        }
    }

    void sortCatalogByGenre() {
        vector<pair<string, Product>> sortedProducts(productCatalog.begin(), productCatalog.end());
        sort(sortedProducts.begin(), sortedProducts.end(),
            [](const pair<string, Product>& a, const pair<string, Product>& b) {
                return a.second.genre < b.second.genre;
            });
        productCatalog.clear();
        for (const auto& product : sortedProducts) {
            productCatalog[product.first] = product.second;
        }
    }
};

int main() {
    BookstoreCheckout checkout;
    return 0;
}
