#include <vector>
#include <queue>
#include <sstream>
#include <algorithm>
#include <climits>

using namespace std;

struct Element {
    int value;
    int arrayIndex;
    int elementIndex;

    Element(int v, int a, int e) : value(v), arrayIndex(a), elementIndex(e) {}
};

struct Compare {
    bool operator()(const Element& a, const Element& b) {
        return a.value > b.value;
    }
};

vector<vector<int>> readArraysFromFile(const string& filename) {
    ifstream file(filename);
    vector<vector<int>> arrays;
    string line;

    while (getline(file, line)) {
        istringstream iss(line);
        vector<int> arr;
        int num;
        while (iss >> num) {
            arr.push_back(num);
        }
        if (!arr.empty()) {
            arrays.push_back(arr);
        }
    }

    return arrays;
}

vector<vector<int>> readArraysFromConsole() {
    vector<vector<int>> arrays;
    cout << "Enter arrays line by line (separate numbers by spaces, empty line to finish):" << endl;
    string line;

    while (getline(cin, line)) {
        if (line.empty()) break;
        istringstream iss(line);
        vector<int> arr;
        int num;
        while (iss >> num) {
            arr.push_back(num);
        }
        if (!arr.empty()) {
            arrays.push_back(arr);
        }
    }

    return arrays;
}

vector<int> mergeSortedArrays(const vector<vector<int>>& arrays) {
    priority_queue<Element, vector<Element>, Compare> minHeap;
    vector<int> mergedArray;
    int totalElements = 0;

    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.push(Element(arrays[i][0], i, 0));
            totalElements += arrays[i].size();
        }
    }

    if (totalElements > 1000) {
        cerr << "Error: Total elements exceed 1000." << endl;
        return {};
    }

    while (!minHeap.empty()) {
        Element current = minHeap.top();
        minHeap.pop();
        mergedArray.push_back(current.value);

        if (current.elementIndex + 1 < arrays[current.arrayIndex].size()) {
            minHeap.push(Element(arrays[current.arrayIndex][current.elementIndex + 1], 
                                current.arrayIndex, 
                                current.elementIndex + 1));
        }
    }

    return mergedArray;
}

void writeOutputToFile(const vector<int>& mergedArray, const string& filename) {
    ofstream file(filename);
    for (int num : mergedArray) {
        file << num << " ";
    }
    file << endl;
}

void printUsage() {
    cout << "Usage:" << endl;
    cout << "  ./merge_arrays -f <input_file> [-o <output_file>]" << endl;
    cout << "  ./merge_arrays -c (enter arrays via console)" << endl;
}

int main(int argc, char* argv[]) {
    vector<vector<int>> arrays;
    string inputFile, outputFile;
    bool useConsole = false;

    if (argc < 2) {
        printUsage();
        return 1;
    }

    for (int i = 1; i < argc; ++i) {
        string arg = argv[i];
        if (arg == "-f" && i + 1 < argc) {
            inputFile = argv[++i];
        } else if (arg == "-o" && i + 1 < argc) {
            outputFile = argv[++i];
        } else if (arg == "-c") {
            useConsole = true;
        }
    }

    if (useConsole) {
        arrays = readArraysFromConsole();
    } else if (!inputFile.empty()) {
        arrays = readArraysFromFile(inputFile);
    } else {
        printUsage();
        return 1;
    }

    if (arrays.size() > 10) {
        cerr << "Error: Cannot merge more than 10 arrays." << endl;
        return 1;
    }

    for (const auto& arr : arrays) {
        if (arr.size() > 200) {
            cerr << "Error: Array size exceeds 200 elements." << endl;
            return 1;
        }
    }

    vector<int> mergedArray = mergeSortedArrays(arrays);

    if (mergedArray.empty()) {
        return 1;
    }

    if (!outputFile.empty()) {
        writeOutputToFile(mergedArray, outputFile);
    } else {
        for (int num : mergedArray) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}
