#include <algorithm>
#include <stdexcept>

class Employee {
private:
    std::string name;
    int age;

public:
    Employee() : name(""), age(0) {}
    Employee(const std::string& name, int age) : name(name), age(age) {
        if (name.empty()) {
            throw std::invalid_argument("Name cannot be empty.");
        }
        if (age < 0) {
            throw std::invalid_argument("Age cannot be negative.");
        }
    }

    std::string getName() const { return name; }
    int getAge() const { return age; }

    void setName(const std::string& name) {
        if (name.empty()) {
            throw std::invalid_argument("Name cannot be empty.");
        }
        this->name = name;
    }

    void setAge(int age) {
        if (age < 0) {
            throw std::invalid_argument("Age cannot be negative.");
        }
        this->age = age;
    }
};

bool compareByAge(const Employee& a, const Employee& b) {
    return a.getAge() < b.getAge();
}

bool compareByName(const Employee& a, const Employee& b) {
    return a.getName() < b.getName();
}

void stableSortByAgeAndName(std::deque<Employee>& employees) {
    std::stable_sort(employees.begin(), employees.end(), compareByName);
    std::stable_sort(employees.begin(), employees.end(), compareByAge);
}

int main() {
    std::deque<Employee> employees;
    const int MAX_CAPACITY = 800;

    try {
        // Example usage
        employees.push_back(Employee("Alice", 30));
        employees.push_back(Employee("Bob", 25));
        employees.push_back(Employee("Charlie", 30));

        if (employees.size() > MAX_CAPACITY) {
            throw std::runtime_error("Deque capacity exceeded.");
        }

        stableSortByAgeAndName(employees);

        // Output sorted employees
        for (const auto& emp : employees) {
            std::cout << "Name: " << emp.getName() << ", Age: " << emp.getAge() << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
