    std::mutex mtx;
    static const size_t MAX_CAPACITY = 800;

public:
    void push_back(const Employee& emp) {
        std::lock_guard<std::mutex> lock(mtx);
        if (deque.size() >= MAX_CAPACITY) {
            throw std::runtime_error("Deque capacity exceeded");
        }
        deque.push_back(emp);
    }

    void pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (deque.empty()) {
            throw std::runtime_error("Deque is empty");
        }
        deque.pop_back();
    }

    void sortByAge() {
        std::lock_guard<std::mutex> lock(mtx);
        std::stable_sort(deque.begin(), deque.end(), 
            [](const Employee& a, const Employee& b) { return a.getAge() < b.getAge(); });
    }

    void sortByName() {
        std::lock_guard<std::mutex> lock(mtx);
        std::stable_sort(deque.begin(), deque.end(), 
            [](const Employee& a, const Employee& b) { return a.getName() < b.getName(); });
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mtx);
        return deque.size();
    }
};

int main() {
    ThreadSafeDeque empDeque;
    try {
        empDeque.push_back(Employee("Alice", 30));
        empDeque.push_back(Employee("Bob", 25));
        empDeque.push_back(Employee("Charlie", 35));

        empDeque.sortByAge();
        empDeque.sortByName();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }
    return 0;
}
