#include <memory>

class Employee {
private:
    std::string name;
    int age;

public:
    Employee(const std::string& name, int age) : name(name), age(age) {
        if (name.empty()) {
            throw std::invalid_argument("Name cannot be empty");
        }
        if (age < 0) {
            throw std::invalid_argument("Age cannot be negative");
        }
    }

    std::string getName() const { return name; }
    int getAge() const { return age; }
};

class ThreadSafeEmployeeDeque {
private:
    std::deque<Employee> employees;
    mutable std::mutex mtx;
    const size_t MAX_SIZE = 600;

    bool compareByAgeAndName(const Employee& a, const Employee& b) {
        if (a.getAge() == b.getAge()) {
            return a.getName() < b.getName();
        }
        return a.getAge() < b.getAge();
    }

public:
    void push_back(const Employee& emp) {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.size() >= MAX_SIZE) {
            throw std::runtime_error("Deque maximum size exceeded");
        }
        employees.push_back(emp);
    }

    void pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.empty()) {
            throw std::runtime_error("Deque is empty");
        }
        employees.pop_back();
    }

    void stableSort() {
        std::lock_guard<std::mutex> lock(mtx);
        std::stable_sort(employees.begin(), employees.end(),
            [this](const Employee& a, const Employee& b) {
                return compareByAgeAndName(a, b);
            });
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.empty();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.size();
    }
};
