use std::collections::HashMap;
use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::Path;

struct WordCounter {
    map: HashMap<String, u32>,
    size_limit: usize,
}

impl WordCounter {
    fn new(size_limit: usize) -> Self {
        WordCounter {
            map: HashMap::with_capacity(size_limit),
            size_limit,
        }
    }

    fn process_text(&mut self, text: &str) {
        let words = text.split_whitespace();
        for word in words {
            let normalized = word
                .chars()
                .filter(|c| c.is_alphabetic())
                .collect::<String>()
                .to_lowercase();

            if !normalized.is_empty() {
                if self.map.len() < self.size_limit || self.map.contains_key(&normalized) {
                    *self.map.entry(normalized).or_insert(0) += 1;
                }
            }
        }
    }

    fn get_most_frequent(&self, count: usize) -> Vec<(&String, &u32)> {
        let mut entries: Vec<_> = self.map.iter().collect();
        entries.sort_by(|a, b| b.1.cmp(a.1));
        entries.into_iter().take(count).collect()
    }
}

fn main() {
    let file_path = Path::new("input.txt");
    let file = File::open(file_path).expect("Unable to open file");
    let reader = BufReader::new(file);

    let mut word_counter = WordCounter::new(10_000);

    for line in reader.lines() {
        if let Ok(line) = line {
            word_counter.process_text(&line);
        }
    }

    let most_frequent = word_counter.get_most_frequent(10);
    for (word, count) in most_frequent {
        println!("{}: {}", word, count);
    }
}
