```rust
use std::collections::LinkedList;
use std::sync::{Arc, Mutex};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Clone)]
struct Message {
    id: u64,
    timestamp: u64,
    data: String,
}

#[derive(Debug)]
enum QueueError {
    Overflow,
    NotFound,
    Expired,
    InvalidOperation,
}

struct MessageQueue {
    messages: Arc<Mutex<LinkedList<Message>>>,
    max_size: usize,
    max_age_secs: u64,
}

impl MessageQueue {
    fn new(max_size: usize, max_age_secs: u64) -> Self {
        MessageQueue {
            messages: Arc::new(Mutex::new(LinkedList::new())),
            max_size,
            max_age_secs,
        }
    }

    fn push(&self, message: Message) -> Result<(), QueueError> {
        let mut messages = self.messages.lock().unwrap();
        if messages.len() >= self.max_size {
            return Err(QueueError::Overflow);
        }
        messages.push_front(message);
        self.cleanup();
        Ok(())
    }

    fn pop(&self) -> Result<Message, QueueError> {
        let mut messages = self.messages.lock().unwrap();
        self.cleanup();
        messages.pop_front().ok_or(QueueError::NotFound)
    }

    fn lookup(&self, id: u64) -> Result<Message, QueueError> {
        let messages = self.messages.lock().unwrap();
        for msg in messages.iter() {
            if msg.id == id {
                let now = SystemTime::now()
                    .duration_since(UNIX_EPOCH)
                    .unwrap()
                    .as_secs();
                if now - msg.timestamp > self.max_age_secs {
                    return Err(QueueError::Expired);
                }
                return Ok(msg.clone());
            }
        }
        Err(QueueError::NotFound)
    }

    fn cleanup(&self) {
        let mut messages = self.messages.lock().unwrap();
        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        messages.retain(|msg| now - msg.timestamp <= self.max_age_secs);
    }
}

fn main() {
    let queue = MessageQueue::new(500, 30);
    // Example usage:
    // queue.push(Message { id: 1, timestamp: SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs(), data: "test".to_string() }).unwrap();
    // let msg = queue.pop().unwrap();
    // let found = queue.lookup(1).unwrap();
}
