```rust
use std::collections::LinkedList;
use std::sync::{Arc, Mutex};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Clone)]
struct Message {
    id: u64,
    timestamp: u64,
    data: String,
}

struct MessageQueue {
    messages: Arc<Mutex<LinkedList<Message>>>,
    capacity: usize,
}

impl MessageQueue {
    fn new(capacity: usize) -> Self {
        MessageQueue {
            messages: Arc::new(Mutex::new(LinkedList::new())),
            capacity,
        }
    }

    fn push(&self, message: Message) -> Result<(), String> {
        let mut messages = self.messages.lock().unwrap();
        if messages.len() >= self.capacity {
            return Err("Queue overflow: maximum capacity reached".to_string());
        }
        messages.push_front(message);
        self.clean_old_messages();
        Ok(())
    }

    fn pop(&self) -> Option<Message> {
        let mut messages = self.messages.lock().unwrap();
        self.clean_old_messages();
        messages.pop_front()
    }

    fn get_by_id(&self, id: u64) -> Option<Message> {
        let mut messages = self.messages.lock().unwrap();
        self.clean_old_messages();
        messages.iter().find(|m| m.id == id).cloned()
    }

    fn clean_old_messages(&self) {
        let current_time = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        let mut messages = self.messages.lock().unwrap();
        messages.retain(|m| current_time - m.timestamp <= 30);
    }
}

fn main() {
    let queue = MessageQueue::new(500);
    let message = Message {
        id: 1,
        timestamp: SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs(),
        data: "Test message".to_string(),
    };
    queue.push(message.clone()).unwrap();
    println!("Pushed: {:?}", message);
    let popped = queue.pop();
    println!("Popped: {:?}", popped);
    let found = queue.get_by_id(1);
    println!("Found by ID: {:?}", found);
}
