#include <iostream>
#include <vector>
#include <algorithm>
#include <stdexcept>
#include <mutex>
#include <thread>

class CinemaReservationSystem {
private:
    std::vector<int> reservations;
    std::mutex mtx;
    const int MAX_RESERVATIONS = 10000;

public:
    bool reserveSeat(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (reservations.size() >= MAX_RESERVATIONS) {
            throw std::runtime_error("Overbooking not allowed. Maximum reservations reached.");
        }
        if (std::find(reservations.begin(), reservations.end(), seatNumber) != reservations.end()) {
            return false; // Seat already reserved
        }
        reservations.push_back(seatNumber);
        return true;
    }

    bool cancelReservation(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        auto it = std::find(reservations.begin(), reservations.end(), seatNumber);
        if (it != reservations.end()) {
            reservations.erase(it);
            return true;
        }
        return false; // Seat not found
    }

    bool isSeatAvailable(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        return std::find(reservations.begin(), reservations.end(), seatNumber) == reservations.end();
    }
};

int main() {
    CinemaReservationSystem cinema;

    // Example usage
    try {
        if (cinema.reserveSeat(101)) {
            std::cout << "Seat 101 reserved successfully." << std::endl;
        } else {
            std::cout << "Seat 101 is already reserved." << std::endl;
        }

        if (cinema.cancelReservation(101)) {
            std::cout << "Reservation for seat 101 canceled." << std::endl;
        } else {
            std::cout << "No reservation found for seat 101." << std::endl;
        }
    } catch (const std::runtime_error& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
