#include <iostream>
#include <vector>
#include <stdexcept>
#include <mutex>
#include <algorithm>

class CinemaReservationSystem {
private:
    std::vector<bool> seats;
    std::mutex mtx;
    const int MAX_SEATS = 10000;

public:
    CinemaReservationSystem() : seats(MAX_SEATS, false) {}

    bool reserveSeat(int seatNumber) {
        if (seatNumber < 0 || seatNumber >= MAX_SEATS) {
            throw std::out_of_range("Seat number out of range.");
        }

        std::lock_guard<std::mutex> lock(mtx);
        if (seats[seatNumber]) {
            return false; // Seat already reserved
        }
        seats[seatNumber] = true;
        return true;
    }

    bool cancelReservation(int seatNumber) {
        if (seatNumber < 0 || seatNumber >= MAX_SEATS) {
            throw std::out_of_range("Seat number out of range.");
        }

        std::lock_guard<std::mutex> lock(mtx);
        if (!seats[seatNumber]) {
            return false; // Seat not reserved
        }
        seats[seatNumber] = false;
        return true;
    }

    bool isSeatAvailable(int seatNumber) {
        if (seatNumber < 0 || seatNumber >= MAX_SEATS) {
            throw std::out_of_range("Seat number out of range.");
        }

        std::lock_guard<std::mutex> lock(mtx);
        return !seats[seatNumber];
    }

    int getAvailableSeatsCount() {
        std::lock_guard<std::mutex> lock(mtx);
        return std::count(seats.begin(), seats.end(), false);
    }
};

int main() {
    CinemaReservationSystem cinema;

    // Example usage
    try {
        if (cinema.reserveSeat(42)) {
            std::cout << "Seat 42 reserved successfully." << std::endl;
        } else {
            std::cout << "Seat 42 is already reserved." << std::endl;
        }

        if (cinema.cancelReservation(42)) {
            std::cout << "Reservation for seat 42 cancelled." << std::endl;
        } else {
            std::cout << "Seat 42 was not reserved." << std::endl;
        }

        std::cout << "Available seats: " << cinema.getAvailableSeatsCount() << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
