using namespace std;

struct Reservation {
    string customerName;
    int seatNumber;
    string movieTitle;
};

class CinemaReservationSystem {
private:
    stack<Reservation> bookings;
    const int MAX_CAPACITY = 10000;

public:
    void makeReservation(const string& name, int seat, const string& movie) {
        if (bookings.size() >= MAX_CAPACITY) {
            throw overflow_error("Cannot make reservation: Stack capacity exceeded.");
        }
        bookings.push({name, seat, movie});
        cout << "Reservation made for " << name << " (Seat: " << seat << ", Movie: " << movie << ")" << endl;
    }

    void cancelReservation() {
        if (bookings.empty()) {
            throw underflow_error("Cannot cancel: No reservations to cancel.");
        }
        Reservation cancelled = bookings.top();
        bookings.pop();
        cout << "Cancelled reservation for " << cancelled.customerName 
             << " (Seat: " << cancelled.seatNumber << ", Movie: " << cancelled.movieTitle << ")" << endl;
    }

    int getCurrentReservationCount() const {
        return bookings.size();
    }
};

int main() {
    CinemaReservationSystem cinema;

    try {
        cinema.makeReservation("Alice", 42, "Inception");
        cinema.makeReservation("Bob", 15, "The Matrix");
        cinema.makeReservation("Charlie", 7, "Interstellar");

        cout << "Current reservations: " << cinema.getCurrentReservationCount() << endl;

        cinema.cancelReservation();
        cinema.cancelReservation();

        cout << "Current reservations: " << cinema.getCurrentReservationCount() << endl;

