from datetime import datetime

class TaskManager:
    def __init__(self):
        self.tasks = []
        self.max_tasks = 50

    def add_task(self, task, deadline):
        if len(self.tasks) >= self.max_tasks:
            print("Task limit reached. Cannot add more tasks.")
            return
        deadline_dt = datetime.strptime(deadline, "%Y-%m-%d %H:%M")
        heapq.heappush(self.tasks, (deadline_dt, task))

    def update_task(self, old_task, old_deadline, new_task, new_deadline):
        old_deadline_dt = datetime.strptime(old_deadline, "%Y-%m-%d %H:%M")
        new_deadline_dt = datetime.strptime(new_deadline, "%Y-%m-%d %H:%M")

        if (old_deadline_dt, old_task) in self.tasks:
            idx = self.tasks.index((old_deadline_dt, old_task))
            self.tasks[idx] = (new_deadline_dt, new_task)
            heapq.heapreplace(self.tasks, self.tasks[idx])
        else:
            print("Task not found.")

    def delete_task(self):
        if self.tasks:
            return heapq.heappop(self.tasks)
        else:
            print("No tasks to delete.")
            return None

    def get_next_task(self):
        return self.tasks[0] if self.tasks else None
