import heapq
from datetime import datetime, timedelta

class TaskManager:
    def __init__(self):
        self.task_queue = []
        self.capacity = 50

    def add_task(self, task_name, deadline):
        if len(self.task_queue) < self.capacity:
            heapq.heappush(self.task_queue, (deadline, task_name))
        else:
            # Replace the task with the farthest deadline if the new task's deadline is sooner
            farthest_deadline_task = self.task_queue[0]
            if deadline < farthest_deadline_task[0]:
                heapq.heapreplace(self.task_queue, (deadline, task_name))

    def get_next_task(self):
        if self.task_queue:
            return heapq.heappop(self.task_queue)
        return None

    def current_queue_size(self):
        return len(self.task_queue)

# Example usage
if __name__ == "__main__":
    manager = TaskManager()

    # Add tasks (example)
    for i in range(1, 60):
        deadline = datetime.now() + timedelta(days=i)
        manager.add_task(f"Task {i}", deadline)

    # Get next task
    next_task = manager.get_next_task()
    print(f"Next task: {next_task[1]} with deadline {next_task[0]}")

    # Current queue size (should be 49 after popping one)
    print(f"Current queue size: {manager.current_queue_size()}")
