import java.util.TreeSet;
import java.util.logging.Logger;

class Task implements Comparable<Task> {
    private final int id;
    private final int priority;

    public Task(int id, int priority) {
        this.id = id;
        this.priority = priority;
    }

    public int getId() {
        return id;
    }

    public int getPriority() {
        return priority;
    }

    @Override
    public int compareTo(Task other) {
        if (this.priority != other.priority) {
            return Integer.compare(this.priority, other.priority);
        } else {
            return Integer.compare(this.id, other.id);
        }
    }

    @Override
    public String toString() {
        return "Task{id=" + id + ", priority=" + priority + "}";
    }
}

public class TaskScheduler {
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());
    private static final int MAX_TASKS = 200;
    private final TreeSet<Task> tasks = new TreeSet<>();

    public void addTask(int id, int priority) throws IllegalStateException {
        if (tasks.size() >= MAX_TASKS) {
            logger.severe("Failed to add task: TreeSet is at full capacity (200 tasks)");
            throw new IllegalStateException("TreeSet is at full capacity");
        }
        Task task = new Task(id, priority);
        tasks.add(task);
        logger.info("Added task: " + task);
    }

    public void removeTask(int id, int priority) {
        Task task = new Task(id, priority);
        if (tasks.remove(task)) {
            logger.info("Removed task: " + task);
        } else {
            logger.warning("Task not found: " + task);
        }
    }

    public Task pollFirst() throws IllegalStateException {
        if (tasks.isEmpty()) {
            logger.severe("Failed to poll first task: TreeSet is empty");
            throw new IllegalStateException("TreeSet is empty");
        }
        Task task = tasks.pollFirst();
        logger.info("Polled first task: " + task);
        return task;
    }
}
