public class TaskScheduler {
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());
    private static final int MAX_TASKS = 200;
    private static final int MIN_TASKS = 150;
    private final TreeSet<Task> tasks = new TreeSet<>();

    public synchronized void addTask(Task task) throws IllegalStateException {
        if (tasks.size() >= MAX_TASKS) {
            logger.severe("Attempted to add task " + task.getId() + " but TreeSet is at full capacity.");
            throw new IllegalStateException("Cannot add task: TreeSet is at full capacity (max " + MAX_TASKS + " tasks).");
        }
        tasks.add(task);
        logger.info("Added task: " + task.getId() + " with priority " + task.getPriority());
    }

    public synchronized void removeTask(Task task) throws IllegalStateException {
        if (tasks.size() <= MIN_TASKS) {
            logger.severe("Attempted to remove task " + task.getId() + " but TreeSet is below minimum capacity.");
            throw new IllegalStateException("Cannot remove task: TreeSet is below minimum capacity (min " + MIN_TASKS + " tasks).");
        }
        if (!tasks.contains(task)) {
            logger.warning("Attempted to remove non-existent task: " + task.getId());
            throw new IllegalArgumentException("Task not found in TreeSet.");
        }
        tasks.remove(task);
        logger.info("Removed task: " + task.getId());
    }

    public synchronized Task pollFirstTask() throws IllegalStateException {
        if (tasks.isEmpty()) {
            logger.severe("Attempted to poll task from an empty TreeSet.");
            throw new IllegalStateException("Cannot poll task: TreeSet is empty.");
        }
        Task task = tasks.pollFirst();
        logger.info("Polled first task: " + task.getId() + " with priority " + task.getPriority());
        return task;
    }

    public synchronized int getTaskCount() {
        return tasks.size();
    }
}
