    private static final int MIN_TASKS = 150;
    private static final int MAX_TASKS = 200;
    private final TreeSet<Task> tasks;

    public TaskScheduler() {
        this.tasks = new TreeSet<>();
    }

    public void addTask(Task task) throws IllegalStateException {
        if (tasks.size() >= MAX_TASKS) {
            logger.severe("Cannot add task: TreeSet is at full capacity (200 tasks).");
            throw new IllegalStateException("TreeSet is at full capacity (200 tasks).");
        }
        tasks.add(task);
        logger.info("Added task: ID=" + task.getId() + ", Priority=" + task.getPriority());
    }

    public void removeTask(Task task) throws IllegalStateException {
        if (tasks.size() <= MIN_TASKS) {
            logger.severe("Cannot remove task: TreeSet would drop below minimum capacity (150 tasks).");
            throw new IllegalStateException("TreeSet would drop below minimum capacity (150 tasks).");
        }
        if (!tasks.contains(task)) {
            logger.severe("Cannot remove task: Task not found.");
            throw new IllegalStateException("Task not found.");
        }
        tasks.remove(task);
        logger.info("Removed task: ID=" + task.getId() + ", Priority=" + task.getPriority());
    }

    public Task pollFirst() throws IllegalStateException {
        if (tasks.isEmpty()) {
            logger.severe("Cannot poll task: TreeSet is empty.");
            throw new IllegalStateException("TreeSet is empty.");
        }
        Task task = tasks.pollFirst();
        logger.info("Polled first task: ID=" + task.getId() + ", Priority=" + task.getPriority());
        return task;
    }

    public static class Task implements Comparable<Task> {
        private final String id;
        private final int priority;

        public Task(String id, int priority) {
            this.id = id;
            this.priority = priority;
        }

        public String getId() {
            return id;
        }

        public int getPriority() {
            return priority;
        }

        @Override
        public int compareTo(Task other) {
            return Integer.compare(this.priority, other.priority);
        }
    }
}
