#include <iostream>
#include <queue>
#include <stdexcept>
#include <string>

using namespace std;

class InventoryItem {
public:
    string name;
    int urgency; // Higher value means higher priority

    InventoryItem(string n, int u) : name(n), urgency(u) {}

    // Overload the < operator to prioritize higher urgency
    bool operator<(const InventoryItem& other) const {
        return urgency < other.urgency;
    }
};

class ElectronicStoreInventory {
private:
    priority_queue<InventoryItem> inventoryQueue;
    const int MAX_ITEMS = 500;

public:
    void addItem(const string& name, int urgency) {
        if (inventoryQueue.size() >= MAX_ITEMS) {
            throw runtime_error("Inventory is full (max 500 items).");
        }
        inventoryQueue.push(InventoryItem(name, urgency));
    }

    void removeItem() {
        if (inventoryQueue.empty()) {
            throw runtime_error("Inventory is empty. No items to remove.");
        }
        inventoryQueue.pop();
    }

    InventoryItem getTopItem() {
        if (inventoryQueue.empty()) {
            throw runtime_error("Inventory is empty. No items to retrieve.");
        }
        return inventoryQueue.top();
    }
};

int main() {
    ElectronicStoreInventory inventory;

    try {
        inventory.addItem("Laptop", 5);
        inventory.addItem("Smartphone", 3);
        inventory.addItem("Headphones", 7);

        InventoryItem topItem = inventory.getTopItem();
        cout << "Top item: " << topItem.name << " (Urgency: " << topItem.urgency << ")" << endl;

        inventory.removeItem();
        topItem = inventory.getTopItem();
        cout << "Top item after removal: " << topItem.name << " (Urgency: " << topItem.urgency << ")" << endl;

    } catch (const runtime_error& e) {
        cerr << "Error: " << e.what() << endl;
    }

    return 0;
}
