```cpp
#include <iostream>
#include <vector>
#include <stdexcept>
#include <algorithm>

class InventoryItem {
public:
    std::string name;
    int urgency; // Higher value means higher urgency

    InventoryItem(const std::string& name, int urgency) 
        : name(name), urgency(urgency) {}

    bool operator<(const InventoryItem& other) const {
        return urgency < other.urgency;
    }
};

class InventorySystem {
private:
    std::vector<InventoryItem> priorityQueue;
    static const int MAX_ITEMS = 500;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (priorityQueue[index] < priorityQueue[parent]) {
                break;
            }
            std::swap(priorityQueue[index], priorityQueue[parent]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int left, right, largest;
        while (true) {
            left = 2 * index + 1;
            right = 2 * index + 2;
            largest = index;

            if (left < priorityQueue.size() && priorityQueue[left] < priorityQueue[largest]) {
                largest = left;
            }
            if (right < priorityQueue.size() && priorityQueue[right] < priorityQueue[largest]) {
                largest = right;
            }

            if (largest == index) {
                break;
            }

            std::swap(priorityQueue[index], priorityQueue[largest]);
            index = largest;
        }
    }

public:
    void push(const InventoryItem& item) {
        if (priorityQueue.size() >= MAX_ITEMS) {
            throw std::runtime_error("Inventory limit reached (500 items).");
        }
        priorityQueue.push_back(item);
        heapifyUp(priorityQueue.size() - 1);
    }

    void pop() {
        if (priorityQueue.empty()) {
            throw std::runtime_error("Inventory is empty.");
        }
        priorityQueue[0] = priorityQueue.back();
        priorityQueue.pop_back();
        if (!priorityQueue.empty()) {
            heapifyDown(0);
        }
    }

    InventoryItem top() const {
        if (priorityQueue.empty()) {
            throw std::runtime_error("Inventory is empty.");
        }
        return priorityQueue[0];
    }

    bool empty() const {
        return priorityQueue.empty();
    }

    size_t size() const {
        return priorityQueue.size();
    }
};

int main() {
    InventorySystem inventory;

    try {
        inventory.push(InventoryItem("Laptop", 3));
        inventory.push(InventoryItem("Smartphone", 5));
        inventory.push(InventoryItem("Tablet", 2));

        std::cout << "Top item: " << inventory.top().name 
                  << " (Urgency: " << inventory.top().urgency << ")" << std::endl;

        inventory.pop();
        std::cout << "After pop, top item: " << inventory.top().name 
                  << " (Urgency: " << inventory.top().urgency << ")" << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
