package main

type Employee struct {
	ID       int
	Name     string
	Department string
}

func FilterEmployees(employees []Employee, excludeDept string) ([]Employee, error) {
	if len(employees) == 0 {
		return nil, nil
	}

	if len(employees) > 4500 {
		employees = employees[:4500]
	}

	filtered := make([]Employee, 0, len(employees))
	for _, emp := range employees {
		if emp.Department != excludeDept {
			filtered = append(filtered, emp)
		}
	}

	return filtered, nil
}
