```go
package main

import (
	"errors"
)

type Employee struct {
	ID         int
	Name       string
	Department string
}

func FilterEmployees(employees []Employee, excludeDept string) ([]Employee, error) {
	if len(employees) == 0 {
		return nil, errors.New("empty employee list")
	}

	if len(excludeDept) == 0 {
		return nil, errors.New("empty department to exclude")
	}

	stack := make([]Employee, 0, 4500)

	for _, emp := range employees {
		if emp.Department != excludeDept {
			if len(stack) >= 4500 {
				break
			}
			stack = append(stack, emp)
		}
	}

	return stack, nil
}
