use std::fmt;

#[derive(Debug, Clone)]
enum MediaType {
    Book(String, String, u32), // title, author, pages
    Movie(String, String, u32), // title, director, duration (minutes)
    Music(String, String, u32), // title, artist, duration (seconds)
}

impl fmt::Display for MediaType {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            MediaType::Book(title, author, pages) => write!(f, "Book: {} by {} ({} pages)", title, author, pages),
            MediaType::Movie(title, director, duration) => write!(f, "Movie: {} directed by {} ({} minutes)", title, director, duration),
            MediaType::Music(title, artist, duration) => write!(f, "Music: {} by {} ({} seconds)", title, artist, duration),
        }
    }
}

struct MediaLibrary {
    entries: Vec<MediaType>,
    max_entries: usize,
}

impl MediaLibrary {
    fn new(max_entries: usize) -> Self {
        MediaLibrary {
            entries: Vec::with_capacity(max_entries),
            max_entries,
        }
    }

    fn add_media(&mut self, media: MediaType) -> Result<(), String> {
        if self.entries.len() >= self.max_entries {
            return Err("Media library is full (max 1000 entries)".to_string());
        }
        self.entries.push(media);
        Ok(())
    }

    fn remove_media(&mut self) -> Option<MediaType> {
        self.entries.pop()
    }

    fn update_media(&mut self, index: usize, new_media: MediaType) -> Result<(), String> {
        if index >= self.entries.len() {
            return Err("Invalid index".to_string());
        }
        self.entries[index] = new_media;
        Ok(())
    }

    fn display_all(&self) {
        for (i, media) in self.entries.iter().enumerate() {
            println!("{}: {}", i, media);
        }
    }
}

fn main() {
    let mut library = MediaLibrary::new(1000);

    // Example usage
    let book = MediaType::Book("Rust Programming".to_string(), "John Doe".to_string(), 300);
    let movie = MediaType::Movie("Inception".to_string(), "Christopher Nolan".to_string(), 148);
    let music = MediaType::Music("Bohemian Rhapsody".to_string(), "Queen".to_string(), 354);

    library.add_media(book).unwrap();
    library.add_media(movie).unwrap();
    library.add_media(music).unwrap();

    library.display_all();

    if let Some(removed) = library.remove_media() {
        println!("Removed: {}", removed);
    }

    let updated_movie = MediaType::Movie("The Dark Knight".to_string(), "Christopher Nolan".to_string(), 152);
    library.update_media(0, updated_movie).unwrap();

    library.display_all();
}
