    title: String,
    media_type: MediaType,
}

struct MediaLibrary {
    entries: Vec<MediaEntry>,
    max_size: usize,
}

impl MediaLibrary {
    fn new(max_size: usize) -> Self {
        MediaLibrary {
            entries: Vec::new(),
            max_size,
        }
    }

    fn add_entry(&mut self, entry: MediaEntry) -> Result<(), String> {
        if self.entries.len() >= self.max_size {
            return Err("Library is full (max 1000 entries)".to_string());
        }
        self.entries.push(entry);
        Ok(())
    }

    fn update_entry(&mut self, index: usize, new_entry: MediaEntry) -> Result<(), String> {
        if index >= self.entries.len() {
            return Err("Index out of bounds".to_string());
        }
        self.entries[index] = new_entry;
        Ok(())
    }

    fn remove_entry(&mut self, index: usize) -> Result<MediaEntry, String> {
        if index >= self.entries.len() {
            return Err("Index out of bounds".to_string());
        }
        Ok(self.entries.remove(index))
    }

    fn find_by_title(&self, title: &str) -> Vec<&MediaEntry> {
        self.entries
            .iter()
            .filter(|entry| entry.title.to_lowercase() == title.to_lowercase())
            .collect()
    }

    fn find_by_type(&self, media_type: MediaType) -> Vec<&MediaEntry> {
        self.entries
            .iter()
            .filter(|entry| matches!(&entry.media_type, media_type))
            .collect()
    }
}

impl fmt::Display for MediaEntry {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{} ({:?})", self.title, self.media_type)
    }
}

fn main() {
    let mut library = MediaLibrary::new(1000);

    // Example usage
    let book = MediaEntry {
        title: "The Rust Programming Language".to_string(),
        media_type: MediaType::Book,
    };
    let movie = MediaEntry {
        title: "Inception".to_string(),
        media_type: MediaType::Movie,
    };
    let music = MediaEntry {
        title: "Thriller".to_string(),
        media_type: MediaType::Music,
    };

    library.add_entry(book).unwrap();
    library.add_entry(movie).unwrap();
    library.add_entry(music).unwrap();

    println!("Library entries: {:?}", library.entries);
}
