use std::fmt;

#[derive(Debug, Clone)]
enum MediaType {
    Book,
    Movie,
    Music,
}

#[derive(Debug, Clone)]
struct MediaEntry {
    id: u32,
    title: String,
    media_type: MediaType,
}

struct MediaLibrary {
    entries: Vec<MediaEntry>,
    max_capacity: usize,
}

impl MediaLibrary {
    fn new(max_capacity: usize) -> Self {
        MediaLibrary {
            entries: Vec::with_capacity(max_capacity),
            max_capacity,
        }
    }

    fn add_entry(&mut self, entry: MediaEntry) -> Result<(), String> {
        if self.entries.len() >= self.max_capacity {
            return Err("Library is at maximum capacity".to_string());
        }

        match entry.media_type {
            MediaType::Book | MediaType::Movie | MediaType::Music => {
                self.entries.push(entry);
                Ok(())
            }
            _ => Err("Invalid media type".to_string()),
        }
    }

    fn update_entry(&mut self, id: u32, new_title: String) -> Result<(), String> {
        if let Some(index) = self.entries.iter().position(|e| e.id == id) {
            let mut entry = self.entries.pop().unwrap();
            if entry.id == id {
                entry.title = new_title;
                self.entries.push(entry);
                Ok(())
            } else {
                self.entries.push(entry);
                Err("Entry not found".to_string())
            }
        } else {
            Err("Entry not found".to_string())
        }
    }

    fn remove_entry(&mut self, id: u32) -> Result<(), String> {
        if let Some(index) = self.entries.iter().position(|e| e.id == id) {
            let mut temp_vec = Vec::with_capacity(self.max_capacity);
            while let Some(entry) = self.entries.pop() {
                if entry.id != id {
                    temp_vec.push(entry);
                }
            }
            while let Some(entry) = temp_vec.pop() {
                self.entries.push(entry);
            }
            Ok(())
        } else {
            Err("Entry not found".to_string())
        }
    }

    fn find_entry(&self, id: u32) -> Option<&MediaEntry> {
        self.entries.iter().find(|&e| e.id == id)
    }
}

impl fmt::Display for MediaType {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            MediaType::Book => write!(f, "Book"),
            MediaType::Movie => write!(f, "Movie"),
            MediaType::Music => write!(f, "Music"),
        }
    }
}

fn main() {
    let mut library = MediaLibrary::new(1000);

    let entry1 = MediaEntry {
        id: 1,
        title: "Rust Programming".to_string(),
        media_type: MediaType::Book,
    };

    let entry2 = MediaEntry {
        id: 2,
        title: "Inception".to_string(),
        media_type: MediaType::Movie,
    };

    library.add_entry(entry1.clone()).unwrap();
    library.add_entry(entry2.clone()).unwrap();

    println!("Entry 1: {:?}", library.find_entry(1));
    println!("Entry 2: {:?}", library.find_entry(2));

    library.update_entry(1, "Advanced Rust".to_string()).unwrap();
    println!("Updated Entry 1: {:?}", library.find_entry(1));

    library.remove_entry(2).unwrap();
    println!("Entry 2 after removal: {:?}", library.find_entry(2));
}
