import java.util.HashSet;

public class StudentRecordManager {
    private HashSet<Student> studentRecords;
    private static final int MAX_STUDENTS = 500;

    public StudentRecordManager() {
        this.studentRecords = new HashSet<>();
    }

    public void addStudent(Student student) throws IllegalStateException {
        if (studentRecords.size() >= MAX_STUDENTS) {
            throw new IllegalStateException("Cannot add student: Maximum capacity reached.");
        }
        if (student == null) {
            throw new IllegalArgumentException("Student cannot be null.");
        }
        studentRecords.add(student);
    }

    public void removeStudent(Student student) throws IllegalArgumentException {
        if (student == null) {
            throw new IllegalArgumentException("Student cannot be null.");
        }
        if (!studentRecords.contains(student)) {
            throw new IllegalArgumentException("Student not found in records.");
        }
        studentRecords.remove(student);
    }

    public boolean containsStudent(Student student) throws IllegalArgumentException {
        if (student == null) {
            throw new IllegalArgumentException("Student cannot be null.");
        }
        return studentRecords.contains(student);
    }

    public static class Student {
        private String studentId;
        private String name;
        private String grade;

        public Student(String studentId, String name, String grade) {
            this.studentId = studentId;
            this.name = name;
            this.grade = grade;
        }

        @Override
        public boolean equals(Object obj) {
            if (this == obj) return true;
            if (obj == null || getClass() != obj.getClass()) return false;
            Student student = (Student) obj;
            return studentId.equals(student.studentId);
        }

        @Override
        public int hashCode() {
            return studentId.hashCode();
        }
    }
}
