import collections
import sys

def process_log_file(log_file_path):
    ip_counter = collections.Counter()
    error_messages = []
    max_ips = 10000

    try:
        with open(log_file_path, 'r') as file:
            for line in file:
                try:
                    # Assuming log format: "IP_ADDRESS ... MESSAGE ..."
                    parts = line.strip().split()
                    if not parts:
                        continue
                    ip = parts[0]

                    # Check if the line is an error (simplified condition)
                    if "error" in line.lower():
                        error_messages.append(line.strip())

                    # Update IP counter if not exceeding max_ips
                    if len(ip_counter) < max_ips or ip in ip_counter:
                        ip_counter[ip] += 1

                except Exception as e:
                    error_messages.append(f"Error processing line: {line.strip()}. Exception: {str(e)}")

    except IOError as e:
        error_messages.append(f"IOError processing file: {str(e)}")
    except Exception as e:
        error_messages.append(f"Unexpected error: {str(e)}")

    return ip_counter, error_messages

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python script.py <log_file_path>")
        sys.exit(1)

    ip_counter, error_messages = process_log_file(sys.argv[1])
    print("IP Address Counts:")
    for ip, count in ip_counter.most_common():
        print(f"{ip}: {count}")

    print("\nError Messages:")
    for error in error_messages:
        print(error)
