import sys
from collections import Counter

def process_log_file(log_file_path):
    ip_counter = Counter()
    error_stack = []

    try:
        with open(log_file_path, 'r') as file:
            for line in file:
                try:
                    # Assuming log format: "IP_ADDRESS ERROR_MESSAGE" (simplified)
                    parts = line.strip().split(maxsplit=1)
                    if len(parts) >= 1:
                        ip = parts[0]
                        ip_counter[ip] += 1

                        # Limit IP counter to 10,000 unique IPs
                        if len(ip_counter) > 10000:
                            ip_counter.clear()
                            raise MemoryError("IP counter limit exceeded. Cleared to prevent memory overflow.")

                    if len(parts) >= 2 and parts[1].startswith("ERROR"):
                        error_message = parts[1]
                        # Push error message to stack (max 20)
                        if len(error_stack) >= 20:
                            error_stack.pop()
                        error_stack.append(error_message)

                except Exception as e:
                    # Push processing error to stack (max 20)
                    if len(error_stack) >= 20:
                        error_stack.pop()
                    error_stack.append(f"Line processing error: {str(e)}")

    except IOError as e:
        # Push IO error to stack (max 20)
        if len(error_stack) >= 20:
            error_stack.pop()
        error_stack.append(f"IO Error: {str(e)}")
        return ip_counter, error_stack
    except Exception as e:
        # Push general error to stack (max 20)
        if len(error_stack) >= 20:
            error_stack.pop()
        error_stack.append(f"Unexpected Error: {str(e)}")
        return ip_counter, error_stack

    return ip_counter, error_stack

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python script.py <log_file_path>")
        sys.exit(1)

    ip_counter, error_stack = process_log_file(sys.argv[1])

    print("Top IP Addresses:")
    for ip, count in ip_counter.most_common(10):  # Display top 10 for brevity
        print(f"{ip}: {count}")

    print("\nError Messages (Recent First):")
    while error_stack:
        print(error_stack.pop())
