use smallvec::SmallVec;
use std::cmp::Ordering;

#[derive(Debug, Clone)]
struct Task {
    id: u32,
    priority: u32,
    // Add other task fields as needed
}

impl PartialEq for Task {
    fn eq(&self, other: &Self) -> bool {
        self.priority == other.priority
    }
}

impl Eq for Task {}

impl PartialOrd for Task {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Task {
    fn cmp(&self, other: &Self) -> Ordering {
        self.priority.cmp(&other.priority).reverse()
    }
}

struct PriorityQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl PriorityQueue {
    fn new() -> Self {
        PriorityQueue {
            tasks: SmallVec::new(),
        }
    }

    fn push(&mut self, task: Task) -> Result<(), &'static str> {
        if self.tasks.len() >= 200 {
            return Err("Priority queue overflow");
        }
        self.tasks.push(task);
        self.tasks.sort();
        Ok(())
    }

    fn pop(&mut self) -> Option<Task> {
        if self.tasks.is_empty() {
            None
        } else {
            Some(self.tasks.pop().unwrap())
        }
    }

    fn update_priority(&mut self, id: u32, new_priority: u32) -> Result<(), &'static str> {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == id) {
            task.priority = new_priority;
            self.tasks.sort();
            Ok(())
        } else {
            Err("Task not found")
        }
    }
}
