use smallvec::{SmallVec, smallvec};

#[derive(Debug, Clone)]
struct Task {
    priority: u32,
    data: String,
}

struct PriorityQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl PriorityQueue {
    fn new() -> Self {
        PriorityQueue {
            tasks: smallvec![],
        }
    }

    fn push(&mut self, task: Task) -> Result<(), &'static str> {
        if self.tasks.len() >= 200 {
            return Err("Priority queue overflow: maximum capacity of 200 reached");
        }

        let mut insert_pos = 0;
        for (i, existing_task) in self.tasks.iter().enumerate() {
            if task.priority > existing_task.priority {
                insert_pos = i;
                break;
            }
            insert_pos = i + 1;
        }

        self.tasks.insert(insert_pos, task);
        Ok(())
    }

    fn pop(&mut self) -> Option<Task> {
        if self.tasks.is_empty() {
            None
        } else {
            Some(self.tasks.remove(0))
        }
    }

    fn update_priority(&mut self, index: usize, new_priority: u32) -> Result<(), &'static str> {
        if index >= self.tasks.len() {
            return Err("Index out of bounds");
        }

        let mut task = self.tasks.remove(index);
        task.priority = new_priority;
        self.push(task)?;
        Ok(())
    }
}
