use smallvec::{SmallVec, smallvec};
use std::cmp::Reverse;

#[derive(Debug, Clone)]
struct Task {
    id: u32,
    priority: u32,
    // Additional task fields can be added here
}

struct TaskQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl TaskQueue {
    fn new() -> Self {
        TaskQueue {
            tasks: SmallVec::with_capacity(200),
        }
    }

    fn push(&mut self, task: Task) -> Result<(), &'static str> {
        if self.tasks.len() >= 200 {
            return Err("Task queue is full (max 200 items)");
        }
        self.tasks.push(task);
        self.tasks.sort_by_key(|t| Reverse(t.priority));
        Ok(())
    }

    fn pop(&mut self) -> Option<Task> {
        if self.tasks.is_empty() {
            None
        } else {
            Some(self.tasks.remove(0))
        }
    }

    fn update_priority(&mut self, task_id: u32, new_priority: u32) -> Result<(), &'static str> {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == task_id) {
            task.priority = new_priority;
            self.tasks.sort_by_key(|t| Reverse(t.priority));
            Ok(())
        } else {
            Err("Task not found")
        }
    }

    fn remove(&mut self, task_id: u32) -> Result<(), &'static str> {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == task_id) {
            self.tasks.remove(pos);
            Ok(())
        } else {
            Err("Task not found")
        }
    }
}
