package main

import (
	"bufio"
	"os"
	"sync"
)

type LogCounter struct {
	mu    sync.Mutex
	count map[string]int
}

func NewLogCounter() *LogCounter {
	return &LogCounter{
		count: make(map[string]int),
	}
}

func (lc *LogCounter) Increment(entry string) {
	lc.mu.Lock()
	defer lc.mu.Unlock()

	if len(lc.count) >= 20000 {
		// Remove a random entry to maintain size limit
		for key := range lc.count {
			delete(lc.count, key)
			break
		}
	}

	lc.count[entry]++
}

func (lc *LogCounter) GetCount(entry string) int {
	lc.mu.Lock()
	defer lc.mu.Unlock()
	return lc.count[entry]
