import queue

def floyd_warshall(graph):
    nodes = sorted(graph.keys())
    n = len(nodes)
    node_index = {node: i for i, node in enumerate(nodes)}

    # Initialize distance matrix
    dist = [[float('inf')] * n for _ in range(n)]
    for i in range(n):
        dist[i][i] = 0
    for u in graph:
        for v, weight in graph[u].items():
            dist[node_index[u]][node_index[v]] = weight

    # Initialize queue for node pairs
    q = queue.Queue(maxsize=1000)

    # Enqueue all possible (i, j) pairs
    for i in range(n):
        for j in range(n):
            if q.full():
                break
            q.put((i, j))

    # Process pairs from the queue
    while not q.empty():
        i, j = q.get()
        for k in range(n):
            if dist[i][k] + dist[k][j] < dist[i][j]:
                dist[i][j] = dist[i][k] + dist[k][j]
                # Enqueue affected pairs
                if not q.full():
                    q.put((i, j))

    # Convert back to node identifiers
    result = {}
    for i in range(n):
        u = nodes[i]
        result[u] = {}
        for j in range(n):
            v = nodes[j]
            result[u][v] = dist[i][j]

    return result
