use arrayvec::ArrayVec;
use log::{info, warn};

type EmployeeData = (u32, Vec<f64>);

fn process_employee_scores(data: &mut ArrayVec<EmployeeData, 100>) -> Result<(), &'static str> {
    // Handle empty data
    if data.is_empty() {
        warn!("No employee data provided");
        return Ok(());
    }

    // Deduplicate and merge scores for same employee IDs
    let mut unique_data: ArrayVec<EmployeeData, 100> = ArrayVec::new();
    for (id, scores) in data.drain(..) {
        if let Some((_, existing_scores)) = unique_data.iter_mut().find(|(eid, _)| *eid == id) {
            existing_scores.extend(scores);
            info!("Merged scores for employee ID: {}", id);
        } else {
            if let Err(_) = unique_data.try_push((id, scores)) {
                return Err("ArrayVec overflow: Cannot store more than 100 employees");
            }
            info!("Added new employee ID: {}", id);
        }
    }

    // Calculate averages
    for (id, scores) in &unique_data {
        let avg: f64 = scores.iter().sum::<f64>() / scores.len() as f64;
        info!("Employee ID: {}, Average Score: {:.2}", id, avg);
    }

    // Restore processed data (optional)
    *data = unique_data;
    Ok(())
}

