type EmployeeTuple = (u32, f64);

struct EmployeeProcessor {
    data: ArrayVec<EmployeeTuple, 100>,
}

impl EmployeeProcessor {
    fn new() -> Self {
        EmployeeProcessor {
            data: ArrayVec::new(),
        }
    }

    fn insert(&mut self, tuple: EmployeeTuple) -> Result<(), &'static str> {
        if self.data.len() >= 100 {
            error!("Overflow error: Cannot insert more than 100 tuples");
            return Err("Overflow error: Maximum capacity reached");
        }

        if self.data.iter().any(|&(id, _)| id == tuple.0) {
            error!("Duplicate employee ID: {}", tuple.0);
            return Err("Duplicate employee ID");
        }

        info!("Inserting tuple: {:?}", tuple);
        self.data.push(tuple);
        Ok(())
    }

    fn get(&self, index: usize) -> Option<&EmployeeTuple> {
        self.data.get(index)
    }

    fn remove(&mut self, index: usize) -> Option<EmployeeTuple> {
        if index < self.data.len() {
            info!("Removing tuple at index: {}", index);
            Some(self.data.remove(index))
        } else {
            None
        }
    }

    fn calculate_averages(&self) -> HashMap<u32, f64> {
        let mut scores: HashMap<u32, Vec<f64>> = HashMap::new();

        for &(id, score) in self.data.iter() {
            scores.entry(id).or_default().push(score);
        }

        scores
            .into_iter()
            .map(|(id, scores)| {
                let avg = if scores.is_empty() {
                    0.0
                } else {
                    scores.iter().sum::<f64>() / scores.len() as f64
                };
                info!("Calculated average for employee {}: {:.2}", id, avg);
                (id, avg)
            })
            .collect()
    }
}

