#include <unordered_map>
#include <vector>
#include <algorithm>

int longestConsecutive(std::vector<int>& nums) {
    if (nums.empty()) return 0;

    std::unordered_map<int, bool> encountered;
    for (int num : nums) {
        encountered[num] = false;
    }

    int max_length = 1;

    for (int num : nums) {
        if (encountered[num]) continue;

        encountered[num] = true;
        int current_length = 1;

        int next = num + 1;
        while (encountered.find(next) != encountered.end()) {
            encountered[next] = true;
            current_length++;
            next++;
        }

        int prev = num - 1;
        while (encountered.find(prev) != encountered.end()) {
            encountered[prev] = true;
            current_length++;
            prev--;
        }

        max_length = std::max(max_length, current_length);
    }

    return max_length;
}
