            encountered[num] = true;
        }

        for (const auto& pair : encountered) {
            int current_num = pair.first;
            if (encountered.find(current_num - 1) == encountered.end()) {
                int current_length = 1;
                while (encountered.find(current_num + current_length) != encountered.end()) {
                    current_length++;
                }
                if (current_length > max_length) {
                    max_length = current_length;
                }
            }
        }

        return max_length;
    } catch (const std::exception& e) {
        throw std::runtime_error("Invalid input data type");
    }
}
