def manage_user_data():
    user_dict = {}

    def insert(uid, data):
        if len(user_dict) >= 1000:
            raise Exception("Maximum capacity of 1000 entries reached.")
        if uid in user_dict:
            raise Exception("Entry already exists. Use 'update' instead.")
        user_dict[uid] = data

    def update(uid, data):
        if uid not in user_dict:
            raise Exception("Entry not found. Use 'insert' instead.")
        user_dict[uid] = data

    def delete(uid):
        if uid not in user_dict:
            raise Exception("Entry not found.")
        del user_dict[uid]

    def fetch(uid):
        return user_dict.get(uid, None)

    operations = {
        'insert': insert,
        'update': update,
        'delete': delete,
        'fetch': fetch
    }

    def perform_operation(op, uid, data=None):
        if op not in operations:
            raise Exception("Invalid operation. Allowed: 'insert', 'update', 'delete', 'fetch'.")
        if op in ['insert', 'update']:
            return operations[op](uid, data)
        elif op == 'delete':
            return operations[op](uid)
        else:  # fetch
            return operations[op](uid)

    return perform_operation
