#include <iostream>
#include <unordered_set>

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* detectLoop(ListNode* head) {
    std::unordered_set<ListNode*> visited;
    ListNode* current = head;

    while (current != nullptr) {
        if (visited.find(current) != visited.end()) {
            return current; // Loop detected, return start node
        }
        visited.insert(current);
        current = current->next;
    }

    return nullptr; // No loop found
}

int main() {
    // Example usage
    ListNode* head = new ListNode(1);
    head->next = new ListNode(2);
    head->next->next = new ListNode(3);
    head->next->next->next = new ListNode(4);
    head->next->next->next->next = head->next; // Create a loop

    ListNode* loopStart = detectLoop(head);
    if (loopStart != nullptr) {
        std::cout << "Loop detected. Start node value: " << loopStart->val << std::endl;
    } else {
        std::cout << "No loop detected." << std::endl;
    }

    // Cleanup (optional, for completeness)
    // Note: This is simplified and may not handle all cases (e.g., loops)
    ListNode* current = head;
    std::unordered_set<ListNode*> toDelete;
    while (current != nullptr && toDelete.find(current) == toDelete.end()) {
        toDelete.insert(current);
        ListNode* temp = current;
        current = current->next;
        delete temp;
    }

    return 0;
}
