import java.util.ArrayList;

public class StockAnalyzer {
    private ArrayList<Double> prices;
    private static final int MAX_SIZE = 2000;

    public StockAnalyzer() {
        this.prices = new ArrayList<>();
    }

    public void addPrice(double price) {
        if (prices.size() < MAX_SIZE) {
            prices.add(price);
        } else {
            System.out.println("Cannot add more prices. Maximum capacity reached.");
        }
    }

    public void removePrice(int index) {
        if (index >= 0 && index < prices.size()) {
            prices.remove(index);
        } else {
            System.out.println("Invalid index. No price removed.");
        }
    }

    public double computeMaxProfit() {
        if (prices.size() < 2) {
            return 0.0;
        }

        double maxProfit = 0.0;
        double minPrice = prices.get(0);

        for (int i = 1; i < prices.size(); i++) {
            double currentPrice = prices.get(i);
            if (currentPrice > minPrice) {
                double profit = currentPrice - minPrice;
                if (profit > maxProfit) {
                    maxProfit = profit;
                }
            } else {
                minPrice = currentPrice;
            }
        }

        return maxProfit;
    }

    public static void main(String[] args) {
        StockAnalyzer analyzer = new StockAnalyzer();
        analyzer.addPrice(100.0);
        analyzer.addPrice(180.0);
        analyzer.addPrice(150.0);
        analyzer.addPrice(200.0);
        analyzer.addPrice(120.0);

        System.out.println("Maximum profit: " + analyzer.computeMaxProfit());
    }
}
