import java.util.Stack;

public class StockProfitAnalyzer {
    private Stack<Double> priceStack;
    private static final int MAX_SIZE = 500;

    public StockProfitAnalyzer() {
        priceStack = new Stack<>();
    }

    public void addPrice(double price) {
        if (priceStack.size() >= MAX_SIZE) {
            priceStack.pop();
        }
        priceStack.push(price);
    }

    public double computeMaxProfit() {
        if (priceStack.size() < 2) {
            return 0.0;
        }

        double maxProfit = 0.0;
        Stack<Double> tempStack = new Stack<>();
        tempStack.addAll(priceStack);

        while (!tempStack.isEmpty()) {
            double sellPrice = tempStack.pop();
            Stack<Double> buyStack = new Stack<>();
            buyStack.addAll(tempStack);

            while (!buyStack.isEmpty()) {
                double buyPrice = buyStack.pop();
                double profit = sellPrice - buyPrice;
                if (profit > maxProfit) {
                    maxProfit = profit;
                }
            }
        }

        return maxProfit;
    }

    public static void main(String[] args) {
        StockProfitAnalyzer analyzer = new StockProfitAnalyzer();

        // Example usage
        for (int i = 0; i < 500; i++) {
            analyzer.addPrice(Math.random() * 100);
        }

        System.out.println("Max profit: " + analyzer.computeMaxProfit());
    }
}
