use std::collections::BTreeMap;

struct MedianFinder {
    low: BTreeMap<i32, usize>,
    high: BTreeMap<i32, usize>,
    low_size: usize,
    high_size: usize,
}

impl MedianFinder {
    fn new() -> Self {
        MedianFinder {
            low: BTreeMap::new(),
            high: BTreeMap::new(),
            low_size: 0,
            high_size: 0,
        }
    }

    fn add_num(&mut self, num: i32) {
        if self.low_size == 0 || num <= *self.low.keys().next_back().unwrap() {
            *self.low.entry(num).or_insert(0) += 1;
            self.low_size += 1;
        } else {
            *self.high.entry(num).or_insert(0) += 1;
            self.high_size += 1;
        }

        self.balance();
    }

    fn balance(&mut self) {
        if self.low_size > self.high_size + 1 {
            let (&key, &count) = self.low.iter().next_back().unwrap();
            if count == 1 {
                self.low.remove(&key);
            } else {
                *self.low.get_mut(&key).unwrap() -= 1;
            }
            *self.high.entry(key).or_insert(0) += 1;
            self.low_size -= 1;
            self.high_size += 1;
        } else if self.high_size > self.low_size {
            let (&key, &count) = self.high.iter().next().unwrap();
            if count == 1 {
                self.high.remove(&key);
            } else {
                *self.high.get_mut(&key).unwrap() -= 1;
            }
            *self.low.entry(key).or_insert(0) += 1;
            self.high_size -= 1;
            self.low_size += 1;
        }
    }

    fn find_median(&self) -> f64 {
        if self.low_size == self.high_size {
            let low_max = *self.low.keys().next_back().unwrap() as f64;
            let high_min = *self.high.keys().next().unwrap() as f64;
            (low_max + high_min) / 2.0
        } else {
            *self.low.keys().next_back().unwrap() as f64
        }
    }
}

fn main() {
    let mut finder = MedianFinder::new();
    finder.add_num(1);
    finder.add_num(2);
    println!("Median: {}", finder.find_median());
    finder.add_num(3);
    println!("Median: {}", finder.find_median());
}
