use std::collections::BTreeMap;
use std::io;

struct MedianFinder {
    map: BTreeMap<i32, usize>,
    size: usize,
    max_size: usize,
}

impl MedianFinder {
    fn new(max_size: usize) -> Self {
        MedianFinder {
            map: BTreeMap::new(),
            size: 0,
            max_size,
        }
    }

    fn add(&mut self, num: i32) {
        *self.map.entry(num).or_insert(0) += 1;
        self.size += 1;

        if self.size > self.max_size {
            self.trim();
        }
    }

    fn trim(&mut self) {
        if let Some((&key, &count)) = self.map.iter().next() {
            if count == 1 {
                self.map.remove(&key);
            } else {
                self.map.insert(key, count - 1);
            }
            self.size -= 1;
        }
    }

    fn compute_median(&mut self) -> Option<f64> {
        if self.size == 0 {
            return None;
        }

        let mut count = 0;
        let mut prev_key = 0;
        let mut found = false;
        let target = (self.size + 1) / 2;

        for (&key, &val) in self.map.iter() {
            count += val;
            if count >= target {
                if self.size % 2 == 1 || count > target {
                    return Some(key as f64);
                } else {
                    return Some((prev_key + key) as f64 / 2.0);
                }
            }
            prev_key = key;
            found = true;
        }

        None
    }
}

fn main() {
    let mut median_finder = MedianFinder::new(2000);

    loop {
        println!("Enter an integer to add to the stream (or 'q' to quit):");
        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();

        if input.trim() == "q" {
            break;
        }

        if let Ok(num) = input.trim().parse::<i32>() {
            median_finder.add(num);
            if let Some(median) = median_finder.compute_median() {
                println!("Current median: {}", median);
            } else {
                println!("No median available.");
            }
        } else {
            println!("Invalid input. Please enter an integer or 'q' to quit.");
        }
    }
}
