use std::collections::BTreeMap;
use std::io;

struct MedianFinder {
    map: BTreeMap<i32, usize>,
    count: usize,
    max_size: usize,
}

impl MedianFinder {
    fn new(max_size: usize) -> Self {
        MedianFinder {
            map: BTreeMap::new(),
            count: 0,
            max_size,
        }
    }

    fn add_num(&mut self, num: i32) {
        if self.count >= self.max_size {
            return;
        }
        *self.map.entry(num).or_insert(0) += 1;
        self.count += 1;
    }

    fn find_median(&self) -> f64 {
        if self.count == 0 {
            return 0.0;
        }

        let mut sum = 0;
        let mut prev_key = 0;
        let mut found = false;

        for (&key, &val) in self.map.iter() {
            for _ in 0..val {
                sum += 1;
                if sum == (self.count + 1) / 2 {
                    if self.count % 2 == 1 {
                        return key as f64;
                    } else {
                        prev_key = key;
                        found = true;
                        break;
                    }
                } else if found && sum == (self.count / 2) + 1 {
                    return (prev_key + key) as f64 / 2.0;
                }
            }
            if found {
                break;
            }
        }
        0.0
    }
}

fn main() {
    let mut median_finder = MedianFinder::new(2000);
    let mut input = String::new();

    loop {
        println!("Enter an integer to add to the stream (or 'q' to quit, 'm' for median):");
        input.clear();
        io::stdin().read_line(&mut input).unwrap();
        let input = input.trim();

        if input == "q" {
            break;
        } else if input == "m" {
            println!("Current median: {}", median_finder.find_median());
        } else {
            match input.parse::<i32>() {
                Ok(num) => median_finder.add_num(num),
                Err(_) => println!("Invalid input. Please enter an integer, 'q', or 'm'."),
            }
        }
    }
}
