import threading
import queue
import time
import random

class LogProcessor:
    def __init__(self, max_threads=1000):
        self.log_queue = queue.Queue()
        self.max_threads = max_threads
        self.threads = []
        self.lock = threading.Lock()

    def process_log(self, log_message):
        with self.lock:
            print(f"Processing log: {log_message}")

    def worker(self):
        while True:
            log_message = self.log_queue.get()
            if log_message is None:
                break
            self.process_log(log_message)
            self.log_queue.task_done()

    def start(self):
        for _ in range(self.max_threads):
            thread = threading.Thread(target=self.worker)
            thread.start()
            self.threads.append(thread)

    def stop(self):
        for _ in range(self.max_threads):
            self.log_queue.put(None)
        for thread in self.threads:
            thread.join()

    def add_log(self, log_message):
        self.log_queue.put(log_message)

def test_log_processor():
    processor = LogProcessor(max_threads=1000)
    processor.start()

    for i in range(1000):
        processor.add_log(f"Log message {i}")

    processor.stop()

if __name__ == "__main__":
    test_log_processor()
