import threading
import queue
import time
import random

class LogProcessor:
    def __init__(self, max_queue_size=1500, max_threads=1000):
        self.log_queue = queue.Queue(maxsize=max_queue_size)
        self.max_threads = max_threads
        self.lock = threading.Lock()

    def enqueue_log(self, log_message):
        try:
            with self.lock:
                if not self.log_queue.full():
                    self.log_queue.put(log_message)
                    print(f"Enqueued: {log_message}")
                else:
                    print("Queue is full. Discarding log message.")
        except Exception as e:
            print(f"Error enqueuing log: {e}")

    def dequeue_and_process(self):
        try:
            with self.lock:
                if not self.log_queue.empty():
                    log_message = self.log_queue.get()
                    print(f"Processing: {log_message}")
                    # Simulate processing time
                    time.sleep(random.uniform(0.1, 0.5))
                    self.log_queue.task_done()
        except Exception as e:
            print(f"Error processing log: {e}")

    def worker(self):
        while True:
            self.dequeue_and_process()

    def start_workers(self):
        for _ in range(self.max_threads):
            thread = threading.Thread(target=self.worker, daemon=True)
            thread.start()

    def simulate_logs(self, num_logs=2000):
        for i in range(num_logs):
            self.enqueue_log(f"Log_{i}")
            time.sleep(random.uniform(0.01, 0.1))

if __name__ == "__main__":
    processor = LogProcessor()
    processor.start_workers()
    processor.simulate_logs()
    processor.log_queue.join()
