import threading
import queue
import time
import random

class LogProcessor:
    def __init__(self, max_queue_size=1500, max_concurrent_messages=1000):
        self.max_queue_size = max_queue_size
        self.max_concurrent_messages = max_concurrent_messages
        self.queue = queue.Queue(maxsize=max_queue_size)
        self.lock = threading.Lock()
        self.producer_threads = []
        self.consumer_threads = []

    def enqueue_message(self, message):
        with self.lock:
            if self.queue.qsize() < self.max_queue_size * 0.9:
                self.queue.put(message)
                print(f"Enqueued: {message}")
            else:
                print("Queue is near capacity. Skipping enqueue.")

    def dequeue_message(self):
        with self.lock:
            if not self.queue.empty():
                message = self.queue.get()
                print(f"Dequeued: {message}")
                return message
            else:
                print("Queue is empty. Nothing to dequeue.")
                return None

    def producer(self, num_messages):
        for i in range(num_messages):
            message = f"LogMessage_{i}"
            self.enqueue_message(message)
            time.sleep(random.uniform(0.001, 0.01))

    def consumer(self):
        while True:
            message = self.dequeue_message()
            if message is None:
                break
            time.sleep(random.uniform(0.001, 0.01))

    def start_processing(self, num_producers=5, num_consumers=5):
        for _ in range(num_producers):
            producer_thread = threading.Thread(target=self.producer, args=(200,))
            producer_thread.start()
            self.producer_threads.append(producer_thread)

        for _ in range(num_consumers):
            consumer_thread = threading.Thread(target=self.consumer)
            consumer_thread.start()
            self.consumer_threads.append(consumer_thread)

        for thread in self.producer_threads:
            thread.join()

        for thread in self.consumer_threads:
            thread.join()

if __name__ == "__main__":
    log_processor = LogProcessor()
    log_processor.start_processing()
