import heapq

class KthSmallestInStream:
    def __init__(self, k):
        self.k = k
        self.min_heap = []

    def insert(self, num):
        heapq.heappush(self.min_heap, -num)
        if len(self.min_heap) > self.k:
            heapq.heappop(self.min_heap)

    def get_kth_smallest(self):
        if len(self.min_heap) < self.k:
            return None
        return -self.min_heap[0]
