#include <algorithm>

using namespace std;

void generatePermutations(vector<int>& nums, vector<vector<int>>& result, int start) {
    if (start == nums.size()) {
        result.push_back(nums);
        if (result.size() >= 1500) {
            // Process or output permutations and clear to manage memory
            result.clear();
        }
        return;
    }
    for (int i = start; i < nums.size(); ++i) {
        if (i != start && nums[i] == nums[start]) continue; // Skip duplicates
        swap(nums[start], nums[i]);
        generatePermutations(nums, result, start + 1);
        swap(nums[start], nums[i]);
    }
}

vector<vector<int>> permuteUnique(vector<int>& nums) {
    vector<vector<int>> result;
    sort(nums.begin(), nums.end());
    generatePermutations(nums, result, 0);
    return result;
}

int main() {
    vector<int> nums = {1, 2, 2}; // Example input
    vector<vector<int>> permutations = permuteUnique(nums);

    // Output the permutations
    for (const auto& perm : permutations) {
        for (int num : perm) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
