#include <iostream>
#include <vector>
#include <stack>
#include <algorithm>

using namespace std;

void generatePermutations(vector<int>& nums, vector<vector<int>>& result) {
    stack<pair<vector<int>, vector<bool>>> stk;
    vector<int> current;
    vector<bool> used(nums.size(), false);
    stk.push({current, used});

    while (!stk.empty() && result.size() < 1500) {
        auto top = stk.top();
        stk.pop();
        current = top.first;
        used = top.second;

        if (current.size() == nums.size()) {
            if (find(result.begin(), result.end(), current) == result.end()) {
                result.push_back(current);
            }
            continue;
        }

        for (int i = 0; i < nums.size(); ++i) {
            if (!used[i]) {
                vector<int> newCurrent = current;
                newCurrent.push_back(nums[i]);
                vector<bool> newUsed = used;
                newUsed[i] = true;
                stk.push({newCurrent, newUsed});
            }
        }
    }
}

int main() {
    vector<int> nums;
    int num;
    cout << "Enter numbers (enter -1 to stop): ";
    while (cin >> num && num != -1) {
        nums.push_back(num);
    }

    vector<vector<int>> permutations;
    generatePermutations(nums, permutations);

    cout << "Unique permutations (max 1500):" << endl;
    for (const auto& perm : permutations) {
        for (int num : perm) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}
