void countUniqueWords(const std::string& input) {
    std::vector<std::string> words;
    std::map<std::string, int> wordCount;

    // Preprocess the string: normalize case and remove punctuation
    std::string processed;
    for (char c : input) {
        if (isalpha(c)) {
            processed += tolower(c);
        } else if (isspace(c)) {
            processed += ' ';
        }
    }

    // Split into words
    std::istringstream iss(processed);
    std::string word;
    while (iss >> word) {
        // Check if word is already in the vector
        bool found = false;
        for (const auto& w : words) {
            if (w == word) {
                found = true;
                break;
            }
        }

        if (!found && words.size() < 100) {
            words.push_back(word);
        }

        wordCount[word]++;
    }

    // Output results
    std::cout << "Total unique words: " << words.size() << std::endl;
    for (const auto& pair : wordCount) {
        std::cout << pair.first << ": " << pair.second << std::endl;
    }
}
