        if customer.arrival_time > current_time {
            current_time = customer.arrival_time;
        }
        let wait_time = current_time - customer.arrival_time;
        total_wait_time += wait_time;
        processed_customers += 1;
        current_time += customer.processing_time;
    }

    if processed_customers > 0 {
        let average_wait_time = total_wait_time as f32 / processed_customers as f32;
        println!("Average wait time: {}", average_wait_time);
    } else {
        println!("No customers processed.");
    }
