import java.util.Date;

public class EmergencyAlertSystem {
    private static final int MAX_ALERTS = 10;
    private PriorityQueue<Alert> alertQueue;

    public EmergencyAlertSystem() {
        alertQueue = new PriorityQueue<>(MAX_ALERTS, new Comparator<Alert>() {
            @Override
            public int compare(Alert a1, Alert a2) {
                return Integer.compare(a2.getSeverity(), a1.getSeverity());
            }
        });
    }

    public void processEmergencyAlerts() {
        while (!alertQueue.isEmpty()) {
            Alert alert = alertQueue.poll();
            System.out.println("Processing Alert - Severity: " + alert.getSeverity() + 
                               ", Timestamp: " + alert.getTimestamp());
        }
    }

    public boolean addAlert(int severity, Date timestamp) {
        if (alertQueue.size() >= MAX_ALERTS) {
            return false;
        }
        alertQueue.offer(new Alert(severity, timestamp));
        return true;
    }

    private static class Alert {
        private int severity;
        private Date timestamp;

        public Alert(int severity, Date timestamp) {
            this.severity = severity;
            this.timestamp = timestamp;
        }

        public int getSeverity() {
            return severity;
        }

        public Date getTimestamp() {
            return timestamp;
        }
    }
}
