#include <unordered_set>
#include <vector>

std::pair<std::unordered_set<int>, int> detectDuplicateErrors(const std::vector<int>& errorCodes) {
    std::unordered_set<int> uniqueCodes;
    std::unordered_set<int> duplicateCodes;
    int duplicateCount = 0;

    for (int code : errorCodes) {
        if (uniqueCodes.find(code) != uniqueCodes.end()) {
            if (duplicateCodes.find(code) == duplicateCodes.end()) {
                duplicateCodes.insert(code);
                duplicateCount++;
            }
        } else {
            uniqueCodes.insert(code);
        }
    }

    return {duplicateCodes, duplicateCount};
}
