            case "add":
                if (vipGuestList.size() < MAX_CAPACITY) {
                    vipGuestList.add(guestId);
                    return true;
                }
                return false;
            case "remove":
                return vipGuestList.remove(Integer.valueOf(guestId));
            case "contains":
                return vipGuestList.contains(guestId);
            default:
                return false;
        }
    }
