        return "Error: Maximum of 5 intervals allowed."

    if not intervals:
        return []

    intervals.sort()
    merged = [intervals[0]]

    for current in intervals[1:]:
        last = merged[-1]
        if current[0] <= last[1]:
            merged.pop()
            merged.append((last[0], max(last[1], current[1])))
        else:
            merged.append(current)

    return merged
