            queue.append((patient_id, severity))
            rearrange_priorities()
        else:
            print("Queue is full. Cannot add more patients.")

    def rearrange_priorities():
        queue_list = list(queue)
        queue_list.sort(key=lambda x: x[1], reverse=True)
        queue.clear()
        queue.extend(queue_list)

    def process_next_patient():
        if queue:
            return queue.popleft()
        else:
            print("Queue is empty.")
            return None

    def get_queue():
        return list(queue)

    return {
        'add_patient': add_patient,
        'process_next_patient': process_next_patient,
        'get_queue': get_queue,
        'rearrange_priorities': rearrange_priorities
    }
