    emergency_queue = deque(maxlen=10)

    def append(patient_id, severity_score):
        if len(emergency_queue) < emergency_queue.maxlen:
            emergency_queue.append((patient_id, severity_score))
            emergency_queue = deque(sorted(emergency_queue, key=lambda x: -x[1]), maxlen=10)
        else:
            raise Exception("Queue is full. Maximum capacity reached.")

    def pop():
        if emergency_queue:
            return emergency_queue.popleft()
        else:
            raise Exception("Queue is empty. No patients to process.")

    return append, pop
