use std::collections::LinkedList;

struct PlaybackQueue {
    tracks: LinkedList<String>,
    current_track: Option<String>,
}

impl PlaybackQueue {
    fn new() -> Self {
        PlaybackQueue {
            tracks: LinkedList::new(),
            current_track: None,
        }
    }

    fn add_track(&mut self, track: String) {
        self.tracks.push_back(track);
    }

    fn remove_track(&mut self, track: &str) -> bool {
        let mut found = false;
        let mut new_tracks = LinkedList::new();

        for t in self.tracks.iter() {
            if t != track {
                new_tracks.push_back(t.clone());
            } else {
                found = true;
            }
        }

        if found {
            self.tracks = new_tracks;
            if let Some(current) = &self.current_track {
                if current == track {
                    self.current_track = None;
                }
            }
        }

        found
    }

    fn next_track(&mut self) -> Option<String> {
        if self.tracks.is_empty() {
            self.current_track = None;
            return None;
        }

        if let Some(current) = &self.current_track {
            let mut iter = self.tracks.iter();
            let mut found = false;
            while let Some(track) = iter.next() {
                if track == current {
                    found = true;
                    break;
                }
            }

            if found {
                let mut new_tracks = LinkedList::new();
                let mut next_track = None;
                let mut skip = true;

                for track in self.tracks.iter() {
                    if skip {
                        if track == current {
                            skip = false;
                        }
                        new_tracks.push_back(track.clone());
                    } else {
                        next_track = Some(track.clone());
                        break;
                    }
                }

                if let Some(next) = next_track {
                    self.current_track = Some(next.clone());
                    Some(next)
                } else {
                    self.current_track = Some(self.tracks.front().unwrap().clone());
                    Some(self.tracks.front().unwrap().clone())
                }
            } else {
                self.current_track = Some(self.tracks.front().unwrap().clone());
                Some(self.tracks.front().unwrap().clone())
            }
        } else {
            self.current_track = Some(self.tracks.front().unwrap().clone());
            Some(self.tracks.front().unwrap().clone())
        }
    }

    fn previous_track(&mut self) -> Option<String> {
        if self.tracks.is_empty() {
            self.current_track = None;
            return None;
        }

        if let Some(current) = &self.current_track {
            let mut prev_track = None;
            let mut found = false;

            for track in self.tracks.iter() {
                if track == current {
                    found = true;
                    break;
                }
                prev_track = Some(track.clone());
            }

            if found {
                if let Some(prev) = prev_track {
                    self.current_track = Some(prev.clone());
                    Some(prev)
                } else {
                    self.current_track = Some(self.tracks.back().unwrap().clone());
                    Some(self.tracks.back().unwrap().clone())
                }
            } else {
                self.current_track = Some(self.tracks.front().unwrap().clone());
                Some(self.tracks.front().unwrap().clone())
            }
        } else {
            self.current_track = Some(self.tracks.front().unwrap().clone());
            Some(self.tracks.front().unwrap().clone())
        }
    }

    fn reset(&mut self) -> Option<String> {
        if self.tracks.is_empty() {
            self.current_track = None;
            None
        } else {
            self.current_track = Some(self.tracks.front().unwrap().clone());
            Some(self.tracks.front().unwrap().clone())
        }
    }
}

fn manage_playback_queue() -> PlaybackQueue {
    PlaybackQueue::new()
}
