use std::collections::LinkedList;

struct PlaybackQueue {
    tracks: LinkedList<String>,
    current_track: Option<String>,
    max_size: usize,
}

impl PlaybackQueue {
    fn new(max_size: usize) -> Self {
        PlaybackQueue {
            tracks: LinkedList::new(),
            current_track: None,
            max_size,
        }
    }

    fn add_track(&mut self, track: String) -> bool {
        if self.tracks.len() >= self.max_size {
            false
        } else {
            self.tracks.push_back(track);
            if self.current_track.is_none() && !self.tracks.is_empty() {
                self.current_track = self.tracks.front().cloned();
            }
            true
        }
    }

    fn remove_track(&mut self, track: &str) -> bool {
        let mut found = false;
        let mut new_tracks = LinkedList::new();

        for t in self.tracks.iter() {
            if t != track {
                new_tracks.push_back(t.clone());
            } else {
                found = true;
            }
        }

        if found {
            self.tracks = new_tracks;
            if self.current_track.as_ref() == Some(&track.to_string()) {
                self.current_track = self.tracks.front().cloned();
            }
            true
        } else {
            false
        }
    }

    fn skip_next(&mut self) -> bool {
        if self.tracks.is_empty() {
            return false;
        }

        let mut new_tracks = self.tracks.clone();
        if let Some(first) = new_tracks.pop_front() {
            new_tracks.push_back(first);
            self.tracks = new_tracks;
            self.current_track = self.tracks.front().cloned();
            true
        } else {
            false
        }
    }

    fn skip_previous(&mut self) -> bool {
        if self.tracks.is_empty() {
            return false;
        }

        let mut new_tracks = self.tracks.clone();
        if let Some(last) = new_tracks.pop_back() {
            new_tracks.push_front(last);
            self.tracks = new_tracks;
            self.current_track = self.tracks.front().cloned();
            true
        } else {
            false
        }
    }

    fn reset(&mut self) -> bool {
        if self.tracks.is_empty() {
            return false;
        }

        self.current_track = self.tracks.front().cloned();
        true
    }
}

fn manage_playback_queue() -> PlaybackQueue {
    PlaybackQueue::new(20)
}
