def track_inventory_changes(updates):
    inventory = {}
    order = []

    for product_id, quantity_change in updates:
        if product_id in inventory:
            inventory[product_id] += quantity_change
            # Move to the end of the order list to mark as most recently used
            order.remove(product_id)
            order.append(product_id)
        else:
            if len(inventory) >= 10:
                # Remove the least recently used product
                lru_product = order.pop(0)
                del inventory[lru_product]
            inventory[product_id] = quantity_change
            order.append(product_id)

    return inventory
