use std::collections::VecDeque;
use std::time::{SystemTime, UNIX_EPOCH};

struct EmailTask {
    content: String,
    is_urgent: bool,
}

fn manage_email_queue(queue: &mut VecDeque<EmailTask>) -> Option<String> {
    if queue.is_empty() {
        return None;
    }

    // Shuffle periodically (e.g., every 10th task)
    if queue.len() % 10 == 0 {
        let mut rng = rand::thread_rng();
        let mut shuffled: Vec<_> = queue.drain(..).collect();
        shuffled.shuffle(&mut rng);
        queue.extend(shuffled);
    }

    // Ensure queue doesn't exceed 100 tasks
    while queue.len() > 100 {
        queue.pop_front();
    }

    if let Some(task) = queue.pop_front() {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        let log = format!(
            "[{}] Processed email: {} (Urgent: {})",
            timestamp, task.content, task.is_urgent
        );
        Some(log)
    } else {
        None
    }
}
