use std::collections::VecDeque;
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug)]
struct EmailTask {
    content: String,
    is_urgent: bool,
}

fn manage_email_queue(
    queue: &mut VecDeque<EmailTask>,
    new_email: Option<EmailTask>,
    process_count: usize,
) -> Vec<String> {
    let mut logs = Vec::new();

    // Push new email to the back of the queue if provided and size allows
    if let Some(email) = new_email {
        if queue.len() < 100 {
            queue.push_back(email);
        } else {
            logs.push("Queue is full. Email not added.".to_string());
        }
    }

    // Periodically shuffle the queue to prioritize urgent emails
    if queue.len() > 10 {
        let mut urgent_emails: VecDeque<EmailTask> = queue
            .drain(..)
            .filter(|email| email.is_urgent)
            .collect();
        let mut non_urgent_emails: VecDeque<EmailTask> = queue
            .drain(..)
            .filter(|email| !email.is_urgent)
            .collect();
        queue.append(&mut urgent_emails);
        queue.append(&mut non_urgent_emails);
    }

    // Process the oldest emails from the front of the queue
    for _ in 0..process_count {
        if let Some(email) = queue.pop_front() {
            let timestamp = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs();
            logs.push(format!(
                "[{}] Processed email: {} (Urgent: {})",
                timestamp, email.content, email.is_urgent
            ));
        } else {
            logs.push("No emails left to process.".to_string());
            break;
        }
    }

    logs
}
