        let mut urgent_emails: VecDeque<EmailTask> = queue
            .drain(..)
            .filter(|email| email.is_urgent)
            .collect();
        let mut normal_emails: VecDeque<EmailTask> = queue
            .drain(..)
            .filter(|email| !email.is_urgent)
            .collect();
        queue.append(&mut urgent_emails);
        queue.append(&mut normal_emails);
    }

    // Pop oldest email from front for processing
    let processed_email = queue.pop_front();

    // Log processing with timestamp if email was processed
    if let Some(email) = &processed_email {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        println!(
            "[{}] Processed email: {} (Urgent: {})",
            timestamp, email.content, email.is_urgent
        );
    }

    processed_email
}
