package main

import (
	"bytes"
	"errors"
)

func logEvents(eventChan <-chan []byte, bufferSize int, flushSize int, flushFunc func([]byte) error) error {
	if bufferSize <= 0 || flushSize <= 0 || flushSize > bufferSize {
		return errors.New("invalid buffer or flush size")
	}

	buf := bytes.NewBuffer(make([]byte, 0, bufferSize))
	for event := range eventChan {
		if len(event) > bufferSize {
			return errors.New("event size exceeds buffer capacity")
		}

		if buf.Len()+len(event) > bufferSize {
			if err := flushFunc(buf.Bytes()); err != nil {
				return err
			}
			buf.Reset()
		}

		if _, err := buf.Write(event); err != nil {
			return err
		}

		if buf.Len() >= flushSize {
			if err := flushFunc(buf.Bytes()); err != nil {
				return err
			}
			buf.Reset()
		}
	}

	// Flush remaining data
	if buf.Len() > 0 {
		if err := flushFunc(buf.Bytes()); err != nil {
			return err
		}
	}

	return nil
}
