using namespace std;

vector<pair<int, int>> mergeMeetingTimes(vector<pair<int, int>>& intervals) {
    if (intervals.empty()) return {};

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    for (int i = 0; i < min(10, (int)intervals.size()); ++i) {
        pq.push(intervals[i]);
    }

    vector<pair<int, int>> merged;
    merged.push_back(pq.top());
    pq.pop();

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();

        if (current.first <= merged.back().second) {
            merged.back().second = max(merged.back().second, current.second);
        } else {
            merged.push_back(current);
        }
    }

    return merged;
}
