#include <vector>
#include <queue>
#include <algorithm>

using namespace std;

vector<pair<int, int>> mergeMeetingTimes(vector<pair<int, int>>& intervals) {
    if (intervals.empty()) return {};

    // Ensure no more than 10 intervals are processed
    if (intervals.size() > 10) {
        intervals.resize(10);
    }

    // Priority queue to sort intervals by start time
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    // Push first 10 intervals into the priority queue
    for (const auto& interval : intervals) {
        pq.push(interval);
    }

    vector<pair<int, int>> merged;

    if (!pq.empty()) {
        auto current = pq.top();
        pq.pop();

        while (!pq.empty()) {
            auto next = pq.top();
            pq.pop();

            if (current.second >= next.first) {
                // Merge overlapping intervals
                current.second = max(current.second, next.second);
            } else {
                merged.push_back(current);
                current = next;
            }
        }
        merged.push_back(current);
    }

    return merged;
}
