package main

import "errors"

var inventory = make(map[string]int)
const maxItems = 100

func trackInventoryStatus(operation string, productID string, quantity int) (int, error) {
	switch operation {
	case "add":
		if len(inventory) >= maxItems {
			return 0, errors.New("inventory full: cannot exceed 100 items")
		}
		inventory[productID] += quantity
	case "remove":
		if _, exists := inventory[productID]; !exists {
			return 0, errors.New("product not found")
		}
		inventory[productID] -= quantity
		if inventory[productID] <= 0 {
			delete(inventory, productID)
		}
	case "modify":
		if _, exists := inventory[productID]; !exists {
			return 0, errors.New("product not found")
		}
		inventory[productID] = quantity
	case "check":
		if _, exists := inventory[productID]; !exists {
			return 0, errors.New("product not found")
		}
		return inventory[productID], nil
	default:
		return 0, errors.New("invalid operation")
	}
	return inventory[productID], nil
}
