using namespace std;

vector<string> filterUniqueEmails(const vector<string>& emails) {
    set<string> uniqueEmails;

    for (const string& email : emails) {
        string processedEmail;
        bool foundAt = false;
        bool foundPlus = false;

        for (char c : email) {
            if (c == '@') {
                foundAt = true;
                foundPlus = false;
            }

            if (!foundAt) {
                if (c == '+') {
                    foundPlus = true;
                }
                if (!foundPlus && c != '.') {
                    processedEmail += tolower(c);
                }
            } else {
                processedEmail += tolower(c);
            }
        }

        uniqueEmails.insert(processedEmail);
    }

    vector<string> result(uniqueEmails.begin(), uniqueEmails.end());
    sort(result.begin(), result.end());

    if (result.size() > 50) {
        result.resize(50);
    }

    return result;
}
