#include <deque>
#include <string>
#include <utility>
#include <algorithm>

struct LogEntry {
    std::string timestamp;
    std::string content;
};

void sortLogsByTimestamp(std::deque<LogEntry>& logs, const LogEntry& newEntry) {
    // Check for duplicates and merge if found
    auto it = std::find_if(logs.begin(), logs.end(), 
        [&newEntry](const LogEntry& entry) { return entry.timestamp == newEntry.timestamp; });

    if (it != logs.end()) {
        it->content += "; " + newEntry.content;
        return;
    }

    // Insert new entry in correct position to maintain order
    auto insertPos = std::lower_bound(logs.begin(), logs.end(), newEntry, 
        [](const LogEntry& a, const LogEntry& b) { return a.timestamp < b.timestamp; });

    logs.insert(insertPos, newEntry);

    // Handle overflow by removing oldest entry if deque exceeds 100 elements
    if (logs.size() > 100) {
        logs.pop_front();
    }
}
