    std::string timestamp;
    std::string content;
};

void sortLogsByTimestamp(std::deque<LogEntry>& logs, const LogEntry& newEntry) {
    // Handle duplicates by merging content if timestamp exists
    for (auto it = logs.begin(); it != logs.end(); ++it) {
        if (it->timestamp == newEntry.timestamp) {
            it->content += " " + newEntry.content;
            return;
        }
    }

    // Add new entry at the correct position to maintain ascending order
    auto it = logs.begin();
    while (it != logs.end() && it->timestamp < newEntry.timestamp) {
        ++it;
    }
    logs.insert(it, newEntry);

    // Prune oldest log if size exceeds limit
    if (logs.size() > 100) {
        logs.pop_front();
    }
}
