#include <deque>
#include <string>
#include <utility>

void sortLogsByTimestamp(std::deque<std::pair<long, std::string>>& logs, const std::pair<long, std::string>& newLog) {
    // Add new log to the deque
    logs.push_back(newLog);

    // Sort the deque by timestamp in ascending order
    std::sort(logs.begin(), logs.end(), [](const auto& a, const auto& b) {
        return a.first < b.first;
    });

    // Merge logs with duplicate timestamps
    auto it = logs.begin();
    while (it != logs.end()) {
        auto next = std::next(it);
        if (next != logs.end() && it->first == next->first) {
            it->second += " " + next->second;
            logs.erase(next);
        } else {
            ++it;
        }
    }

    // Ensure deque size does not exceed 100 and is never below 10
    if (logs.size() > 100) {
        logs.pop_front();
    }
    if (logs.size() < 10) {
        return; // Do not pop_front if size is below 10
    }
}
