fn manage_inventory(transactions: Vec<(u32, i32)>) -> HashMap<u32, i32> {
    let mut inventory: HashMap<u32, i32> = HashMap::with_capacity(10);

    for (product_id, quantity_change) in transactions {
        if inventory.len() >= 10 && !inventory.contains_key(&product_id) {
            continue;
        }

        let current_quantity = inventory.entry(product_id).or_insert(0);
        *current_quantity += quantity_change;
    }

    inventory
}
