    for (product_id, quantity_change) in transactions {
        if let Some(index) = inventory.iter().position(|&(id, _)| id == product_id) {
            let (_, current_quantity) = inventory[index];
            inventory.pop();
            inventory.push((product_id, current_quantity + quantity_change));
