fn manage_inventory(transactions: Vec<(u32, i32)>) -> Vec<(u32, i32)> {
    let mut inventory: Vec<(u32, i32)> = Vec::with_capacity(10);

    for (product_id, quantity) in transactions {
        if inventory.len() >= 10 {
            inventory.pop();
        }

        let mut found = false;
        for (id, stock) in inventory.iter_mut() {
            if *id == product_id {
                *stock += quantity;
                found = true;
                break;
            }
        }

        if !found {
            inventory.push((product_id, quantity));
        }
    }

    inventory
}
