void batchProcessTasks(std::list<std::pair<int, std::string>>& tasks) {
    // Process completed tasks
    auto it = tasks.begin();
    while (it != tasks.end()) {
        if (it->second == "completed") {
            it = tasks.erase(it);
        } else {
            ++it;
        }
    }

    // Limit to maximum 50 tasks
    while (tasks.size() > 50) {
        tasks.erase(std::prev(tasks.end()));
    }
}
