#include <list>
#include <utility>
#include <algorithm>

void batchProcessTasks(std::list<std::pair<int, bool>>& tasks) {
    // Process completed tasks
    for (auto it = tasks.begin(); it != tasks.end(); ) {
        if (it->second) { // if task is completed
            it = tasks.erase(it);
        } else {
            ++it;
        }
    }

    // Ensure list does not exceed 50 tasks
    while (tasks.size() > 50) {
        tasks.erase(--tasks.end());
    }

    // Keep the list ordered by task ID
    tasks.sort([](const std::pair<int, bool>& a, const std::pair<int, bool>& b) {
        return a.first < b.first;
    });
}
