def compare_string_sequences(seq1, seq2):
    if len(seq1) != 4 or len(seq2) != 4:
        raise ValueError("Both sequences must contain exactly 4 strings.")

    matches = 0
    mismatches = 0
    differences = []

    for i in range(4):
        if seq1[i] == seq2[i]:
            matches += 1
        else:
            mismatches += 1
            differences.append(f"Position {i + 1}: '{seq1[i]}' != '{seq2[i]}'")

    report = {
        "total_matches": matches,
        "total_mismatches": mismatches,
        "differences": differences
    }

    return report
