#include <string>

std::unordered_map<std::string, std::vector<int>> categorizeStudentGrades(const std::vector<std::pair<int, char>>& studentGrades) {
    std::unordered_map<std::string, std::vector<int>> gradeCategories;
    gradeCategories.reserve(50); // Reserve space for at least 50 entries

    for (const auto& entry : studentGrades) {
        int studentId = entry.first;
        char grade = entry.second;

        std::string category;
        if (grade == 'A' || grade == 'a') {
            category = "A";
        } else if (grade == 'B' || grade == 'b') {
            category = "B";
        } else if (grade == 'C' || grade == 'c') {
            category = "C";
        } else if (grade == 'D' || grade == 'd') {
            category = "D";
        } else {
            category = "F";
        }

        gradeCategories[category].push_back(studentId);
    }

    return gradeCategories;
}
