func rotateArray(arr []int, k int) {
    n := len(arr)
    if n == 0 {
        return
    }
    k = k % n
    if k == 0 {
        return
    }
    reverse := func(a []int, start, end int) {
        for start < end {
            a[start], a[end] = a[end], a[start]
            start++
            end--
        }
    }
    reverse(arr, 0, n-1)
    reverse(arr, 0, k-1)
    reverse(arr, k, n-1)
}
