use arrayvec::ArrayVec;

struct StudentGrade {
    student_id: u32,
    grade: f32,
}

fn manage_student_grades(
    grades: &mut ArrayVec<StudentGrade, 50>,
    action: &str,
    student_id: u32,
    grade: Option<f32>,
) -> Result<(), String> {
    match action {
        "add" => {
            if grades.len() >= 50 {
                return Err("Maximum capacity reached".to_string());
            }
            if let Some(g) = grade {
                grades.push(StudentGrade { student_id, grade: g });
                Ok(())
            } else {
                Err("Grade not provided for add action".to_string())
            }
        }
        "update" => {
            if let Some(g) = grade {
                if let Some(student_grade) = grades.iter_mut().find(|sg| sg.student_id == student_id) {
                    student_grade.grade = g;
                    Ok(())
                } else {
                    Err("Student ID not found".to_string())
                }
            } else {
                Err("Grade not provided for update action".to_string())
            }
        }
        "delete" => {
            if let Some(pos) = grades.iter().position(|sg| sg.student_id == student_id) {
                grades.remove(pos);
                Ok(())
            } else {
                Err("Student ID not found".to_string())
            }
        }
        "average" => {
            if grades.is_empty() {
                Err("No grades to compute average".to_string())
            } else {
                let sum: f32 = grades.iter().map(|sg| sg.grade).sum();
                let avg = sum / grades.len() as f32;
                println!("Average grade: {}", avg);
                Ok(())
            }
        }
        _ => Err("Invalid action".to_string()),
    }
}
