use arrayvec::ArrayVec;

struct StudentGrade {
    id: u32,
    grade: f32,
}

fn manage_student_grades(
    grades: &mut ArrayVec<StudentGrade, 50>,
    operation: &str,
    id: u32,
    grade: Option<f32>,
) -> Result<f32, &'static str> {
    match operation {
        "add" => {
            if grades.len() >= 50 {
                return Err("Maximum capacity reached");
            }
            if let Some(g) = grade {
                grades.push(StudentGrade { id, grade: g });
                Ok(compute_average(grades))
            } else {
                Err("Grade not provided for add operation")
            }
        }
        "update" => {
            let pos = grades.iter().position(|sg| sg.id == id);
            if let Some(idx) = pos {
                if let Some(g) = grade {
                    grades[idx].grade = g;
                    Ok(compute_average(grades))
                } else {
                    Err("Grade not provided for update operation")
                }
            } else {
                Err("Student ID not found")
            }
        }
        "delete" => {
            let pos = grades.iter().position(|sg| sg.id == id);
            if let Some(idx) = pos {
                grades.remove(idx);
                Ok(compute_average(grades))
            } else {
                Err("Student ID not found")
            }
        }
        _ => Err("Invalid operation"),
    }
}

fn compute_average(grades: &ArrayVec<StudentGrade, 50>) -> f32 {
    if grades.is_empty() {
        0.0
    } else {
        grades.iter().map(|sg| sg.grade).sum::<f32>() / grades.len() as f32
    }
}
