#include <stack>
#include <string>

bool validateBrackets(const std::string& s) {
    std::stack<char> stack;
    for (char c : s) {
        if (c == '{' || c == '(' || c == '[') {
            if (stack.size() >= 10) {
                return false;
            }
            stack.push(c);
        } else {
            if (stack.empty()) {
                return false;
            }
            char top = stack.top();
            if ((c == '}' && top != '{') || 
                (c == ')' && top != '(') || 
                (c == ']' && top != '[')) {
                return false;
            }
            stack.pop();
        }
    }
    return stack.empty();
}
