package main

import (
	"sync"
)

type ResourceStatus struct {
	Enabled bool
}

type ResourceCache struct {
	statusMap sync.Map
	count     int
	maxCount  int
	mu        sync.Mutex
}

func NewResourceCache() *ResourceCache {
	return &ResourceCache{
		maxCount: 100,
	}
}

func (rc *ResourceCache) cacheResourceStatus(resource string, status ResourceStatus) bool {
	rc.mu.Lock()
	defer rc.mu.Unlock()

	if rc.count >= rc.maxCount {
		return false
	}

	_, loaded := rc.statusMap.LoadOrStore(resource, status)
	if !loaded {
		rc.count++
	}
	return true
}

func (rc *ResourceCache) setStatus(resource string, status ResourceStatus) {
	rc.statusMap.Store(resource, status)
}

func (rc *ResourceCache) isEnabled(resource string) bool {
	val, ok := rc.statusMap.Load(resource)
	if !ok {
		return false
	}
	return val.(ResourceStatus).Enabled
}

func (rc *ResourceCache) deleteResource(resource string) {
	rc.mu.Lock()
	defer rc.mu.Unlock()

	_, loaded := rc.statusMap.Load(resource)
	if loaded {
		rc.statusMap.Delete(resource)
		rc.count--
	}
}

func (rc *ResourceCache) countDistinctResources() int {
	rc.mu.Lock()
	defer rc.mu.Unlock()
	return rc.count
}
