public class AnagramDetector {
    public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, String[] wordsToCheck) {
        HashMap<String, Integer> result = new HashMap<>();
        if (wordsToCheck.length > 10) {
            String[] limitedWords = Arrays.copyOf(wordsToCheck, 10);
            wordsToCheck = limitedWords;
        }

        String[] articleWords = articleText.split("\\s+");
        HashMap<String, Integer> articleAnagramCounts = new HashMap<>();

        for (String word : articleWords) {
            String normalizedWord = normalizeWord(word);
            articleAnagramCounts.put(normalizedWord, articleAnagramCounts.getOrDefault(normalizedWord, 0) + 1);
        }

        for (String word : wordsToCheck) {
            String normalizedKey = normalizeWord(word);
            int count = articleAnagramCounts.getOrDefault(normalizedKey, 0);
            result.put(word, count);
        }

        return result;
    }

    private static String normalizeWord(String word) {
        char[] chars = word.toLowerCase().toCharArray();
        Arrays.sort(chars);
        return new String(chars);
    }
}
