public class AnagramDetector {
    public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, String[] wordsToCheck) {
        HashMap<String, Integer> result = new HashMap<>();
        if (wordsToCheck == null || wordsToCheck.length == 0 || wordsToCheck.length > 10) {
            return result;
        }

        HashMap<String, String> normalizedWords = new HashMap<>();
        for (String word : wordsToCheck) {
            String normalized = normalizeWord(word);
            normalizedWords.put(word, normalized);
        }

        String[] articleWords = articleText.split("\\s+");
        HashMap<String, Integer> articleCounts = new HashMap<>();

        for (String word : articleWords) {
            String normalized = normalizeWord(word);
            Integer count = articleCounts.get(normalized);
            if (count == null) {
                articleCounts.put(normalized, 1);
            } else {
                articleCounts.put(normalized, count + 1);
            }
        }

        for (String word : wordsToCheck) {
            String normalized = normalizedWords.get(word);
            Integer count = articleCounts.get(normalized);
            result.put(word, count != null ? count : 0);
        }

        return result;
    }

    private static String normalizeWord(String word) {
        char[] chars = word.toLowerCase().toCharArray();
        Arrays.sort(chars);
        return new String(chars);
    }
}
