import java.util.HashMap;
import java.util.Arrays;

public class AnagramDetector {
    public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, String[] wordsToCheck) {
        HashMap<String, Integer> anagramCounts = new HashMap<>();
        String[] articleWords = articleText.split("\\s+");

        for (String word : wordsToCheck) {
            if (anagramCounts.size() >= 10) {
                break;
            }
            char[] wordChars = word.toLowerCase().toCharArray();
            Arrays.sort(wordChars);
            String sortedWord = new String(wordChars);
            int count = 0;

            for (String articleWord : articleWords) {
                char[] articleWordChars = articleWord.toLowerCase().toCharArray();
                Arrays.sort(articleWordChars);
                String sortedArticleWord = new String(articleWordChars);

                if (sortedWord.equals(sortedArticleWord)) {
                    count++;
                }
            }

            anagramCounts.put(word, count);
        }

        while (anagramCounts.size() < 10 && wordsToCheck.length >= 10) {
            for (String word : wordsToCheck) {
                if (anagramCounts.size() >= 10) {
                    break;
                }
                if (!anagramCounts.containsKey(word)) {
                    anagramCounts.put(word, 0);
                }
            }
        }

        return anagramCounts;
    }
}
