#include <vector>
#include <algorithm>
#include <stdexcept>

struct SurveyResponse {
    int participantId;
    int rating;
};

class SurveyDataOrganizer {
private:
    std::vector<SurveyResponse> responses;
    const int MAX_PARTICIPANTS = 100;

    int findParticipantIndex(int participantId) {
        auto it = std::lower_bound(responses.begin(), responses.end(), participantId,
            [](const SurveyResponse& sr, int id) { return sr.participantId < id; });
        if (it != responses.end() && it->participantId == participantId) {
            return std::distance(responses.begin(), it);
        }
        return -1;
    }

public:
    void addResponse(int participantId, int rating) {
        if (responses.size() >= MAX_PARTICIPANTS) {
            throw std::runtime_error("Maximum participant limit reached.");
        }

        int index = findParticipantIndex(participantId);
        if (index != -1) {
            throw std::runtime_error("Participant ID already exists.");
        }

        SurveyResponse newResponse{participantId, rating};
        auto it = std::lower_bound(responses.begin(), responses.end(), participantId,
            [](const SurveyResponse& sr, int id) { return sr.participantId < id; });
        responses.insert(it, newResponse);
    }

    int getRating(int participantId) {
        int index = findParticipantIndex(participantId);
        if (index == -1) {
            throw std::runtime_error("Participant ID not found.");
        }
        return responses[index].rating;
    }

    void updateRating(int participantId, int newRating) {
        int index = findParticipantIndex(participantId);
        if (index == -1) {
            throw std::runtime_error("Participant ID not found.");
        }
        responses[index].rating = newRating;
    }

    void deleteResponse(int participantId) {
        int index = findParticipantIndex(participantId);
        if (index == -1) {
            throw std::runtime_error("Participant ID not found.");
        }
        responses.erase(responses.begin() + index);
    }
};
