fn analyze_feedback(feedback: &str) -> HashMap<String, u32> {
    let mut word_counts = HashMap::new();
    let mut word_buffer = String::new();

    for c in feedback.chars() {
        if c.is_alphabetic() {
            word_buffer.push(c.to_ascii_lowercase());
        } else if !word_buffer.is_empty() {
            *word_counts.entry(word_buffer.clone()).or_insert(0) += 1;
            word_buffer.clear();

            if word_counts.len() >= 50 {
                break;
            }
        }
    }

    if !word_buffer.is_empty() && word_counts.len() < 50 {
        *word_counts.entry(word_buffer).or_insert(0) += 1;
    }

    word_counts
}
