    let mut processed_words = 0;

    for word in feedback.split_whitespace() {
        let processed_word = word
            .chars()
            .filter(|c| c.is_alphabetic())
            .collect::<String>()
            .to_lowercase();

        if !processed_word.is_empty() {
            if word_counts.contains_key(&processed_word) {
                if let Some(count) = word_counts.get_mut(&processed_word) {
                    *count += 1;
                }
            } else if processed_words < 50 {
                word_counts.insert(processed_word, 1);
                processed_words += 1;
            }
        }
    }

    word_counts
}
