use std::collections::HashMap;

fn analyze_feedback(feedback: &str) -> HashMap<String, u32> {
    let mut word_counts = HashMap::with_capacity(50);

    for word in feedback.split_whitespace() {
        let processed_word = word
            .chars()
            .filter(|c| c.is_alphabetic())
            .map(|c| c.to_ascii_lowercase())
            .collect::<String>();

        if !processed_word.is_empty() {
            *word_counts.entry(processed_word).or_insert(0) += 1;

            if word_counts.len() > 50 {
                let min_key = word_counts
                    .iter()
                    .min_by_key(|(_, &count)| count)
                    .map(|(key, _)| key.clone())
                    .unwrap();
                word_counts.remove(&min_key);
            }
        }
    }

    word_counts
}
