type Employee struct {
	Name     string
	ID       int
	Position string
	Salary   float64
}

type EmployeeStack struct {
	employees []Employee
	maxSize   int
}

func NewEmployeeStack() *EmployeeStack {
	return &EmployeeStack{
		employees: make([]Employee, 0),
		maxSize:   100,
	}
}

func (es *EmployeeStack) push(emp Employee) error {
	if len(es.employees) >= es.maxSize {
		return errors.New("stack is full, cannot add more employees")
	}
	es.employees = append(es.employees, emp)
	return nil
}

func (es *EmployeeStack) pop() (Employee, error) {
	if len(es.employees) == 0 {
		return Employee{}, errors.New("stack is empty, no employees to pop")
	}
	emp := es.employees[len(es.employees)-1]
	es.employees = es.employees[:len(es.employees)-1]
	return emp, nil
}

func (es *EmployeeStack) update(id int, emp Employee) error {
	for i := range es.employees {
		if es.employees[i].ID == id {
			es.employees[i] = emp
			return nil
		}
	}
	return errors.New("employee not found")
}

func (es *EmployeeStack) retrieve(id int) (Employee, error) {
	for _, emp := range es.employees {
		if emp.ID == id {
			return emp, nil
		}
	}
	return Employee{}, errors.New("employee not found")
}

func manageEmployeeRecords() {
	stack := NewEmployeeStack()
	// Example usage:
	// Push
	stack.push(Employee{Name: "John Doe", ID: 1, Position: "Developer", Salary: 50000})
	// Update
	stack.update(1, Employee{Name: "John Doe", ID: 1, Position: "Senior Developer", Salary: 60000})
	// Retrieve
	emp, _ := stack.retrieve(1)
	fmt.Println(emp)
	// Pop
	poppedEmp, _ := stack.pop()
	fmt.Println(poppedEmp)
}
