    std::vector<double> rollingAverages;
    int n = temperatures.size();

    for (int i = 0; i < n; ++i) {
        int start = std::max(0, i - windowSize + 1);
        int end = i + 1;
        double sum = 0.0;
        int count = 0;

        for (int j = start; j < end; ++j) {
            sum += temperatures[j];
            ++count;
