package main

import (
	"bytes"
	"strings"
)

type LogEntry struct {
	Content string
}

type LogBuffer struct {
	buffer   []LogEntry
	capacity int
}

func NewLogBuffer(capacity int) *LogBuffer {
	return &LogBuffer{
		buffer:   make([]LogEntry, 0, capacity),
		capacity: capacity,
	}
}

func (lb *LogBuffer) AddEntry(entry LogEntry) {
	if len(lb.buffer) >= lb.capacity {
		lb.buffer = lb.buffer[1:]
	}
	lb.buffer = append(lb.buffer, entry)
}

func (lb *LogBuffer) SearchErrorPatterns(patterns []string) map[string]int {
	errorCounts := make(map[string]int)
	for _, entry := range lb.buffer {
		for _, pattern := range patterns {
			if strings.Contains(entry.Content, pattern) {
				errorCounts[pattern]++
			}
		}
	}
	return errorCounts
}

func processLogFile(logEntries []string, errorPatterns []string) map[string]int {
	buffer := NewLogBuffer(1000)
	for _, entry := range logEntries {
		buffer.AddEntry(LogEntry{Content: entry})
	}
	return buffer.SearchErrorPatterns(errorPatterns)
}
