	if len(lb.buffer) >= lb.capacity {
		lb.pop()
	}
	lb.buffer = append(lb.buffer, log)
}

func (lb *LogBuffer) pop() string {
	if len(lb.buffer) == 0 {
		return ""
	}
	log := lb.buffer[0]
	lb.buffer = lb.buffer[1:]
	return log
}

func processLogFile(logs []string, errorPatterns []string) map[string]int {
	buffer := NewLogBuffer(1000)
	errorCounts := make(map[string]int)

	for _, log := range logs {
		buffer.push(log)
		for _, pattern := range errorPatterns {
			if strings.Contains(log, pattern) {
				errorCounts[pattern]++
			}
		}
	}

	return errorCounts
}
