use std::collections::HashSet;

fn detect_cycle_in_graph(graph: &Vec<Vec<usize>>, node: usize, visited: &mut HashSet<usize>, recursion_stack: &mut HashSet<usize>) -> bool {
    if recursion_stack.contains(&node) {
        return true;
    }

    if visited.contains(&node) {
        return false;
    }

    if visited.len() >= 10 {
        visited.clear();
    }

    visited.insert(node);
    recursion_stack.insert(node);

    for &neighbor in &graph[node] {
        if detect_cycle_in_graph(graph, neighbor, visited, recursion_stack) {
            return true;
        }
    }

    recursion_stack.remove(&node);
    false
}

pub fn has_cycle(graph: &Vec<Vec<usize>>) -> bool {
    let mut visited = HashSet::new();
    let mut recursion_stack = HashSet::new();

    for node in 0..graph.len() {
        if detect_cycle_in_graph(graph, node, &mut visited, &mut recursion_stack) {
            return true;
        }
    }

    false
}
