public class MeetingScheduler {
    public static ArrayList<Meeting> organizeMeetings(ArrayList<Meeting> meetings) {
        PriorityQueue<Meeting> queue = new PriorityQueue<>((a, b) -> b.getUrgency() - a.getUrgency());
        ArrayList<Meeting> processedMeetings = new ArrayList<>();

        for (Meeting meeting : meetings) {
            queue.offer(meeting);
            if (queue.size() > 10) {
                queue.poll();
            }
        }

        while (!queue.isEmpty()) {
            Meeting meeting = queue.poll();
            meeting.markCompleted();
            processedMeetings.add(meeting);
        }

        return processedMeetings;
    }
}

