std::pair<std::vector<std::string>, int> deduplicateEmailAddresses(const std::vector<std::string>& emails) {
    std::unordered_set<std::string> uniqueEmails;
    std::vector<std::string> result;
    int duplicatesRemoved = 0;

    for (const auto& email : emails) {
        if (uniqueEmails.size() < 100) {
            if (uniqueEmails.find(email) == uniqueEmails.end()) {
                uniqueEmails.insert(email);
                result.push_back(email);
            } else {
                duplicatesRemoved++;
            }
        } else {
            if (uniqueEmails.find(email) == uniqueEmails.end()) {
                duplicatesRemoved++;
            }
        }
    }

    return {result, duplicatesRemoved};
}
