use std::collections::BinaryHeap;

struct GameSession {
    score: u32,
    // Add other relevant fields here
}

impl Ord for GameSession {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.score.cmp(&other.score)
    }
}

impl PartialOrd for GameSession {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl PartialEq for GameSession {
    fn eq(&self, other: &Self) -> bool {
        self.score == other.score
    }
}

impl Eq for GameSession {}

struct EventLogger {
    heap: BinaryHeap<GameSession>,
}

impl EventLogger {
    pub fn new() -> Self {
        EventLogger {
            heap: BinaryHeap::new(),
        }
    }

    pub fn push(&mut self, session: GameSession) {
        self.heap.push(session);
    }

    pub fn pop(&mut self) -> Option<GameSession> {
        self.heap.pop()
    }

    pub fn peek(&self) -> Option<&GameSession> {
        self.heap.peek()
    }

    pub fn into_sorted_vec(self) -> Vec<GameSession> {
        self.heap.into_sorted_vec()
    }
}
